pub const StandardUniform = struct {
    pub fn sample(_: StandardUniform, rng: Rng, comptime T: type) T {
        return rng.value(T);
    }

    pub fn sampleFrom(_: StandardUniform, source: anytype, comptime T: type) T {
        return Rng.valueFrom(source, T);
    }

    pub fn fill(_: StandardUniform, rng: Rng, comptime T: type, dest: []T) void {
        standardUniformFillFrom(rng, T, dest);
    }

    pub fn fillFrom(_: StandardUniform, source: anytype, comptime T: type, dest: []T) void {
        standardUniformFillFrom(source, T, dest);
    }
};

fn standardUniformFillFrom(source: anytype, comptime T: type, dest: []T) void {
    if (comptime standardUniformCanBulkFill(T)) {
        Rng.fillFrom(source, T, dest);
        return;
    }
    for (dest) |*item| item.* = Rng.valueFrom(source, T);
}

fn standardUniformCanBulkFill(comptime T: type) bool {
    return switch (@typeInfo(T)) {
        .int, .float, .bool, .vector => true,
        else => false,
    };
}

pub fn sampleIter(rng: Rng, comptime T: type, sampler: anytype) Rng.SampleIterator(@TypeOf(sampler), T) {
    return rng.sampleIter(T, sampler);
}

pub fn sampleIterFrom(source: anytype, comptime T: type, sampler: anytype) Rng.SampleIteratorFrom(@TypeOf(source), @TypeOf(sampler), T) {
    return Rng.sampleIterFrom(source, T, sampler);
}

pub fn map(comptime In: type, comptime Out: type, sampler: anytype, mapper: anytype) MappedSampler(@TypeOf(sampler), @TypeOf(mapper), In, Out) {
    return .{ .sampler = sampler, .mapper = mapper };
}

pub fn MappedSampler(comptime Sampler: type, comptime Mapper: type, comptime In: type, comptime Out: type) type {
    return struct {
        const Self = @This();

        sampler: Sampler,
        mapper: Mapper,

        pub fn sample(self: Self, rng: Rng) Out {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) Out {
            return applyMapper(Out, self.mapper, Rng.sampleFrom(source, In, self.sampler));
        }

        pub fn fill(self: Self, rng: Rng, dest: []Out) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []Out) void {
            for (dest) |*item| item.* = applyMapper(Out, self.mapper, Rng.sampleFrom(source, In, self.sampler));
        }

        pub fn map(self: Self, comptime NextOut: type, mapper: anytype) MappedSampler(Self, @TypeOf(mapper), Out, NextOut) {
            return .{ .sampler = self, .mapper = mapper };
        }
    };
}

pub fn Map(comptime Sampler: type, comptime Mapper: type, comptime In: type, comptime Out: type) type {
    return MappedSampler(Sampler, Mapper, In, Out);
}

pub fn Iter(comptime Sampler: type, comptime Source: type, comptime T: type) type {
    return Rng.SampleIteratorFrom(Source, Sampler, T);
}

fn applyMapper(comptime Out: type, mapper: anytype, value: anytype) Out {
    const Mapper = @TypeOf(mapper);
    const Base = switch (@typeInfo(Mapper)) {
        .pointer => |pointer| pointer.child,
        else => Mapper,
    };

    if (comptime @hasDecl(Base, "map")) {
        const info = @typeInfo(@TypeOf(@field(Base, "map"))).@"fn";
        if (comptime info.params.len == 1) return @as(Out, Base.map(value));
        if (comptime info.params.len == 2) return @as(Out, mapper.map(value));
        @compileError(@typeName(Base) ++ ".map must accept either (value) or (self, value)");
    }
    if (comptime @hasDecl(Base, "apply")) {
        const info = @typeInfo(@TypeOf(@field(Base, "apply"))).@"fn";
        if (comptime info.params.len == 1) return @as(Out, Base.apply(value));
        if (comptime info.params.len == 2) return @as(Out, mapper.apply(value));
        @compileError(@typeName(Base) ++ ".apply must accept either (value) or (self, value)");
    }
    if (comptime @hasDecl(Base, "call")) {
        const info = @typeInfo(@TypeOf(@field(Base, "call"))).@"fn";
        if (comptime info.params.len == 1) return @as(Out, Base.call(value));
        if (comptime info.params.len == 2) return @as(Out, mapper.call(value));
        @compileError(@typeName(Base) ++ ".call must accept either (value) or (self, value)");
    }
    @compileError("mapped sampler mapper must expose map, apply, or call");
}

pub fn Choose(comptime T: type) type {
    return struct {
        const Self = @This();

        items: []const T,

        pub fn init(items: []const T) ?Self {
            if (items.len == 0) return null;
            return .{ .items = items };
        }

        pub fn new(items: []const T) ?Self {
            return init(items);
        }

        pub fn initChecked(items: []const T) Error!Self {
            return init(items) orelse error.EmptyRange;
        }

        pub fn newChecked(items: []const T) Error!Self {
            return initChecked(items);
        }

        pub fn len(self: Self) usize {
            return self.items.len;
        }

        pub fn numChoices(self: Self) usize {
            return self.items.len;
        }

        pub fn constantIndex(self: Self) ?usize {
            return if (self.items.len == 1) 0 else null;
        }

        pub fn isEmpty(self: Self) bool {
            return self.items.len == 0;
        }

        pub fn itemsValue(self: Self) []const T {
            return self.items;
        }

        pub fn itemAt(self: Self, index: usize) Error!*const T {
            if (index >= self.items.len) return error.InvalidParameter;
            return &self.items[index];
        }

        pub fn item(self: Self, index: usize) Error!*const T {
            return self.itemAt(index);
        }

        pub fn get(self: Self, index: usize) ?*const T {
            if (index >= self.items.len) return null;
            return &self.items[index];
        }

        pub const ProbabilityIterator = struct {
            const Iterator = @This();

            choice: Self,
            index: usize = 0,

            pub fn next(self: *Iterator) ?f64 {
                const value = self.choice.probability(self.index) orelse return null;
                self.index += 1;
                return value;
            }

            pub fn remaining(self: Iterator) usize {
                return self.choice.len() - self.index;
            }

            pub fn len(self: Iterator) usize {
                return self.remaining();
            }

            pub fn sizeHint(self: Iterator) SizeHint {
                const length = self.remaining();
                return .{ .lower = length, .upper = length };
            }

            pub fn fill(self: *Iterator, dest: []f64) usize {
                const count = @min(dest.len, self.remaining());
                if (count == 0) return 0;
                @memset(dest[0..count], 1.0 / @as(f64, @floatFromInt(self.choice.len())));
                self.index += count;
                return count;
            }
        };

        pub fn probabilityAt(self: Self, index: usize) Error!f64 {
            if (index >= self.items.len) return error.InvalidParameter;
            return 1.0 / @as(f64, @floatFromInt(self.items.len));
        }

        pub fn probability(self: Self, index: usize) ?f64 {
            return self.probabilityAt(index) catch null;
        }

        pub fn probabilityIter(self: Self) ProbabilityIterator {
            return .{ .choice = self };
        }

        pub fn probabilities(self: Self, allocator: std.mem.Allocator) ![]f64 {
            const out = try allocator.alloc(f64, self.items.len);
            errdefer allocator.free(out);
            try self.probabilitiesInto(out);
            return out;
        }

        pub fn probabilitiesInto(self: Self, out: []f64) Error!void {
            if (out.len != self.items.len) return error.InvalidLength;
            @memset(out, 1.0 / @as(f64, @floatFromInt(self.items.len)));
        }

        pub fn sample(self: Self, rng: Rng) *const T {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) *const T {
            std.debug.assert(self.items.len > 0);
            if (self.items.len == 1) return &self.items[0];
            return &self.items[Rng.uintLessThanFrom(source, usize, self.items.len)];
        }

        pub fn sampleValue(self: Self, rng: Rng) T {
            return self.sample(rng).*;
        }

        pub fn sampleValueFrom(self: Self, source: anytype) T {
            return self.sampleFrom(source).*;
        }

        pub fn sampleValueChecked(self: Self, rng: Rng) Error!T {
            return self.sampleValueCheckedFrom(rng);
        }

        pub fn sampleValueCheckedFrom(self: Self, source: anytype) Error!T {
            if (comptime valueTypeHasEmptyEnum(T)) return error.EmptyRange;
            return self.sampleValueFrom(source);
        }

        pub fn valueChecked(self: Self, rng: Rng) Error!T {
            return self.sampleValueChecked(rng);
        }

        pub fn valueCheckedFrom(self: Self, source: anytype) Error!T {
            return self.sampleValueCheckedFrom(source);
        }

        pub fn sampleIndex(self: Self, rng: Rng) usize {
            return self.sampleIndexFrom(rng);
        }

        pub fn sampleIndexFrom(self: Self, source: anytype) usize {
            std.debug.assert(self.items.len > 0);
            if (self.items.len == 1) return 0;
            return Rng.uintLessThanFrom(source, usize, self.items.len);
        }

        pub fn sampleIndexChecked(self: Self, rng: Rng) Error!usize {
            return self.sampleIndexCheckedFrom(rng);
        }

        pub fn sampleIndexCheckedFrom(self: Self, source: anytype) Error!usize {
            return self.sampleIndexFrom(source);
        }

        pub fn sampleIndexU32(self: Self, rng: Rng) Error!u32 {
            return self.sampleIndexU32From(rng);
        }

        pub fn sampleIndexU32From(self: Self, source: anytype) Error!u32 {
            if (self.items.len > std.math.maxInt(u32)) return error.InvalidParameter;
            if (self.items.len == 1) return 0;
            return Rng.uintLessThanFrom(source, u32, @intCast(self.items.len));
        }

        pub fn sampleIndexU32Checked(self: Self, rng: Rng) Error!u32 {
            return self.sampleIndexU32CheckedFrom(rng);
        }

        pub fn sampleIndexU32CheckedFrom(self: Self, source: anytype) Error!u32 {
            return self.sampleIndexU32From(source);
        }

        pub fn fill(self: Self, rng: Rng, dest: []*const T) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []*const T) void {
            if (dest.len == 0) return;
            const items = self.items;
            std.debug.assert(items.len > 0);
            if (items.len == 1) {
                @memset(dest, &items[0]);
                return;
            }
            const item_len = items.len;
            for (dest) |*slot| slot.* = &items[Rng.uintLessThanFrom(source, usize, item_len)];
        }

        pub fn fillChecked(self: Self, rng: Rng, dest: []*const T) Error!void {
            try self.fillCheckedFrom(rng, dest);
        }

        pub fn fillCheckedFrom(self: Self, source: anytype, dest: []*const T) Error!void {
            self.fillFrom(source, dest);
        }

        pub fn ptrs(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]*const T {
            return self.ptrsFrom(allocator, rng, amount);
        }

        pub fn ptrsFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]*const T {
            const out = try allocator.alloc(*const T, amount);
            errdefer allocator.free(out);
            self.fillFrom(source, out);
            return out;
        }

        pub fn ptrsChecked(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]*const T {
            return self.ptrsCheckedFrom(allocator, rng, amount);
        }

        pub fn ptrsCheckedFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]*const T {
            return self.ptrsFrom(allocator, source, amount);
        }

        pub fn ptrArray(self: Self, rng: Rng, comptime N: usize) [N]*const T {
            return self.ptrArrayFrom(rng, N);
        }

        pub fn ptrArrayFrom(self: Self, source: anytype, comptime N: usize) [N]*const T {
            var out: [N]*const T = undefined;
            self.fillFrom(source, &out);
            return out;
        }

        pub fn ptrArrayChecked(self: Self, rng: Rng, comptime N: usize) Error![N]*const T {
            return self.ptrArrayCheckedFrom(rng, N);
        }

        pub fn ptrArrayCheckedFrom(self: Self, source: anytype, comptime N: usize) Error![N]*const T {
            return self.ptrArrayFrom(source, N);
        }

        pub fn ptrIter(self: Self, rng: Rng) PtrIterator(Rng) {
            return self.ptrIterFrom(rng);
        }

        pub fn ptrIterFrom(self: Self, source: anytype) PtrIterator(@TypeOf(source)) {
            return .{ .source = source, .choice = self };
        }

        pub fn ptrIterChecked(self: Self, rng: Rng) Error!PtrIterator(Rng) {
            return self.ptrIterCheckedFrom(rng);
        }

        pub fn ptrIterCheckedFrom(self: Self, source: anytype) Error!PtrIterator(@TypeOf(source)) {
            return self.ptrIterFrom(source);
        }

        pub fn PtrIterator(comptime Source: type) type {
            return struct {
                const SelfIter = @This();

                source: Source,
                choice: Self,

                pub fn next(self: *SelfIter) ?*const T {
                    return self.nextValue();
                }

                pub fn nextValue(self: *SelfIter) *const T {
                    const items = self.choice.items;
                    if (items.len == 1) return &items[0];
                    return &items[Rng.uintLessThanFrom(self.source, usize, items.len)];
                }

                pub fn fill(self: *SelfIter, dest: []*const T) void {
                    self.choice.fillFrom(self.source, dest);
                }
            };
        }

        pub fn fillIndices(self: Self, rng: Rng, dest: []usize) void {
            self.fillIndicesFrom(rng, dest);
        }

        pub fn fillIndicesFrom(self: Self, source: anytype, dest: []usize) void {
            if (dest.len == 0) return;
            const item_len = self.items.len;
            std.debug.assert(item_len > 0);
            if (item_len == 1) {
                @memset(dest, 0);
                return;
            }
            for (dest) |*index| index.* = Rng.uintLessThanFrom(source, usize, item_len);
        }

        pub fn fillIndicesChecked(self: Self, rng: Rng, dest: []usize) Error!void {
            try self.fillIndicesCheckedFrom(rng, dest);
        }

        pub fn fillIndicesCheckedFrom(self: Self, source: anytype, dest: []usize) Error!void {
            self.fillIndicesFrom(source, dest);
        }

        pub fn indices(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]usize {
            return self.indicesFrom(allocator, rng, amount);
        }

        pub fn indicesFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]usize {
            const out = try allocator.alloc(usize, amount);
            errdefer allocator.free(out);
            self.fillIndicesFrom(source, out);
            return out;
        }

        pub fn indicesChecked(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]usize {
            return self.indicesCheckedFrom(allocator, rng, amount);
        }

        pub fn indicesCheckedFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]usize {
            return self.indicesFrom(allocator, source, amount);
        }

        pub fn indexArray(self: Self, rng: Rng, comptime N: usize) [N]usize {
            return self.indexArrayFrom(rng, N);
        }

        pub fn indexArrayFrom(self: Self, source: anytype, comptime N: usize) [N]usize {
            var out: [N]usize = undefined;
            self.fillIndicesFrom(source, &out);
            return out;
        }

        pub fn indexArrayChecked(self: Self, rng: Rng, comptime N: usize) Error![N]usize {
            return self.indexArrayCheckedFrom(rng, N);
        }

        pub fn indexArrayCheckedFrom(self: Self, source: anytype, comptime N: usize) Error![N]usize {
            return self.indexArrayFrom(source, N);
        }

        pub fn fillIndicesU32(self: Self, rng: Rng, dest: []u32) Error!void {
            return self.fillIndicesU32From(rng, dest);
        }

        pub fn fillIndicesU32From(self: Self, source: anytype, dest: []u32) Error!void {
            if (dest.len == 0) return;
            const item_len = self.items.len;
            if (item_len > std.math.maxInt(u32)) return error.InvalidParameter;
            if (item_len == 1) {
                @memset(dest, 0);
                return;
            }
            const item_len_u32: u32 = @intCast(item_len);
            for (dest) |*index| index.* = Rng.uintLessThanFrom(source, u32, item_len_u32);
        }

        pub fn fillIndicesU32Checked(self: Self, rng: Rng, dest: []u32) Error!void {
            try self.fillIndicesU32CheckedFrom(rng, dest);
        }

        pub fn fillIndicesU32CheckedFrom(self: Self, source: anytype, dest: []u32) Error!void {
            try self.fillIndicesU32From(source, dest);
        }

        pub fn indicesU32(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]u32 {
            return self.indicesU32From(allocator, rng, amount);
        }

        pub fn indicesU32From(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]u32 {
            if (self.items.len > std.math.maxInt(u32)) return error.InvalidParameter;
            const out = try allocator.alloc(u32, amount);
            errdefer allocator.free(out);
            try self.fillIndicesU32From(source, out);
            return out;
        }

        pub fn indicesU32Checked(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]u32 {
            return self.indicesU32CheckedFrom(allocator, rng, amount);
        }

        pub fn indicesU32CheckedFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]u32 {
            return self.indicesU32From(allocator, source, amount);
        }

        pub fn indexArrayU32(self: Self, rng: Rng, comptime N: usize) Error![N]u32 {
            return self.indexArrayU32From(rng, N);
        }

        pub fn indexArrayU32From(self: Self, source: anytype, comptime N: usize) Error![N]u32 {
            var out: [N]u32 = undefined;
            try self.fillIndicesU32From(source, &out);
            return out;
        }

        pub fn indexArrayU32Checked(self: Self, rng: Rng, comptime N: usize) Error![N]u32 {
            return self.indexArrayU32CheckedFrom(rng, N);
        }

        pub fn indexArrayU32CheckedFrom(self: Self, source: anytype, comptime N: usize) Error![N]u32 {
            return try self.indexArrayU32From(source, N);
        }

        pub fn indexIter(self: Self, rng: Rng) IndexIterator(Rng) {
            return self.indexIterFrom(rng);
        }

        pub fn indexIterFrom(self: Self, source: anytype) IndexIterator(@TypeOf(source)) {
            return .{ .source = source, .choice = self };
        }

        pub fn indexIterChecked(self: Self, rng: Rng) Error!IndexIterator(Rng) {
            return self.indexIterCheckedFrom(rng);
        }

        pub fn indexIterCheckedFrom(self: Self, source: anytype) Error!IndexIterator(@TypeOf(source)) {
            return self.indexIterFrom(source);
        }

        pub fn indexIterU32(self: Self, rng: Rng) Error!U32IndexIterator(Rng) {
            return self.indexIterU32From(rng);
        }

        pub fn indexIterU32From(self: Self, source: anytype) Error!U32IndexIterator(@TypeOf(source)) {
            if (self.items.len > std.math.maxInt(u32)) return error.InvalidParameter;
            return .{ .source = source, .choice = self };
        }

        pub fn indexIterU32Checked(self: Self, rng: Rng) Error!U32IndexIterator(Rng) {
            return self.indexIterU32CheckedFrom(rng);
        }

        pub fn indexIterU32CheckedFrom(self: Self, source: anytype) Error!U32IndexIterator(@TypeOf(source)) {
            return self.indexIterU32From(source);
        }

        pub fn IndexIterator(comptime Source: type) type {
            return struct {
                const SelfIter = @This();

                source: Source,
                choice: Self,

                pub fn next(self: *SelfIter) ?usize {
                    return self.nextValue();
                }

                pub fn nextValue(self: *SelfIter) usize {
                    const item_len = self.choice.items.len;
                    return if (item_len == 1) 0 else Rng.uintLessThanFrom(self.source, usize, item_len);
                }

                pub fn fill(self: *SelfIter, dest: []usize) void {
                    self.choice.fillIndicesFrom(self.source, dest);
                }
            };
        }

        pub fn U32IndexIterator(comptime Source: type) type {
            return struct {
                const SelfIter = @This();

                source: Source,
                choice: Self,

                pub fn next(self: *SelfIter) ?u32 {
                    return self.nextValue();
                }

                pub fn nextValue(self: *SelfIter) u32 {
                    const item_len = self.choice.items.len;
                    if (item_len == 1) return 0;
                    return Rng.uintLessThanFrom(self.source, u32, @intCast(item_len));
                }

                pub fn fill(self: *SelfIter, dest: []u32) void {
                    self.choice.fillIndicesU32From(self.source, dest) catch unreachable;
                }
            };
        }

        pub fn fillValues(self: Self, rng: Rng, dest: []T) void {
            self.fillValuesFrom(rng, dest);
        }

        pub fn fillValuesFrom(self: Self, source: anytype, dest: []T) void {
            if (dest.len == 0) return;
            if (comptime valueTypeHasEmptyEnum(T)) return;
            const items = self.items;
            std.debug.assert(items.len > 0);
            if (items.len == 1) {
                @memset(dest, items[0]);
                return;
            }
            const item_len = items.len;
            for (dest) |*slot| slot.* = items[Rng.uintLessThanFrom(source, usize, item_len)];
        }

        pub fn fillValuesChecked(self: Self, rng: Rng, dest: []T) Error!void {
            try self.fillValuesCheckedFrom(rng, dest);
        }

        pub fn fillValuesCheckedFrom(self: Self, source: anytype, dest: []T) Error!void {
            if (dest.len == 0) return;
            if (comptime valueTypeHasEmptyEnum(T)) return error.EmptyRange;
            self.fillValuesFrom(source, dest);
        }

        pub fn valueArray(self: Self, rng: Rng, comptime N: usize) [N]T {
            return self.valueArrayFrom(rng, N);
        }

        pub fn valueArrayFrom(self: Self, source: anytype, comptime N: usize) [N]T {
            var out: [N]T = undefined;
            self.fillValuesFrom(source, &out);
            return out;
        }

        pub fn valueArrayChecked(self: Self, rng: Rng, comptime N: usize) Error![N]T {
            return self.valueArrayCheckedFrom(rng, N);
        }

        pub fn valueArrayCheckedFrom(self: Self, source: anytype, comptime N: usize) Error![N]T {
            var out: [N]T = undefined;
            if (N == 0) return out;
            if (comptime valueTypeHasEmptyEnum(T)) return error.EmptyRange;
            self.fillValuesFrom(source, &out);
            return out;
        }

        pub fn values(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]T {
            return self.valuesFrom(allocator, rng, amount);
        }

        pub fn valuesFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]T {
            if (amount == 0) return allocator.alloc(T, 0);
            if (comptime valueTypeHasEmptyEnum(T)) return error.EmptyRange;
            const out = try allocator.alloc(T, amount);
            errdefer allocator.free(out);
            self.fillValuesFrom(source, out);
            return out;
        }

        pub fn valuesChecked(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]T {
            return self.valuesCheckedFrom(allocator, rng, amount);
        }

        pub fn valuesCheckedFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]T {
            return self.valuesFrom(allocator, source, amount);
        }

        pub fn valueIter(self: Self, rng: Rng) ValueIterator(Rng) {
            return self.valueIterFrom(rng);
        }

        pub fn valueIterFrom(self: Self, source: anytype) ValueIterator(@TypeOf(source)) {
            return .{ .source = source, .choice = self };
        }

        pub fn valueIterChecked(self: Self, rng: Rng) Error!ValueIterator(Rng) {
            return self.valueIterCheckedFrom(rng);
        }

        pub fn valueIterCheckedFrom(self: Self, source: anytype) Error!ValueIterator(@TypeOf(source)) {
            if (comptime valueTypeHasEmptyEnum(T)) return error.EmptyRange;
            return self.valueIterFrom(source);
        }

        pub fn ValueIterator(comptime Source: type) type {
            return struct {
                const SelfIter = @This();

                source: Source,
                choice: Self,

                pub fn next(self: *SelfIter) ?T {
                    return self.nextValue();
                }

                pub fn nextValue(self: *SelfIter) ?T {
                    if (comptime valueTypeHasEmptyEnum(T)) return null;
                    const items = self.choice.items;
                    if (items.len == 1) return items[0];
                    return items[Rng.uintLessThanFrom(self.source, usize, items.len)];
                }

                pub fn fill(self: *SelfIter, dest: []T) void {
                    self.choice.fillValuesFrom(self.source, dest);
                }
            };
        }

        pub fn iter(self: Self, rng: Rng) Rng.SampleIterator(Self, *const T) {
            return rng.sampleIter(*const T, self);
        }

        pub fn iterFrom(self: Self, source: anytype) Rng.SampleIteratorFrom(@TypeOf(source), Self, *const T) {
            return Rng.sampleIterFrom(source, *const T, self);
        }

        pub fn iterChecked(self: Self, rng: Rng) Error!Rng.SampleIterator(Self, *const T) {
            return self.iter(rng);
        }

        pub fn iterCheckedFrom(self: Self, source: anytype) Error!Rng.SampleIteratorFrom(@TypeOf(source), Self, *const T) {
            return self.iterFrom(source);
        }
    };
}

fn SliceChoose(comptime T: type) type {
    return Choose(T);
}

pub const slice = struct {
    pub const Empty = Error;

    pub fn Choose(comptime T: type) type {
        return SliceChoose(T);
    }
};

const LibmvecExpF64x4 = *const fn (@Vector(4, f64)) callconv(.c) @Vector(4, f64);
const LibmvecExpF32x8 = *const fn (@Vector(8, f32)) callconv(.c) @Vector(8, f32);
const LibmExpF64 = *const fn (f64) callconv(.c) f64;
const can_try_libmvec = builtin.target.cpu.arch == .x86_64 and
    builtin.target.os.tag == .linux and
    builtin.target.abi.isGnu() and
    builtin.link_libc;
const can_try_libm = builtin.target.os.tag == .linux and
    builtin.target.abi.isGnu() and
    builtin.link_libc;
const can_try_dynamic_lib = can_try_libmvec or can_try_libm;
const ProfileDynLib = if (can_try_dynamic_lib) std.DynLib else struct {
    fn close(self: *@This()) void {
        _ = self;
    }

    fn lookup(self: *@This(), comptime T: type, name: [:0]const u8) ?T {
        _ = self;
        _ = name;
        return null;
    }
};

pub fn uniform(rng: Rng, comptime T: type, min: T, max: T) T {
    return uniformFrom(rng, T, min, max);
}

pub fn uniformFrom(source: anytype, comptime T: type, min: T, max: T) T {
    switch (@typeInfo(T)) {
        .int => return Rng.intRangeLessThanFrom(source, T, min, max),
        .float => {
            std.debug.assert(min <= max);
            return Rng.floatRangeFrom(source, T, min, max);
        },
        else => @compileError("uniform supports integer and floating-point types"),
    }
}

pub fn uniformChecked(rng: Rng, comptime T: type, min: T, max: T) Error!T {
    return uniformCheckedFrom(rng, T, min, max);
}

pub fn uniformCheckedFrom(source: anytype, comptime T: type, min: T, max: T) Error!T {
    switch (@typeInfo(T)) {
        .int => return Rng.intRangeLessThanCheckedFrom(source, T, min, max),
        .float => return Rng.floatRangeCheckedFrom(source, T, min, max),
        else => @compileError("uniformChecked supports integer and floating-point types"),
    }
}

pub fn sampleSingle(rng: Rng, comptime T: type, min: T, max: T) Error!T {
    return uniformChecked(rng, T, min, max);
}

pub fn sampleSingleFrom(source: anytype, comptime T: type, min: T, max: T) Error!T {
    return uniformCheckedFrom(source, T, min, max);
}

pub fn fillUniform(rng: Rng, comptime T: type, dest: []T, min: T, max: T) void {
    fillUniformFrom(rng, T, dest, min, max);
}

pub fn fillUniformFrom(source: anytype, comptime T: type, dest: []T, min: T, max: T) void {
    switch (@typeInfo(T)) {
        .int, .float => Rng.fillRangeFrom(source, T, dest, min, max),
        else => @compileError("fillUniform supports integer and floating-point slices"),
    }
}

pub fn fillUniformChecked(rng: Rng, comptime T: type, dest: []T, min: T, max: T) Error!void {
    return fillUniformCheckedFrom(rng, T, dest, min, max);
}

pub fn fillUniformCheckedFrom(source: anytype, comptime T: type, dest: []T, min: T, max: T) Error!void {
    switch (@typeInfo(T)) {
        .int, .float => try Rng.fillRangeCheckedFrom(source, T, dest, min, max),
        else => @compileError("fillUniformChecked supports integer and floating-point slices"),
    }
}

pub fn uniformInclusive(rng: Rng, comptime T: type, min: T, max: T) T {
    return uniformInclusiveFrom(rng, T, min, max);
}

pub fn uniformInclusiveFrom(source: anytype, comptime T: type, min: T, max: T) T {
    switch (@typeInfo(T)) {
        .int => return Rng.intRangeAtMostFrom(source, T, min, max),
        .float => {
            std.debug.assert(min <= max);
            if (min == max) return min;
            return min + (max - min) * uniformClosedUnitFrom(source, T);
        },
        else => @compileError("uniformInclusive supports integer and floating-point types"),
    }
}

pub fn uniformInclusiveChecked(rng: Rng, comptime T: type, min: T, max: T) Error!T {
    return uniformInclusiveCheckedFrom(rng, T, min, max);
}

pub fn uniformInclusiveCheckedFrom(source: anytype, comptime T: type, min: T, max: T) Error!T {
    switch (@typeInfo(T)) {
        .int => return Rng.intRangeAtMostCheckedFrom(source, T, min, max),
        .float => {
            try validateFiniteFloatRange(T, min, max, true);
            return uniformInclusiveFrom(source, T, min, max);
        },
        else => @compileError("uniformInclusiveChecked supports integer and floating-point types"),
    }
}

pub fn sampleSingleInclusive(rng: Rng, comptime T: type, min: T, max: T) Error!T {
    return uniformInclusiveChecked(rng, T, min, max);
}

pub fn sampleSingleInclusiveFrom(source: anytype, comptime T: type, min: T, max: T) Error!T {
    return uniformInclusiveCheckedFrom(source, T, min, max);
}

pub fn fillUniformInclusive(rng: Rng, comptime T: type, dest: []T, min: T, max: T) void {
    fillUniformInclusiveFrom(rng, T, dest, min, max);
}

pub fn fillUniformInclusiveFrom(source: anytype, comptime T: type, dest: []T, min: T, max: T) void {
    switch (@typeInfo(T)) {
        .int => {
            if (min == max) {
                @memset(dest, min);
                return;
            }
            for (dest) |*item| item.* = Rng.intRangeAtMostFrom(source, T, min, max);
        },
        .float => {
            std.debug.assert(min <= max and std.math.isFinite(min) and std.math.isFinite(max));
            if (min == max) {
                @memset(dest, min);
                return;
            }
            const width = max - min;
            for (dest) |*item| item.* = min + width * uniformClosedUnitFrom(source, T);
        },
        else => @compileError("fillUniformInclusive supports integer and floating-point slices"),
    }
}

pub fn fillUniformInclusiveChecked(rng: Rng, comptime T: type, dest: []T, min: T, max: T) Error!void {
    return fillUniformInclusiveCheckedFrom(rng, T, dest, min, max);
}

pub fn fillUniformInclusiveCheckedFrom(source: anytype, comptime T: type, dest: []T, min: T, max: T) Error!void {
    if (dest.len == 0) return;
    switch (@typeInfo(T)) {
        .int => {
            if (min > max) return error.EmptyRange;
            fillUniformInclusiveFrom(source, T, dest, min, max);
        },
        .float => {
            try validateFiniteFloatRange(T, min, max, true);
            fillUniformInclusiveFrom(source, T, dest, min, max);
        },
        else => @compileError("fillUniformInclusiveChecked supports integer and floating-point slices"),
    }
}

pub fn vectorUniform(rng: Rng, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType)) VectorType {
    return vectorUniformFrom(rng, VectorType, min, max);
}

pub fn vectorUniformFrom(source: anytype, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType)) VectorType {
    return Rng.vectorRangeFrom(source, VectorType, min, max);
}

pub fn vectorUniformChecked(rng: Rng, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType)) Error!VectorType {
    return vectorUniformCheckedFrom(rng, VectorType, min, max);
}

pub fn vectorUniformCheckedFrom(source: anytype, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType)) Error!VectorType {
    return Rng.vectorRangeCheckedFrom(source, VectorType, min, max);
}

pub fn fillVectorUniform(rng: Rng, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType)) void {
    fillVectorUniformFrom(rng, VectorType, dest, min, max);
}

pub fn fillVectorUniformFrom(source: anytype, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType)) void {
    Rng.fillVectorRangeFrom(source, VectorType, dest, min, max);
}

pub fn fillVectorUniformChecked(rng: Rng, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType)) Error!void {
    return fillVectorUniformCheckedFrom(rng, VectorType, dest, min, max);
}

pub fn fillVectorUniformCheckedFrom(source: anytype, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType)) Error!void {
    return Rng.fillVectorRangeCheckedFrom(source, VectorType, dest, min, max);
}

pub fn vectorUniformInclusive(rng: Rng, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType)) VectorType {
    return vectorUniformInclusiveFrom(rng, VectorType, min, max);
}

pub fn vectorUniformInclusiveFrom(source: anytype, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType)) VectorType {
    const info = vectorInfo(VectorType);
    switch (@typeInfo(info.child)) {
        .int => {
            std.debug.assert(min <= max);
            if (min == max) return @splat(min);
            var out: VectorType = undefined;
            inline for (0..info.len) |lane| out[lane] = Rng.intRangeAtMostFrom(source, info.child, min, max);
            return out;
        },
        .float => {
            std.debug.assert(min <= max and std.math.isFinite(min) and std.math.isFinite(max));
            if (min == max) return @splat(min);
            return @as(VectorType, @splat(min)) +
                (@as(VectorType, @splat(max)) - @as(VectorType, @splat(min))) *
                    vectorClosedUnitFrom(source, VectorType);
        },
        else => @compileError("vectorUniformInclusive supports integer and floating-point vectors"),
    }
}

pub fn vectorUniformInclusiveChecked(rng: Rng, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType)) Error!VectorType {
    return vectorUniformInclusiveCheckedFrom(rng, VectorType, min, max);
}

pub fn vectorUniformInclusiveCheckedFrom(source: anytype, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType)) Error!VectorType {
    try validateVectorInclusiveRange(VectorType, min, max);
    return vectorUniformInclusiveFrom(source, VectorType, min, max);
}

pub fn fillVectorUniformInclusive(rng: Rng, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType)) void {
    fillVectorUniformInclusiveFrom(rng, VectorType, dest, min, max);
}

pub fn fillVectorUniformInclusiveFrom(source: anytype, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType)) void {
    const info = vectorInfo(VectorType);
    if ((@typeInfo(info.child) == .int or @typeInfo(info.child) == .float) and min == max) {
        @memset(dest, @as(VectorType, @splat(min)));
        return;
    }
    for (dest) |*item| item.* = vectorUniformInclusiveFrom(source, VectorType, min, max);
}

pub fn fillVectorUniformInclusiveChecked(rng: Rng, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType)) Error!void {
    return fillVectorUniformInclusiveCheckedFrom(rng, VectorType, dest, min, max);
}

pub fn fillVectorUniformInclusiveCheckedFrom(source: anytype, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType)) Error!void {
    if (dest.len == 0) return;
    try validateVectorInclusiveRange(VectorType, min, max);
    fillVectorUniformInclusiveFrom(source, VectorType, dest, min, max);
}

fn validateVectorInclusiveRange(comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType)) Error!void {
    const info = vectorInfo(VectorType);
    switch (@typeInfo(info.child)) {
        .int => {
            if (min > max) return error.EmptyRange;
        },
        .float => {
            try validateFiniteFloatRange(info.child, min, max, true);
        },
        else => @compileError("vectorUniformInclusiveChecked supports integer and floating-point vectors"),
    }
}

fn uniformClosedUnitFrom(source: anytype, comptime T: type) T {
    comptime requireFloat(T);
    return switch (T) {
        f32 => @as(f32, @floatFromInt(@as(u24, @truncate(Rng.nextFrom(source) >> 40)))) *
            (1.0 / 16777215.0),
        f64 => @as(f64, @floatFromInt(Rng.nextFrom(source) >> 11)) *
            (1.0 / 9007199254740991.0),
        else => @compileError("alea supports f32 and f64 floats"),
    };
}

fn vectorClosedUnitFrom(source: anytype, comptime VectorType: type) VectorType {
    const info = vectorInfo(VectorType);
    comptime requireFloat(info.child);
    var out: VectorType = undefined;
    inline for (0..info.len) |lane| out[lane] = uniformClosedUnitFrom(source, info.child);
    return out;
}

pub fn bernoulli(rng: Rng, p: f64) bool {
    const dist = Bernoulli.init(p) catch unreachable;
    return dist.sampleFrom(rng);
}

pub fn bernoulliFrom(source: anytype, p: f64) bool {
    const dist = Bernoulli.init(p) catch unreachable;
    return dist.sampleFrom(source);
}

pub fn bernoulliChecked(rng: Rng, p: f64) Error!bool {
    return bernoulliCheckedFrom(rng, p);
}

pub fn bernoulliCheckedFrom(source: anytype, p: f64) Error!bool {
    const dist = try Bernoulli.init(p);
    return dist.sampleFrom(source);
}

pub fn fillBernoulli(rng: Rng, dest: []bool, p: f64) void {
    fillBernoulliFrom(rng, dest, p);
}

pub fn fillBernoulliFrom(source: anytype, dest: []bool, p: f64) void {
    const dist = Bernoulli.init(p) catch unreachable;
    dist.fillFrom(source, dest);
}

pub fn fillBernoulliChecked(rng: Rng, dest: []bool, p: f64) Error!void {
    return fillBernoulliCheckedFrom(rng, dest, p);
}

pub fn fillBernoulliCheckedFrom(source: anytype, dest: []bool, p: f64) Error!void {
    if (dest.len == 0) return;
    const dist = try Bernoulli.init(p);
    dist.fillFrom(source, dest);
}

pub fn vectorBernoulli(rng: Rng, comptime VectorType: type, p: f64) VectorType {
    return vectorBernoulliFrom(rng, VectorType, p);
}

pub fn vectorBernoulliFrom(source: anytype, comptime VectorType: type, p: f64) VectorType {
    const dist = VectorBernoulli(VectorType).init(p) catch unreachable;
    return dist.sampleFrom(source);
}

pub fn vectorBernoulliChecked(rng: Rng, comptime VectorType: type, p: f64) Error!VectorType {
    return vectorBernoulliCheckedFrom(rng, VectorType, p);
}

pub fn vectorBernoulliCheckedFrom(source: anytype, comptime VectorType: type, p: f64) Error!VectorType {
    const dist = try VectorBernoulli(VectorType).init(p);
    return dist.sampleFrom(source);
}

pub fn fillVectorBernoulli(rng: Rng, comptime VectorType: type, dest: []VectorType, p: f64) void {
    fillVectorBernoulliFrom(rng, VectorType, dest, p);
}

pub fn fillVectorBernoulliFrom(source: anytype, comptime VectorType: type, dest: []VectorType, p: f64) void {
    const dist = VectorBernoulli(VectorType).init(p) catch unreachable;
    dist.fillFrom(source, dest);
}

pub fn fillVectorBernoulliChecked(rng: Rng, comptime VectorType: type, dest: []VectorType, p: f64) Error!void {
    return fillVectorBernoulliCheckedFrom(rng, VectorType, dest, p);
}

