fn standardNormalNativeF32Tail(source: anytype, u: f32) f32 {
    var x: f32 = 1;
    var y: f32 = 0;
    while (-2.0 * y < x * x) {
        x = @log(Rng.floatOpenFrom(source, f32)) / native_f32_norm_r;
        y = @log(Rng.floatOpenFrom(source, f32));
    }
    return if (u < 0) x - native_f32_norm_r else native_f32_norm_r - x;
}

