pub fn LogNormal(comptime T: type) type {
    return struct {
        const Self = @This();

        normal_sampler: Normal(T),

        pub fn init(mean: T, stddev: T) Error!Self {
            return .{ .normal_sampler = try Normal(T).init(mean, stddev) };
        }

        pub fn new(mean: T, stddev: T) Error!Self {
            return Self.init(mean, stddev);
        }

        pub fn initMeanCv(mean: T, coefficient_of_variation: T) Error!Self {
            comptime requireFloat(T);
            if (coefficient_of_variation == 0) {
                if (mean == 0) {
                    return .{ .normal_sampler = .{ .mean = -std.math.inf(T), .stddev = 0 } };
                }
                if (!(mean > 0) or !std.math.isFinite(mean)) return error.InvalidParameter;
                return .{ .normal_sampler = try Normal(T).init(@log(mean), 0) };
            }
            if (!(mean > 0) or !std.math.isFinite(mean)) return error.InvalidParameter;
            if (!(coefficient_of_variation >= 0) or !std.math.isFinite(coefficient_of_variation)) return error.InvalidParameter;

            const variance_ratio = coefficient_of_variation * coefficient_of_variation;
            const stddev = @sqrt(std.math.log1p(variance_ratio));
            const log_mean = @log(mean) - 0.5 * stddev * stddev;
            return .{ .normal_sampler = try Normal(T).init(log_mean, stddev) };
        }

        pub fn fromMeanCv(mean: T, coefficient_of_variation: T) Error!Self {
            return Self.initMeanCv(mean, coefficient_of_variation);
        }

        pub fn sample(self: *Self, rng: Rng) T {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: *Self, source: anytype) T {
            return logNormalFrom(source, T, self.normal_sampler.mean, self.normal_sampler.stddev);
        }

        pub fn fromZScore(self: Self, z_score: T) T {
            return @exp(self.normal_sampler.fromZScore(z_score));
        }

        pub fn logMean(self: Self) T {
            return self.normal_sampler.meanValue();
        }

        pub fn logMeanValue(self: Self) T {
            return self.logMean();
        }

        pub fn logStddev(self: Self) T {
            return self.normal_sampler.stddevValue();
        }

        pub fn logStddevValue(self: Self) T {
            return self.logStddev();
        }

        pub fn linearMeanValue(self: Self) T {
            const sigma = self.logStddev();
            return @exp(self.logMean() + 0.5 * sigma * sigma);
        }

        pub fn medianValue(self: Self) T {
            return @exp(self.logMean());
        }

        pub fn modeValue(self: Self) T {
            const sigma = self.logStddev();
            return @exp(self.logMean() - sigma * sigma);
        }

        pub fn expectedValue(self: Self) T {
            return self.linearMeanValue();
        }

        pub fn varianceValue(self: Self) T {
            const sigma = self.logStddev();
            const mean = self.linearMeanValue();
            return (@exp(sigma * sigma) - 1) * mean * mean;
        }

        pub fn minValue(self: Self) T {
            if (self.logStddev() == 0) return self.linearMeanValue();
            return 0;
        }

        pub fn maxValue(self: Self) ?T {
            if (self.logStddev() == 0) return self.linearMeanValue();
            return null;
        }

        pub fn coefficientOfVariationValue(self: Self) T {
            const sigma = self.logStddev();
            return @sqrt(@exp(sigma * sigma) - 1);
        }

        pub fn fill(self: *Self, rng: Rng, dest: []T) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: *Self, source: anytype, dest: []T) void {
            fillLogNormalFrom(source, T, dest, self.normal_sampler.mean, self.normal_sampler.stddev);
        }
    };
}

pub fn BufferedLogNormal(comptime T: type, comptime buffer_len: usize) type {
    comptime {
        requireFloat(T);
        if (buffer_len == 0) @compileError("BufferedLogNormal buffer_len must be greater than zero");
    }

    return struct {
        const Self = @This();

        pub const capacity: usize = buffer_len;

        log_mean: T,
        log_stddev: T,
        buffer: [buffer_len]T = undefined,
        index: usize = buffer_len,

        pub fn init(mean: T, stddev: T) Error!Self {
            const base = try LogNormal(T).init(mean, stddev);
            return .{
                .log_mean = base.normal_sampler.mean,
                .log_stddev = base.normal_sampler.stddev,
            };
        }

        pub fn initMeanCv(mean: T, coefficient_of_variation: T) Error!Self {
            const base = try LogNormal(T).initMeanCv(mean, coefficient_of_variation);
            return .{
                .log_mean = base.normal_sampler.mean,
                .log_stddev = base.normal_sampler.stddev,
            };
        }

        pub fn logMeanValue(self: Self) T {
            return self.log_mean;
        }

        pub fn logMean(self: Self) T {
            return self.logMeanValue();
        }

        pub fn logStddevValue(self: Self) T {
            return self.log_stddev;
        }

        pub fn logStddev(self: Self) T {
            return self.logStddevValue();
        }

        pub fn linearMeanValue(self: Self) T {
            const sigma = self.logStddev();
            return @exp(self.logMean() + 0.5 * sigma * sigma);
        }

        pub fn medianValue(self: Self) T {
            return @exp(self.logMean());
        }

        pub fn modeValue(self: Self) T {
            const sigma = self.logStddev();
            return @exp(self.logMean() - sigma * sigma);
        }

        pub fn expectedValue(self: Self) T {
            return self.linearMeanValue();
        }

        pub fn varianceValue(self: Self) T {
            const sigma = self.logStddev();
            const mean = self.linearMeanValue();
            return (@exp(sigma * sigma) - 1) * mean * mean;
        }

        pub fn minValue(self: Self) T {
            if (self.logStddev() == 0) return self.linearMeanValue();
            return 0;
        }

        pub fn maxValue(self: Self) ?T {
            if (self.logStddev() == 0) return self.linearMeanValue();
            return null;
        }

        pub fn coefficientOfVariationValue(self: Self) T {
            const sigma = self.logStddev();
            return @sqrt(@exp(sigma * sigma) - 1);
        }

        pub fn bufferedValueCount(self: Self) usize {
            return buffer_len - self.index;
        }

        pub fn reset(self: *Self) void {
            self.index = buffer_len;
        }

        pub fn sample(self: *Self, rng: Rng) T {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: *Self, source: anytype) T {
            if (self.log_stddev == 0) return @exp(self.log_mean);
            if (self.index == buffer_len) {
                fillLogNormalFrom(source, T, self.buffer[0..], self.log_mean, self.log_stddev);
                self.index = 0;
            }
            const value = self.buffer[self.index];
            self.index += 1;
            return value;
        }

        pub fn fill(self: *Self, rng: Rng, dest: []T) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: *Self, source: anytype, dest: []T) void {
            if (self.log_stddev == 0) {
                @memset(dest, @exp(self.log_mean));
                return;
            }
            var written: usize = 0;
            if (self.index < buffer_len) {
                const buffered_count = buffer_len - self.index;
                const n = @min(dest.len, buffered_count);
                @memcpy(dest[0..n], self.buffer[self.index..][0..n]);
                self.index += n;
                written += n;
            }
            while (written + buffer_len <= dest.len) : (written += buffer_len) {
                fillLogNormalFrom(source, T, dest[written..][0..buffer_len], self.log_mean, self.log_stddev);
            }
            if (written < dest.len) {
                fillLogNormalFrom(source, T, self.buffer[0..], self.log_mean, self.log_stddev);
                self.index = 0;
                const n = dest.len - written;
                @memcpy(dest[written..], self.buffer[0..n]);
                self.index = n;
            }
        }
    };
}

pub fn LogNormalLibmvec(comptime T: type, comptime buffer_len: usize) type {
