                .exp_f64x4 = if (T == f64) lookupLibmvecExpF64x4(&lib) orelse return error.LibmvecUnavailable else {},
                .exp_f32x8 = if (T == f32) lookupLibmvecExpF32x8(&lib) orelse return error.LibmvecUnavailable else {},
