pub fn geometricFailuresFrom(source: anytype, p: f64) u64 {
    std.debug.assert(p > 0 and p <= 1);
    if (p == 1) return 0;
    return @intFromFloat(@floor(@log(1 - Rng.floatOpenFrom(source, f64)) / @log(1 - p)));
}

