pub fn chiSquaredFrom(source: anytype, comptime T: type, dof: T) T {
    comptime requireFloat(T);
    std.debug.assert(dof >= 0 and std.math.isFinite(dof));
    if (dof == 0) return 0;
    return gammaFrom(source, T, dof / 2, 2);
}

