    comptime requireFloat(T);
    std.debug.assert(dof >= 0 and std.math.isFinite(dof));
    if (dof == 0) {
        @memset(dest, 0);
        return;
    }
    if (dof == 1) {
        for (dest) |*item| {
            const z = Rng.standardNormalFastFrom(source, T);
            item.* = z * z;
        }
        return;
    }

    const sampler = ChiSquared(T).init(dof) catch unreachable;
    sampler.fillFrom(source, dest);
}

