fn kumaraswamyFromOpenUniformVector(comptime VectorType: type, uniform_vec: VectorType, inverse_alpha: vectorChild(VectorType), inverse_beta: vectorChild(VectorType)) VectorType {
    const one_vec: VectorType = @splat(1);
    const inverse_alpha_vec: VectorType = @splat(inverse_alpha);
    const inverse_beta_vec: VectorType = @splat(inverse_beta);
    return @exp(@log(one_vec - @exp(@log(one_vec - uniform_vec) * inverse_beta_vec)) * inverse_alpha_vec);
}

fn kumaraswamyBetaOneFromOpenUniformVector(comptime VectorType: type, uniform_vec: VectorType, inverse_alpha: vectorChild(VectorType)) VectorType {
    const inverse_alpha_vec: VectorType = @splat(inverse_alpha);
    return @exp(@log(uniform_vec) * inverse_alpha_vec);
}

fn kumaraswamyAlphaOneFromOpenUniformVector(comptime VectorType: type, uniform_vec: VectorType, inverse_beta: vectorChild(VectorType)) VectorType {
    const one_vec: VectorType = @splat(1);
    const inverse_beta_vec: VectorType = @splat(inverse_beta);
    return one_vec - @exp(@log(one_vec - uniform_vec) * inverse_beta_vec);
}

pub fn VectorKumaraswamy(comptime VectorType: type) type {
    const Child = vectorChild(VectorType);
    requireFloat(Child);

    return struct {
        const Self = @This();

        sampler: Kumaraswamy(Child),

        pub fn init(alpha: Child, beta_param: Child) Error!Self {
            return .{ .sampler = try Kumaraswamy(Child).init(alpha, beta_param) };
        }

        pub fn alphaValue(self: Self) Child {
            return self.sampler.alphaValue();
        }

        pub fn betaValue(self: Self) Child {
            return self.sampler.betaValue();
        }

        pub fn expectedValue(self: Self) Child {
            return self.sampler.expectedValue();
        }

        pub fn varianceValue(self: Self) Child {
            return self.sampler.varianceValue();
        }

        pub fn modeValue(self: Self) ?Child {
            return self.sampler.modeValue();
        }

        pub fn medianValue(self: Self) Child {
            return self.sampler.medianValue();
        }

        pub fn minValue(self: Self) Child {
            return self.sampler.minValue();
        }

        pub fn maxValue(self: Self) Child {
            return self.sampler.maxValue();
        }

        pub fn sample(self: Self, rng: Rng) VectorType {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) VectorType {
            if (self.sampler.isDegenerate()) return @splat(self.sampler.degenerateValue());
            const uniform_vec = Rng.vectorOpenFrom(source, VectorType);
            if (self.sampler.method == .beta_one_sqrt) return @sqrt(uniform_vec);
            if (self.sampler.method == .beta_one) return kumaraswamyBetaOneFromOpenUniformVector(VectorType, uniform_vec, 1 / self.alphaValue());
            if (self.sampler.method == .alpha_one) return kumaraswamyAlphaOneFromOpenUniformVector(VectorType, uniform_vec, 1 / self.betaValue());
            return kumaraswamyFromOpenUniformVector(VectorType, uniform_vec, 1 / self.alphaValue(), 1 / self.betaValue());
        }

        pub fn fill(self: Self, rng: Rng, dest: []VectorType) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []VectorType) void {
            if (self.sampler.isDegenerate()) {
                @memset(dest, @as(VectorType, @splat(self.sampler.degenerateValue())));
                return;
            }
            for (dest) |*item| {
                const uniform_vec = Rng.vectorOpenFrom(source, VectorType);
                item.* = switch (self.sampler.method) {
                    .beta_one_sqrt => @sqrt(uniform_vec),
                    .beta_one => kumaraswamyBetaOneFromOpenUniformVector(VectorType, uniform_vec, 1 / self.alphaValue()),
                    .alpha_one => kumaraswamyAlphaOneFromOpenUniformVector(VectorType, uniform_vec, 1 / self.betaValue()),
                    .generic => kumaraswamyFromOpenUniformVector(VectorType, uniform_vec, 1 / self.alphaValue(), 1 / self.betaValue()),
                    .point_zero, .point_one => unreachable,
                };
            }
        }
    };
}

pub fn Kumaraswamy(comptime T: type) type {
    return struct {
        const Self = @This();
        const Method = enum { generic, alpha_one, beta_one, beta_one_sqrt, point_zero, point_one };

        inverse_alpha: T,
        inverse_beta: T,
        method: Method,

        pub fn init(alpha: T, beta_param: T) Error!Self {
            comptime requireFloat(T);
            if (!kumaraswamyParametersValid(T, alpha, beta_param)) return error.InvalidParameter;
            return .{
                .inverse_alpha = if (alpha == std.math.inf(T)) 0 else 1 / alpha,
                .inverse_beta = if (beta_param == std.math.inf(T)) 0 else 1 / beta_param,
                .method = if (alpha == std.math.inf(T))
                    .point_one
                else if (beta_param == std.math.inf(T))
                    .point_zero
                else if (alpha == 2 and beta_param == 1)
                    .beta_one_sqrt
                else if (beta_param == 1)
                    .beta_one
                else if (alpha == 1)
                    .alpha_one
                else
                    .generic,
            };
        }

        pub fn alphaValue(self: Self) T {
            return 1 / self.inverse_alpha;
        }

        pub fn betaValue(self: Self) T {
            return 1 / self.inverse_beta;
        }

        pub fn expectedValue(self: Self) T {
            if (self.method == .point_one) return 1;
            if (self.method == .point_zero) return 0;
            return self.momentValue(1);
        }

        pub fn varianceValue(self: Self) T {
            if (self.isDegenerate()) return 0;
            const first_moment = self.momentValue(1);
            const second_moment = self.momentValue(2);
            return second_moment - first_moment * first_moment;
        }

        pub fn modeValue(self: Self) ?T {
            if (self.method == .point_one) return 1;
            if (self.method == .point_zero) return 0;
            const alpha = self.alphaValue();
            const beta_param = self.betaValue();
            if (alpha > 1 and alpha * beta_param > 1) {
                return std.math.pow(T, (alpha - 1) / (alpha * beta_param - 1), 1 / alpha);
            }
            if (alpha < 1 and beta_param < 1) return null;
            if (alpha == 1 and beta_param == 1) return null;
            if (beta_param <= 1) return 1;
            return 0;
        }

        pub fn medianValue(self: Self) T {
            if (self.method == .point_one) return 1;
            if (self.method == .point_zero) return 0;
            return std.math.pow(T, 1 - std.math.pow(T, 0.5, self.inverse_beta), self.inverse_alpha);
        }

        pub fn minValue(self: Self) T {
            return if (self.method == .point_one) 1 else 0;
        }

        pub fn maxValue(self: Self) T {
            return if (self.method == .point_zero) 0 else 1;
        }

        fn momentValue(self: Self, order: T) T {
            const beta_param = self.betaValue();
            const beta_arg = 1 + order * self.inverse_alpha;
            return beta_param * @exp(std.math.lgamma(T, beta_arg) + std.math.lgamma(T, beta_param) - std.math.lgamma(T, beta_arg + beta_param));
        }

        pub fn sample(self: Self, rng: Rng) T {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) T {
            switch (self.method) {
                .point_zero => return 0,
                .point_one => return 1,
                .beta_one_sqrt => return @sqrt(Rng.floatOpenFrom(source, T)),
                .beta_one => return std.math.pow(T, Rng.floatOpenFrom(source, T), self.inverse_alpha),
                .alpha_one => return 1 - std.math.pow(T, 1 - Rng.floatOpenFrom(source, T), self.inverse_beta),
                .generic => {},
            }

            const u = Rng.floatOpenFrom(source, T);
            return std.math.pow(T, 1 - std.math.pow(T, 1 - u, self.inverse_beta), self.inverse_alpha);
        }

        pub fn fill(self: Self, rng: Rng, dest: []T) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []T) void {
            switch (self.method) {
                .point_zero => {
                    @memset(dest, 0);
                    return;
                },
                .point_one => {
                    @memset(dest, 1);
                    return;
                },
                .beta_one_sqrt => {
                    Rng.fillOpenFrom(source, T, dest);
                    for (dest) |*item| item.* = @sqrt(item.*);
                    return;
                },
                .beta_one => {
                    Rng.fillOpenFrom(source, T, dest);
                    for (dest) |*item| item.* = std.math.pow(T, item.*, self.inverse_alpha);
                    return;
                },
                .alpha_one => {
                    Rng.fillOpenFrom(source, T, dest);
                    for (dest) |*item| item.* = 1 - std.math.pow(T, 1 - item.*, self.inverse_beta);
                    return;
                },
                .generic => {},
            }

            for (dest) |*item| item.* = self.sampleFrom(source);
        }

        fn isDegenerate(self: Self) bool {
            return self.method == .point_zero or self.method == .point_one;
        }

        fn degenerateValue(self: Self) T {
            return if (self.method == .point_one) 1 else 0;
        }
    };
}

pub fn powerFunction(rng: Rng, comptime T: type, min: T, max: T, shape: T) T {
    return powerFunctionFrom(rng, T, min, max, shape);
}

pub fn powerFunctionChecked(rng: Rng, comptime T: type, min: T, max: T, shape: T) Error!T {
    return powerFunctionCheckedFrom(rng, T, min, max, shape);
}

pub fn powerFunctionCheckedFrom(source: anytype, comptime T: type, min: T, max: T, shape: T) Error!T {
    const dist = try PowerFunction(T).init(min, max, shape);
    return dist.sampleFrom(source);
}

pub fn powerFunctionFrom(source: anytype, comptime T: type, min: T, max: T, shape: T) T {
    comptime requireFloat(T);
    std.debug.assert(powerFunctionParametersValid(T, min, max, shape));
    if (min == max) return min;
    if (shape == std.math.inf(T)) return max;

    if (shape == 1) return Rng.floatRangeFrom(source, T, min, max);
    if (shape == 2) return min + (max - min) * @sqrt(Rng.floatOpenFrom(source, T));
    return min + (max - min) * std.math.pow(T, Rng.floatOpenFrom(source, T), 1 / shape);
}

pub fn fillPowerFunction(rng: Rng, comptime T: type, dest: []T, min: T, max: T, shape: T) void {
    fillPowerFunctionFrom(rng, T, dest, min, max, shape);
}

pub fn fillPowerFunctionFrom(source: anytype, comptime T: type, dest: []T, min: T, max: T, shape: T) void {
    comptime requireFloat(T);
    std.debug.assert(powerFunctionParametersValid(T, min, max, shape));
    if (min == max) {
        @memset(dest, min);
        return;
    }
    if (shape == std.math.inf(T)) {
        @memset(dest, max);
        return;
    }
    if (shape == 1) {
        Rng.fillRangeFrom(source, T, dest, min, max);
        return;
    }
    if (shape == 2) {
        const width = max - min;
        Rng.fillOpenFrom(source, T, dest);
        for (dest) |*item| item.* = min + width * @sqrt(item.*);
        return;
    }

    Rng.fillOpenFrom(source, T, dest);
    powerFunctionFromOpenUniforms(T, dest, min, max - min, 1 / shape);
}

fn powerFunctionParametersValid(comptime T: type, min: T, max: T, shape: T) bool {
    return min <= max and shape > 0 and
        std.math.isFinite(min) and
        std.math.isFinite(max) and
        (std.math.isFinite(shape) or shape == std.math.inf(T));
}

pub fn fillPowerFunctionChecked(rng: Rng, comptime T: type, dest: []T, min: T, max: T, shape: T) Error!void {
    return fillPowerFunctionCheckedFrom(rng, T, dest, min, max, shape);
}

pub fn fillPowerFunctionCheckedFrom(source: anytype, comptime T: type, dest: []T, min: T, max: T, shape: T) Error!void {
    if (dest.len == 0) return;
    const sampler = try PowerFunction(T).init(min, max, shape);
    sampler.fillFrom(source, dest);
}

pub fn vectorPowerFunction(rng: Rng, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType), shape: vectorChild(VectorType)) VectorType {
    return vectorPowerFunctionFrom(rng, VectorType, min, max, shape);
}

pub fn vectorPowerFunctionFrom(source: anytype, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType), shape: vectorChild(VectorType)) VectorType {
    const sampler = VectorPowerFunction(VectorType).init(min, max, shape) catch unreachable;
    return sampler.sampleFrom(source);
}

pub fn vectorPowerFunctionChecked(rng: Rng, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType), shape: vectorChild(VectorType)) Error!VectorType {
    return vectorPowerFunctionCheckedFrom(rng, VectorType, min, max, shape);
}

pub fn vectorPowerFunctionCheckedFrom(source: anytype, comptime VectorType: type, min: vectorChild(VectorType), max: vectorChild(VectorType), shape: vectorChild(VectorType)) Error!VectorType {
