    return sampler.sampleFrom(source);
}

pub fn fillVectorPowerFunction(rng: Rng, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType), shape: vectorChild(VectorType)) void {
    fillVectorPowerFunctionFrom(rng, VectorType, dest, min, max, shape);
}

pub fn fillVectorPowerFunctionFrom(source: anytype, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType), shape: vectorChild(VectorType)) void {
    const sampler = VectorPowerFunction(VectorType).init(min, max, shape) catch unreachable;
    sampler.fillFrom(source, dest);
}

pub fn fillVectorPowerFunctionChecked(rng: Rng, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType), shape: vectorChild(VectorType)) Error!void {
    return fillVectorPowerFunctionCheckedFrom(rng, VectorType, dest, min, max, shape);
}

pub fn fillVectorPowerFunctionCheckedFrom(source: anytype, comptime VectorType: type, dest: []VectorType, min: vectorChild(VectorType), max: vectorChild(VectorType), shape: vectorChild(VectorType)) Error!void {
    if (dest.len == 0) return;
    const sampler = try VectorPowerFunction(VectorType).init(min, max, shape);
    sampler.fillFrom(source, dest);
}

fn powerFunctionFromOpenUniformVector(comptime VectorType: type, uniform_vec: VectorType, min: vectorChild(VectorType), width: vectorChild(VectorType), inverse_shape: vectorChild(VectorType)) VectorType {
    if (width == 0) return @splat(min);
    const min_vec: VectorType = @splat(min);
    const width_vec: VectorType = @splat(width);
    const inverse_shape_vec: VectorType = @splat(inverse_shape);
    return min_vec + width_vec * @exp(@log(uniform_vec) * inverse_shape_vec);
}

pub fn VectorPowerFunction(comptime VectorType: type) type {
    const Child = vectorChild(VectorType);
    requireFloat(Child);

    return struct {
        const Self = @This();

        sampler: PowerFunction(Child),

        pub fn init(min: Child, max: Child, shape: Child) Error!Self {
            return .{ .sampler = try PowerFunction(Child).init(min, max, shape) };
        }

        pub fn minValue(self: Self) Child {
            return self.sampler.minValue();
        }

        pub fn maxValue(self: Self) Child {
            return self.sampler.maxValue();
        }

        pub fn shapeValue(self: Self) Child {
            return self.sampler.shapeValue();
        }

        pub fn expectedValue(self: Self) Child {
            return self.sampler.expectedValue();
        }

        pub fn varianceValue(self: Self) Child {
            return self.sampler.varianceValue();
        }

        pub fn medianValue(self: Self) Child {
            return self.sampler.medianValue();
        }

        pub fn sample(self: Self, rng: Rng) VectorType {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) VectorType {
            if (self.sampler.isDegenerate()) return @splat(self.minValue());
            switch (self.sampler.method) {
                .point_max => return @splat(self.maxValue()),
                .uniform => return Rng.vectorRangeFrom(source, VectorType, self.minValue(), self.maxValue()),
                .sqrt => {
                    const uniform_vec = Rng.vectorOpenFrom(source, VectorType);
                    const min_vec: VectorType = @splat(self.minValue());
                    const width_vec: VectorType = @splat(self.maxValue() - self.minValue());
                    return min_vec + width_vec * @sqrt(uniform_vec);
                },
                .generic => {
                    const uniform_vec = Rng.vectorOpenFrom(source, VectorType);
                    return powerFunctionFromOpenUniformVector(VectorType, uniform_vec, self.minValue(), self.maxValue() - self.minValue(), 1 / self.shapeValue());
                },
            }
        }

        pub fn fill(self: Self, rng: Rng, dest: []VectorType) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []VectorType) void {
            if (self.sampler.isDegenerate()) {
                @memset(dest, @as(VectorType, @splat(self.minValue())));
                return;
            }
            switch (self.sampler.method) {
                .point_max => {
                    @memset(dest, @as(VectorType, @splat(self.maxValue())));
                },
                .uniform => {
                    Rng.fillVectorRangeFrom(source, VectorType, dest, self.minValue(), self.maxValue());
                },
                .sqrt => {
                    const min_vec: VectorType = @splat(self.minValue());
                    const width_vec: VectorType = @splat(self.maxValue() - self.minValue());
                    for (dest) |*item| {
                        const uniform_vec = Rng.vectorOpenFrom(source, VectorType);
                        item.* = min_vec + width_vec * @sqrt(uniform_vec);
                    }
                },
                .generic => {
                    const width = self.maxValue() - self.minValue();
                    const inverse_shape = 1 / self.shapeValue();
                    for (dest) |*item| {
                        const uniform_vec = Rng.vectorOpenFrom(source, VectorType);
                        item.* = powerFunctionFromOpenUniformVector(VectorType, uniform_vec, self.minValue(), width, inverse_shape);
                    }
                },
            }
        }
    };
}

pub fn PowerFunction(comptime T: type) type {
    return struct {
        const Self = @This();
        const Method = enum { generic, uniform, sqrt, point_max };

        min: T,
        range: T,
        inverse_shape: T,
        method: Method,

        pub fn init(min: T, max: T, shape: T) Error!Self {
            comptime requireFloat(T);
            if (!powerFunctionParametersValid(T, min, max, shape)) return error.InvalidParameter;
            return .{
                .min = min,
                .range = max - min,
                .inverse_shape = if (shape == std.math.inf(T)) 0 else 1 / shape,
                .method = if (shape == std.math.inf(T))
                    .point_max
                else if (shape == 1)
                    .uniform
                else if (shape == 2)
                    .sqrt
                else
                    .generic,
            };
        }

        pub fn minValue(self: Self) T {
            return if (self.method == .point_max) self.maxValue() else self.min;
        }

        pub fn maxValue(self: Self) T {
            return self.min + self.range;
        }

        pub fn shapeValue(self: Self) T {
            return 1 / self.inverse_shape;
        }

        pub fn expectedValue(self: Self) T {
            if (self.method == .point_max) return self.maxValue();
            const shape = self.shapeValue();
            return self.min + self.range * shape / (shape + 1);
        }

        pub fn varianceValue(self: Self) T {
            if (self.method == .point_max) return 0;
            const shape = self.shapeValue();
            return self.range * self.range * shape / ((shape + 1) * (shape + 1) * (shape + 2));
        }

        pub fn medianValue(self: Self) T {
            if (self.method == .point_max) return self.maxValue();
            return self.min + self.range * std.math.pow(T, 0.5, self.inverse_shape);
        }

        pub fn sample(self: Self, rng: Rng) T {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) T {
            if (self.isDegenerate()) return self.degenerateValue();
            return switch (self.method) {
                .point_max => self.maxValue(),
                .uniform => Rng.floatRangeFrom(source, T, self.min, self.min + self.range),
                .sqrt => self.min + self.range * @sqrt(Rng.floatOpenFrom(source, T)),
                .generic => self.min + self.range * std.math.pow(T, Rng.floatOpenFrom(source, T), self.inverse_shape),
            };
        }

        pub fn fill(self: Self, rng: Rng, dest: []T) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []T) void {
            if (self.isDegenerate()) {
                @memset(dest, self.degenerateValue());
                return;
            }
            switch (self.method) {
                .point_max => {
                    @memset(dest, self.maxValue());
                    return;
                },
                .uniform => {
                    Rng.fillRangeFrom(source, T, dest, self.min, self.min + self.range);
                    return;
                },
                .sqrt => {
                    Rng.fillOpenFrom(source, T, dest);
                    for (dest) |*item| item.* = self.min + self.range * @sqrt(item.*);
                    return;
                },
                .generic => {},
            }

            Rng.fillOpenFrom(source, T, dest);
            powerFunctionFromOpenUniforms(T, dest, self.min, self.range, self.inverse_shape);
        }

        fn isDegenerate(self: Self) bool {
            return self.range == 0 or self.method == .point_max;
        }

        fn degenerateValue(self: Self) T {
            return if (self.method == .point_max) self.maxValue() else self.min;
        }
    };
}

pub fn rayleigh(rng: Rng, comptime T: type, scale: T) T {
    return rayleighFrom(rng, T, scale);
}

pub fn rayleighChecked(rng: Rng, comptime T: type, scale: T) Error!T {
    return rayleighCheckedFrom(rng, T, scale);
}

pub fn rayleighCheckedFrom(source: anytype, comptime T: type, scale: T) Error!T {
    const dist = try Rayleigh(T).init(scale);
    return dist.sampleFrom(source);
}

pub fn rayleighFrom(source: anytype, comptime T: type, scale: T) T {
    comptime requireFloat(T);
    std.debug.assert(scale >= 0 and std.math.isFinite(scale));
    if (scale == 0) return 0;

    return scale * @sqrt(-2 * @log(Rng.floatOpenFrom(source, T)));
}

pub fn fillRayleigh(rng: Rng, comptime T: type, dest: []T, scale: T) void {
    fillRayleighFrom(rng, T, dest, scale);
}

pub fn fillRayleighFrom(source: anytype, comptime T: type, dest: []T, scale: T) void {
    comptime requireFloat(T);
    std.debug.assert(scale >= 0 and std.math.isFinite(scale));
    if (scale == 0) {
        @memset(dest, 0);
        return;
    }
    Rng.fillOpenFrom(source, T, dest);
    rayleighFromOpenUniforms(T, dest, scale);
}

pub fn fillRayleighChecked(rng: Rng, comptime T: type, dest: []T, scale: T) Error!void {
    return fillRayleighCheckedFrom(rng, T, dest, scale);
}

pub fn fillRayleighCheckedFrom(source: anytype, comptime T: type, dest: []T, scale: T) Error!void {
    if (dest.len == 0) return;
    const sampler = try Rayleigh(T).init(scale);
    sampler.fillFrom(source, dest);
}

pub fn vectorRayleigh(rng: Rng, comptime VectorType: type, scale: vectorChild(VectorType)) VectorType {
    return vectorRayleighFrom(rng, VectorType, scale);
}

pub fn vectorRayleighFrom(source: anytype, comptime VectorType: type, scale: vectorChild(VectorType)) VectorType {
    const sampler = VectorRayleigh(VectorType).init(scale) catch unreachable;
    return sampler.sampleFrom(source);
}

pub fn vectorRayleighChecked(rng: Rng, comptime VectorType: type, scale: vectorChild(VectorType)) Error!VectorType {
    return vectorRayleighCheckedFrom(rng, VectorType, scale);
}

pub fn vectorRayleighCheckedFrom(source: anytype, comptime VectorType: type, scale: vectorChild(VectorType)) Error!VectorType {
    const sampler = try VectorRayleigh(VectorType).init(scale);
    return sampler.sampleFrom(source);
}

pub fn fillVectorRayleigh(rng: Rng, comptime VectorType: type, dest: []VectorType, scale: vectorChild(VectorType)) void {
    fillVectorRayleighFrom(rng, VectorType, dest, scale);
}

pub fn fillVectorRayleighFrom(source: anytype, comptime VectorType: type, dest: []VectorType, scale: vectorChild(VectorType)) void {
