    comptime requireFloat(T);
    std.debug.assert(scale >= 0 and std.math.isFinite(scale));
    if (scale == 0) {
        @memset(dest, 0);
        return;
    }
    for (dest) |*item| item.* = maxwellFrom(source, T, scale);
}

