pub fn VectorMaxwell(comptime VectorType: type) type {
    const Child = vectorChild(VectorType);
    requireFloat(Child);

    return struct {
        const Self = @This();

        sampler: Maxwell(Child),

        pub fn init(scale: Child) Error!Self {
            return .{ .sampler = try Maxwell(Child).init(scale) };
        }

