fn frechetFromOpenClosedUniformVector(comptime VectorType: type, uniform_vec: VectorType, location: vectorChild(VectorType), scale: vectorChild(VectorType), negative_inverse_shape: vectorChild(VectorType)) VectorType {
    const location_vec: VectorType = @splat(location);
    const scale_vec: VectorType = @splat(scale);
    const negative_inverse_shape_vec: VectorType = @splat(negative_inverse_shape);
    return location_vec + scale_vec * @exp(@log(-@log(uniform_vec)) * negative_inverse_shape_vec);
}

fn frechetShapeOneFromOpenClosedUniformVector(comptime VectorType: type, uniform_vec: VectorType, location: vectorChild(VectorType), scale: vectorChild(VectorType)) VectorType {
    const location_vec: VectorType = @splat(location);
    const negative_scale_vec: VectorType = @splat(-scale);
    return location_vec + negative_scale_vec / @log(uniform_vec);
}

pub fn VectorFrechet(comptime VectorType: type) type {
    const Child = vectorChild(VectorType);
    requireFloat(Child);

    return struct {
        const Self = @This();

        sampler: Frechet(Child),

        pub fn init(location: Child, scale: Child, shape: Child) Error!Self {
            return .{ .sampler = try Frechet(Child).init(location, scale, shape) };
        }

        pub fn locationValue(self: Self) Child {
            return self.sampler.locationValue();
        }

        pub fn scaleValue(self: Self) Child {
            return self.sampler.scaleValue();
        }

        pub fn shapeValue(self: Self) Child {
            return self.sampler.shapeValue();
        }

        pub fn expectedValue(self: Self) ?Child {
            return self.sampler.expectedValue();
        }

        pub fn varianceValue(self: Self) ?Child {
            return self.sampler.varianceValue();
        }

        pub fn medianValue(self: Self) Child {
            return self.sampler.medianValue();
        }

        pub fn modeValue(self: Self) Child {
            return self.sampler.modeValue();
        }

        pub fn minValue(self: Self) Child {
            return self.sampler.minValue();
        }

        pub fn maxValue(self: Self) ?Child {
            return self.sampler.maxValue();
        }

        pub fn sample(self: Self, rng: Rng) VectorType {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) VectorType {
            if (self.sampler.isDegenerate()) return @splat(self.sampler.degenerateValue());
            const uniform_vec = Rng.vectorOpenClosedFrom(source, VectorType);
            if (self.shapeValue() == 1) return frechetShapeOneFromOpenClosedUniformVector(VectorType, uniform_vec, self.locationValue(), self.scaleValue());
            return frechetFromOpenClosedUniformVector(VectorType, uniform_vec, self.locationValue(), self.scaleValue(), -1 / self.shapeValue());
        }

        pub fn fill(self: Self, rng: Rng, dest: []VectorType) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []VectorType) void {
            if (self.sampler.isDegenerate()) {
                @memset(dest, @as(VectorType, @splat(self.sampler.degenerateValue())));
                return;
            }
            for (dest) |*item| {
                const uniform_vec = Rng.vectorOpenClosedFrom(source, VectorType);
                if (self.shapeValue() == 1) {
                    item.* = frechetShapeOneFromOpenClosedUniformVector(VectorType, uniform_vec, self.locationValue(), self.scaleValue());
                } else {
                    item.* = frechetFromOpenClosedUniformVector(VectorType, uniform_vec, self.locationValue(), self.scaleValue(), -1 / self.shapeValue());
                }
            }
        }
    };
}

pub fn Frechet(comptime T: type) type {
    return struct {
        const Self = @This();

        location: T,
        scale: T,
        shape: T,

        pub fn init(location: T, scale: T, shape: T) Error!Self {
            comptime requireFloat(T);
            if (!frechetParametersValid(T, location, scale, shape)) return error.InvalidParameter;
            return .{ .location = location, .scale = scale, .shape = shape };
        }

        pub fn new(location: T, scale: T, shape: T) Error!Self {
            return Self.init(location, scale, shape);
        }

        pub fn locationValue(self: Self) T {
            return self.location;
        }

        pub fn scaleValue(self: Self) T {
            return self.scale;
        }

        pub fn shapeValue(self: Self) T {
            return self.shape;
        }

        pub fn expectedValue(self: Self) ?T {
            if (self.isDegenerate()) return self.degenerateValue();
            if (!(self.shape > 1)) return null;
            return self.location + self.scale * std.math.gamma(T, 1 - 1 / self.shape);
        }

        pub fn varianceValue(self: Self) ?T {
            if (self.isDegenerate()) return 0;
            if (!(self.shape > 2)) return null;
            const mean_factor = std.math.gamma(T, 1 - 1 / self.shape);
            const second_moment_factor = std.math.gamma(T, 1 - 2 / self.shape);
            const scale_squared = self.scale * self.scale;
            return scale_squared * (second_moment_factor - mean_factor * mean_factor);
        }

        pub fn medianValue(self: Self) T {
            if (self.isDegenerate()) return self.degenerateValue();
            return self.location + self.scale * std.math.pow(T, @log(@as(T, 2)), -1 / self.shape);
        }

        pub fn modeValue(self: Self) T {
            if (self.isDegenerate()) return self.degenerateValue();
            return self.location + self.scale * std.math.pow(T, self.shape / (self.shape + 1), 1 / self.shape);
        }

        pub fn minValue(self: Self) T {
            return if (self.isDegenerate()) self.degenerateValue() else self.location;
        }

        pub fn maxValue(self: Self) ?T {
            return if (self.isDegenerate()) self.degenerateValue() else null;
        }

        pub fn sample(self: Self, rng: Rng) T {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) T {
            if (self.isDegenerate()) return self.degenerateValue();
            return frechetFrom(source, T, self.location, self.scale, self.shape);
        }

        pub fn fill(self: Self, rng: Rng, dest: []T) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []T) void {
            if (self.isDegenerate()) {
                @memset(dest, self.degenerateValue());
                return;
            }
            fillFrechetFrom(source, T, dest, self.location, self.scale, self.shape);
        }

        fn isDegenerate(self: Self) bool {
            return self.scale == 0 or self.shape == std.math.inf(T);
        }

        fn degenerateValue(self: Self) T {
            return if (self.shape == std.math.inf(T)) self.location + self.scale else self.location;
        }
    };
}

