pub fn VectorZipf(comptime VectorType: type) type {
    const Child = vectorChild(VectorType);
    requireFloat(Child);

    return struct {
        const Self = @This();

        sampler: Zipf(Child),

        pub fn init(n: Child, exponent: Child) Error!Self {
            return .{ .sampler = try Zipf(Child).init(n, exponent) };
        }

        pub fn nValue(self: Self) ?Child {
            return self.sampler.nValue();
        }

        pub fn minValue(self: Self) Child {
            return self.sampler.minValue();
        }

        pub fn maxValue(self: Self) Child {
            return self.sampler.maxValue();
        }

        pub fn exponentValue(self: Self) Child {
            return self.sampler.exponentValue();
        }

        pub fn sample(self: Self, rng: Rng) VectorType {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) VectorType {
            if (self.sampler.isDegenerate()) return @splat(1);
            var out: VectorType = undefined;
            inline for (0..@typeInfo(VectorType).vector.len) |lane| out[lane] = self.sampler.sampleFrom(source);
            return out;
        }

        pub fn fill(self: Self, rng: Rng, dest: []VectorType) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []VectorType) void {
            if (self.sampler.isDegenerate()) {
                @memset(dest, @as(VectorType, @splat(1)));
                return;
            }
            for (dest) |*item| item.* = self.sampleFrom(source);
        }
    };
}

pub fn Zipf(comptime T: type) type {
    return struct {
        const Self = @This();

        exponent: T,
        t: T,
        q: T,

        pub fn init(n: T, exponent: T) Error!Self {
            comptime requireFloat(T);
            if (!(exponent >= 0) or std.math.isNan(exponent)) return error.InvalidParameter;
            if (!(n >= 1) or std.math.isNan(n)) return error.InvalidParameter;
            if (std.math.isInf(n) and exponent <= 1) return error.InvalidParameter;

            const q = if (exponent != 1) 1 / (1 - exponent) else 0;
            const t = if (std.math.isInf(exponent))
                1
            else if (exponent != 1)
                (std.math.pow(T, n, 1 - exponent) - exponent) * q
            else
                1 + @log(n);

            if (!(t > 0) or std.math.isNan(t)) return error.InvalidParameter;
            return .{ .exponent = exponent, .t = t, .q = q };
        }

        pub fn new(n: T, exponent: T) Error!Self {
            return Self.init(n, exponent);
        }

        pub fn nValue(self: Self) ?T {
            if (std.math.isInf(self.exponent)) return null;
            if (self.exponent == 1) return @exp(self.t - 1);
            return std.math.pow(T, self.t * (1 - self.exponent) + self.exponent, self.q);
        }

        pub fn minValue(_: Self) T {
            return 1;
        }

        pub fn maxValue(self: Self) T {
            if (std.math.isInf(self.exponent)) return 1;
            return self.nValue().?;
        }

        pub fn exponentValue(self: Self) T {
            return self.exponent;
        }

        pub fn sample(self: Self, rng: Rng) T {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) T {
            if (self.isDegenerate()) return 1;

            while (true) {
                const inv_b = self.invCdf(Rng.floatFrom(source, T));
                const x = @floor(inv_b + 1);
                var ratio = std.math.pow(T, x, -self.exponent);
                if (x > 1) ratio *= std.math.pow(T, inv_b, self.exponent);

                if (Rng.floatFrom(source, T) < ratio) return x;
            }
        }

        pub fn fill(self: Self, rng: Rng, dest: []T) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []T) void {
            if (self.isDegenerate()) {
                @memset(dest, 1);
                return;
            }
            for (dest) |*item| item.* = self.sampleFrom(source);
        }

        fn isDegenerate(self: Self) bool {
            return self.maxValue() == 1;
        }

        fn invCdf(self: Self, p: T) T {
            const pt = p * self.t;
            if (pt <= 1) return pt;
            if (self.exponent != 1) return std.math.pow(T, pt * (1 - self.exponent) + self.exponent, self.q);
            return @exp(pt - 1);
        }
    };
}

pub fn zeta(rng: Rng, comptime T: type, exponent: T) T {
    return zetaFrom(rng, T, exponent);
}

pub fn zetaChecked(rng: Rng, comptime T: type, exponent: T) Error!T {
    return zetaCheckedFrom(rng, T, exponent);
}

pub fn zetaCheckedFrom(source: anytype, comptime T: type, exponent: T) Error!T {
    const dist = try Zeta(T).init(exponent);
    return dist.sampleFrom(source);
}

pub fn zetaFrom(source: anytype, comptime T: type, exponent: T) T {
    comptime requireFloat(T);
    std.debug.assert(exponent > 1);

    const sampler = Zeta(T).init(exponent) catch unreachable;
    return sampler.sampleFrom(source);
}

pub fn fillZeta(rng: Rng, comptime T: type, dest: []T, exponent: T) void {
    fillZetaFrom(rng, T, dest, exponent);
}

pub fn fillZetaFrom(source: anytype, comptime T: type, dest: []T, exponent: T) void {
    const sampler = Zeta(T).init(exponent) catch unreachable;
    sampler.fillFrom(source, dest);
}

pub fn fillZetaChecked(rng: Rng, comptime T: type, dest: []T, exponent: T) Error!void {
    return fillZetaCheckedFrom(rng, T, dest, exponent);
}

pub fn fillZetaCheckedFrom(source: anytype, comptime T: type, dest: []T, exponent: T) Error!void {
    if (dest.len == 0) return;
    const sampler = try Zeta(T).init(exponent);
    sampler.fillFrom(source, dest);
}

pub fn vectorZeta(rng: Rng, comptime VectorType: type, exponent: vectorChild(VectorType)) VectorType {
    return vectorZetaFrom(rng, VectorType, exponent);
}

pub fn vectorZetaFrom(source: anytype, comptime VectorType: type, exponent: vectorChild(VectorType)) VectorType {
    const sampler = VectorZeta(VectorType).init(exponent) catch unreachable;
    return sampler.sampleFrom(source);
}

pub fn vectorZetaChecked(rng: Rng, comptime VectorType: type, exponent: vectorChild(VectorType)) Error!VectorType {
    return vectorZetaCheckedFrom(rng, VectorType, exponent);
}

pub fn vectorZetaCheckedFrom(source: anytype, comptime VectorType: type, exponent: vectorChild(VectorType)) Error!VectorType {
    const sampler = try VectorZeta(VectorType).init(exponent);
    return sampler.sampleFrom(source);
}

pub fn fillVectorZeta(rng: Rng, comptime VectorType: type, dest: []VectorType, exponent: vectorChild(VectorType)) void {
    fillVectorZetaFrom(rng, VectorType, dest, exponent);
}

pub fn fillVectorZetaFrom(source: anytype, comptime VectorType: type, dest: []VectorType, exponent: vectorChild(VectorType)) void {
    const sampler = VectorZeta(VectorType).init(exponent) catch unreachable;
    sampler.fillFrom(source, dest);
}

pub fn fillVectorZetaChecked(rng: Rng, comptime VectorType: type, dest: []VectorType, exponent: vectorChild(VectorType)) Error!void {
    return fillVectorZetaCheckedFrom(rng, VectorType, dest, exponent);
}

pub fn fillVectorZetaCheckedFrom(source: anytype, comptime VectorType: type, dest: []VectorType, exponent: vectorChild(VectorType)) Error!void {
    if (dest.len == 0) return;
    const sampler = try VectorZeta(VectorType).init(exponent);
    sampler.fillFrom(source, dest);
}

pub fn VectorZeta(comptime VectorType: type) type {
    const Child = vectorChild(VectorType);
    requireFloat(Child);

    return struct {
        const Self = @This();

        sampler: Zeta(Child),

        pub fn init(exponent: Child) Error!Self {
            return .{ .sampler = try Zeta(Child).init(exponent) };
        }

        pub fn exponentValue(self: Self) Child {
            return self.sampler.exponentValue();
        }

        pub fn minValue(self: Self) Child {
            return self.sampler.minValue();
        }

        pub fn maxValue(self: Self) ?Child {
            return self.sampler.maxValue();
        }

        pub fn sample(self: Self, rng: Rng) VectorType {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) VectorType {
            if (self.isDegenerate()) return @splat(1);
            var out: VectorType = undefined;
            inline for (0..@typeInfo(VectorType).vector.len) |lane| out[lane] = self.sampler.sampleFrom(source);
            return out;
        }

        pub fn fill(self: Self, rng: Rng, dest: []VectorType) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []VectorType) void {
            if (self.isDegenerate()) {
                @memset(dest, @as(VectorType, @splat(1)));
                return;
            }
            for (dest) |*item| item.* = self.sampleFrom(source);
        }

        fn isDegenerate(self: Self) bool {
            return std.math.isInf(self.exponentValue());
        }
    };
}

pub fn Zeta(comptime T: type) type {
    return struct {
        const Self = @This();

        exponent_minus_one: T,
        b: T,

        pub fn init(exponent: T) Error!Self {
            comptime requireFloat(T);
            if (!(exponent > 1) or std.math.isNan(exponent)) return error.InvalidParameter;
            const exponent_minus_one = exponent - 1;
            return .{
                .exponent_minus_one = exponent_minus_one,
                .b = std.math.pow(T, 2, exponent_minus_one),
            };
        }

        pub fn new(exponent: T) Error!Self {
            return Self.init(exponent);
        }

        pub fn exponentValue(self: Self) T {
            return self.exponent_minus_one + 1;
        }

        pub fn minValue(_: Self) T {
            return 1;
        }

        pub fn maxValue(self: Self) ?T {
            return if (self.isDegenerate()) 1 else null;
        }

        pub fn sample(self: Self, rng: Rng) T {
            return self.sampleFrom(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) T {
            if (self.isDegenerate()) return 1;
            while (true) {
                const u = Rng.floatOpenClosedFrom(source, T);
                const x = @floor(std.math.pow(T, u, -1 / self.exponent_minus_one));
                if (std.math.isInf(x)) return x;

                const t = std.math.pow(T, 1 + 1 / x, self.exponent_minus_one);
                const v = Rng.floatFrom(source, T);
                if (v * x * (t - 1) * self.b <= t * (self.b - 1)) return x;
            }
        }

        pub fn fill(self: Self, rng: Rng, dest: []T) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []T) void {
            if (self.isDegenerate()) {
                @memset(dest, 1);
                return;
            }
            for (dest) |*item| item.* = self.sampleFrom(source);
        }

        fn isDegenerate(self: Self) bool {
            return std.math.isInf(self.exponentValue());
        }
    };
}

pub fn Dirichlet(comptime T: type) type {
    return struct {
        const Self = @This();

        alpha: []const T,

        pub fn init(alpha: []const T) Error!Self {
            comptime requireFloat(T);
            if (alpha.len == 0) return error.EmptyRange;
            var infinite_count: usize = 0;
            for (alpha) |a| {
                if (!(a > 0)) return error.InvalidParameter;
                if (a == std.math.inf(T)) {
                    infinite_count += 1;
                } else if (!std.math.isFinite(a)) return error.InvalidParameter;
            }
            if (infinite_count > 1) return error.InvalidParameter;
            return .{ .alpha = alpha };
        }

        pub fn new(alpha: []const T) Error!Self {
            return Self.init(alpha);
        }

        pub fn alphaValues(self: Self) []const T {
            return self.alpha;
        }

        pub fn alphaAt(self: Self, index: usize) Error!T {
            if (index >= self.alpha.len) return error.InvalidParameter;
            return self.alpha[index];
        }

        pub fn meanAt(self: Self, index: usize) Error!T {
            _ = try self.alphaAt(index);
            if (self.degenerateIndex()) |degenerate| return if (index == degenerate) 1 else 0;
            return self.alpha[index] / self.totalAlphaValue();
        }

        pub fn means(self: Self, allocator: std.mem.Allocator) ![]T {
            const out = try allocator.alloc(T, self.alpha.len);
            errdefer allocator.free(out);
            try self.meansInto(out);
            return out;
        }

        pub fn meansInto(self: Self, out: []T) Error!void {
            if (out.len != self.alpha.len) return error.InvalidLength;
            if (self.degenerateIndex()) |degenerate| {
                @memset(out, 0);
                out[degenerate] = 1;
                return;
            }
            const alpha_0 = self.totalAlphaValue();
            for (self.alpha, out) |alpha_i, *slot| slot.* = alpha_i / alpha_0;
        }

        pub fn varianceAt(self: Self, index: usize) Error!T {
            const alpha_i = try self.alphaAt(index);
            if (self.isDegenerate()) return 0;
            const alpha_0 = self.totalAlphaValue();
            return alpha_i * (alpha_0 - alpha_i) / (alpha_0 * alpha_0 * (alpha_0 + 1));
        }

        pub fn variances(self: Self, allocator: std.mem.Allocator) ![]T {
            const out = try allocator.alloc(T, self.alpha.len);
            errdefer allocator.free(out);
            try self.variancesInto(out);
            return out;
        }

        pub fn variancesInto(self: Self, out: []T) Error!void {
            if (out.len != self.alpha.len) return error.InvalidLength;
            if (self.isDegenerate()) {
                @memset(out, 0);
                return;
            }
            const alpha_0 = self.totalAlphaValue();
            const denominator = alpha_0 * alpha_0 * (alpha_0 + 1);
            for (self.alpha, out) |alpha_i, *slot| slot.* = alpha_i * (alpha_0 - alpha_i) / denominator;
        }

        pub fn covarianceAt(self: Self, i: usize, j: usize) Error!T {
            if (i == j) return self.varianceAt(i);
            const alpha_i = try self.alphaAt(i);
            const alpha_j = try self.alphaAt(j);
            _ = alpha_i;
            _ = alpha_j;
            if (self.isDegenerate()) return 0;
            const alpha_0 = self.totalAlphaValue();
            return -(self.alpha[i] * self.alpha[j]) / (alpha_0 * alpha_0 * (alpha_0 + 1));
        }

        pub fn covariances(self: Self, allocator: std.mem.Allocator) ![]T {
            const count = std.math.mul(usize, self.alpha.len, self.alpha.len) catch return error.OutOfMemory;
            const out = try allocator.alloc(T, count);
            errdefer allocator.free(out);
            try self.covariancesInto(out);
            return out;
        }

        pub fn covariancesInto(self: Self, out: []T) Error!void {
            const count = std.math.mul(usize, self.alpha.len, self.alpha.len) catch return error.InvalidLength;
            if (out.len != count) return error.InvalidLength;
            if (self.isDegenerate()) {
                @memset(out, 0);
                return;
            }
            const alpha_0 = self.totalAlphaValue();
            const denominator = alpha_0 * alpha_0 * (alpha_0 + 1);
            var row: usize = 0;
            while (row < self.alpha.len) : (row += 1) {
                var col: usize = 0;
                while (col < self.alpha.len) : (col += 1) {
                    const alpha_i = self.alpha[row];
                    const alpha_j = self.alpha[col];
                    out[row * self.alpha.len + col] = if (row == col)
                        alpha_i * (alpha_0 - alpha_i) / denominator
                    else
                        -(alpha_i * alpha_j) / denominator;
                }
            }
        }

        pub fn dimensionValue(self: Self) usize {
            return self.alpha.len;
        }

        pub fn totalAlphaValue(self: Self) T {
            var total: T = 0;
            for (self.alpha) |value| total += value;
            return total;
        }

        pub fn sample(self: Self, allocator: std.mem.Allocator, rng: Rng) ![]T {
            return self.sampleFrom(allocator, rng);
        }

        pub fn sampleFrom(self: Self, allocator: std.mem.Allocator, source: anytype) ![]T {
            const out = try allocator.alloc(T, self.alpha.len);
            errdefer allocator.free(out);
            self.sampleIntoFrom(source, out);
            return out;
        }

        pub fn sampleInto(self: Self, rng: Rng, out: []T) void {
            self.sampleIntoFrom(rng, out);
        }

        pub fn sampleIntoChecked(self: Self, rng: Rng, out: []T) Error!void {
            try self.sampleIntoCheckedFrom(rng, out);
        }

        pub fn sampleIntoCheckedFrom(self: Self, source: anytype, out: []T) Error!void {
            if (out.len != self.alpha.len) return error.InvalidLength;
            self.sampleIntoFrom(source, out);
        }

        pub fn sampleManyInto(self: Self, rng: Rng, out: []T) void {
            self.sampleManyIntoFrom(rng, out);
        }

        pub fn sampleManyIntoChecked(self: Self, rng: Rng, out: []T) Error!void {
            try self.sampleManyIntoCheckedFrom(rng, out);
        }

        pub fn sampleManyIntoCheckedFrom(self: Self, source: anytype, out: []T) Error!void {
            if (out.len % self.alpha.len != 0) return error.InvalidLength;
            self.sampleManyIntoFrom(source, out);
        }

        pub fn sampleManyIntoFrom(self: Self, source: anytype, out: []T) void {
            std.debug.assert(out.len % self.alpha.len == 0);
            if (self.alpha.len == 1) {
                @memset(out, 1);
                return;
            }
            if (self.degenerateIndex()) |degenerate| {
                @memset(out, 0);
                var offset: usize = degenerate;
                while (offset < out.len) : (offset += self.alpha.len) out[offset] = 1;
                return;
            }
            var offset: usize = 0;
            while (offset < out.len) : (offset += self.alpha.len) {
                self.sampleIntoFrom(source, out[offset..][0..self.alpha.len]);
            }
        }

        pub fn sampleIntoFrom(self: Self, source: anytype, out: []T) void {
            std.debug.assert(out.len == self.alpha.len);
            if (self.alpha.len == 1) {
                out[0] = 1;
                return;
            }
            if (self.degenerateIndex()) |degenerate| {
                @memset(out, 0);
                out[degenerate] = 1;
                return;
            }
            var total: T = 0;
            for (self.alpha, out) |a, *slot| {
                const value = gammaFrom(source, T, a, 1);
                slot.* = value;
                total += value;
            }

            for (out) |*value| value.* /= total;
        }

        fn isDegenerate(self: Self) bool {
            return self.degenerateIndex() != null;
        }

        fn degenerateIndex(self: Self) ?usize {
            for (self.alpha, 0..) |value, index| {
                if (value == std.math.inf(T)) return index;
            }
            return null;
        }
    };
}

pub fn aliasTable(comptime T: type) type {
    return AliasTable(T);
}

pub fn WeightedIndex(comptime Weight: type) type {
    return AliasTable(Weight);
}

pub fn AliasTable(comptime Weight: type) type {
    return struct {
        const Self = @This();

        prob: []f64,
        prob_threshold: []u64,
        alias: []usize,
        weight_values: []f64,
        total: f64,
        positive_count: usize = 0,
        constant_index: ?usize = null,
        allocator: std.mem.Allocator,

        pub const Update = struct {
            index: usize,
            weight: Weight,
        };

        pub const WeightIterator = struct {
            const Iterator = @This();

            table: Self,
            index: usize = 0,

            pub fn next(self: *Iterator) ?f64 {
                const value = self.table.weight(self.index) orelse return null;
                self.index += 1;
                return value;
            }

            pub fn remaining(self: Iterator) usize {
                return self.table.len() - self.index;
            }

            pub fn len(self: Iterator) usize {
                return self.remaining();
            }

            pub fn sizeHint(self: Iterator) struct { lower: usize, upper: ?usize } {
                const length = self.remaining();
                return .{ .lower = length, .upper = length };
            }

            pub fn fill(self: *Iterator, dest: []f64) usize {
                const count = @min(dest.len, self.remaining());
                if (count == 0) return 0;
                @memcpy(dest[0..count], self.table.weight_values[self.index..][0..count]);
                self.index += count;
                return count;
            }
        };

        pub const ProbabilityIterator = struct {
            const Iterator = @This();

            table: Self,
            index: usize = 0,

            pub fn next(self: *Iterator) ?f64 {
                const value = self.table.probability(self.index) orelse return null;
                self.index += 1;
                return value;
            }

            pub fn remaining(self: Iterator) usize {
                return self.table.len() - self.index;
            }

            pub fn len(self: Iterator) usize {
                return self.remaining();
            }

            pub fn sizeHint(self: Iterator) struct { lower: usize, upper: ?usize } {
                const length = self.remaining();
                return .{ .lower = length, .upper = length };
            }

            pub fn fill(self: *Iterator, dest: []f64) usize {
                const count = @min(dest.len, self.remaining());
                if (count == 0) return 0;
                for (self.table.weight_values[self.index..][0..count], dest[0..count]) |weight_value, *slot| {
                    slot.* = weight_value / self.table.total;
                }
                self.index += count;
                return count;
            }
        };

        pub fn init(allocator: std.mem.Allocator, input_weights: []const Weight) !Self {
            return initFromWeights(allocator, input_weights);
        }

        pub fn new(allocator: std.mem.Allocator, input_weights: []const Weight) !Self {
            return init(allocator, input_weights);
        }

        fn initFromWeights(allocator: std.mem.Allocator, input_weights: anytype) !Self {
            if (input_weights.len == 0) return error.InvalidInput;

            const prob = try allocator.alloc(f64, input_weights.len);
            errdefer allocator.free(prob);
            const prob_threshold = try allocator.alloc(u64, input_weights.len);
            errdefer allocator.free(prob_threshold);
            const alias = try allocator.alloc(usize, input_weights.len);
            errdefer allocator.free(alias);
            const weight_values = try allocator.alloc(f64, input_weights.len);
            errdefer allocator.free(weight_values);

            var scaled = try allocator.alloc(f64, input_weights.len);
            defer allocator.free(scaled);
            var small = try std.ArrayList(usize).initCapacity(allocator, input_weights.len);
            defer small.deinit(allocator);
            var large = try std.ArrayList(usize).initCapacity(allocator, input_weights.len);
            defer large.deinit(allocator);

            var total: f64 = 0;
            var positive_index: ?usize = null;
            var positive_count: usize = 0;
            for (input_weights, 0..) |input_weight, index| {
                const value = try weightToF64(input_weight);
                weight_values[index] = value;
                total += value;
                if (!std.math.isFinite(total)) return error.Overflow;
                if (value > 0) {
                    positive_index = index;
                    positive_count += 1;
                }
            }
            if (total == 0) return error.InsufficientNonZero;

            for (weight_values, 0..) |value, i| {
                scaled[i] = value * @as(f64, @floatFromInt(input_weights.len)) / total;
                if (scaled[i] < 1) {
                    try small.append(allocator, i);
                } else {
                    try large.append(allocator, i);
                }
            }

            while (small.pop()) |less| {
                if (large.pop()) |more| {
                    prob[less] = scaled[less];
                    alias[less] = more;
                    scaled[more] = (scaled[more] + scaled[less]) - 1;
                    if (scaled[more] < 1) {
                        try small.append(allocator, more);
                    } else {
                        try large.append(allocator, more);
                    }
                } else {
                    prob[less] = 1;
                    alias[less] = less;
                }
            }

            while (large.pop()) |more| {
                prob[more] = 1;
                alias[more] = more;
            }

            for (prob, prob_threshold) |probability_value, *threshold| {
                threshold.* = aliasProbabilityThreshold(probability_value);
            }

            return .{
                .prob = prob,
                .prob_threshold = prob_threshold,
                .alias = alias,
                .weight_values = weight_values,
                .total = total,
                .positive_count = positive_count,
                .constant_index = if (positive_count == 1) positive_index else null,
                .allocator = allocator,
            };
        }

        pub fn initByIndex(
            allocator: std.mem.Allocator,
            length: usize,
            comptime weightFn: fn (usize) Weight,
        ) !Self {
            const input_weights = try weightsFromIndices(allocator, length, weightFn);
            defer allocator.free(input_weights);
            return Self.init(allocator, input_weights);
        }

        pub fn initBy(
            allocator: std.mem.Allocator,
            comptime T: type,
            items: []const T,
            comptime weightFn: fn (*const T) Weight,
        ) !Self {
            const input_weights = try weightsFromItems(allocator, T, items, weightFn);
            defer allocator.free(input_weights);
            return Self.init(allocator, input_weights);
        }

        pub fn deinit(self: *Self) void {
            self.allocator.free(self.prob);
            self.allocator.free(self.prob_threshold);
            self.allocator.free(self.alias);
            self.allocator.free(self.weight_values);
            self.* = undefined;
        }

        pub fn update(self: *Self, input_weights: []const Weight) !void {
            if (input_weights.len != self.prob.len) return error.InvalidParameter;

            const next = try Self.init(self.allocator, input_weights);
            self.allocator.free(self.prob);
            self.allocator.free(self.prob_threshold);
            self.allocator.free(self.alias);
            self.allocator.free(self.weight_values);
            self.prob = next.prob;
            self.prob_threshold = next.prob_threshold;
            self.alias = next.alias;
            self.weight_values = next.weight_values;
            self.total = next.total;
            self.positive_count = next.positive_count;
            self.constant_index = next.constant_index;
        }

        pub fn updateAt(self: *Self, index: usize, input_weight: Weight) !void {
            if (index >= self.prob.len) return error.InvalidParameter;
            const value = try weightToF64(input_weight);
            const next_total = self.total - self.weight_values[index] + value;
            try validateStaticWeightTotal(next_total);
            const input_weights = try self.allocator.dupe(f64, self.weight_values);
            defer self.allocator.free(input_weights);
            input_weights[index] = value;

            const next = try initFromWeights(self.allocator, input_weights);
            self.allocator.free(self.prob);
            self.allocator.free(self.prob_threshold);
            self.allocator.free(self.alias);
            self.allocator.free(self.weight_values);
            self.prob = next.prob;
            self.prob_threshold = next.prob_threshold;
            self.alias = next.alias;
            self.weight_values = next.weight_values;
            self.total = next.total;
            self.positive_count = next.positive_count;
            self.constant_index = next.constant_index;
        }

        pub fn updateMany(self: *Self, updates: []const Update) !void {
            if (updates.len == 0) return;

            var next_total = self.total;
            var previous_index: ?usize = null;
            for (updates) |item| {
                if (item.index >= self.prob.len) return error.InvalidParameter;
                if (previous_index) |previous| {
                    if (previous >= item.index) return error.InvalidParameter;
                }
                const value = try weightToF64(item.weight);
                next_total = next_total - self.weight_values[item.index] + value;
                previous_index = item.index;
            }
            try validateStaticWeightTotal(next_total);

            const input_weights = try self.allocator.dupe(f64, self.weight_values);
            defer self.allocator.free(input_weights);
            for (updates) |item| input_weights[item.index] = try weightToF64(item.weight);

            const next = try initFromWeights(self.allocator, input_weights);
            self.allocator.free(self.prob);
            self.allocator.free(self.prob_threshold);
            self.allocator.free(self.alias);
            self.allocator.free(self.weight_values);
            self.prob = next.prob;
            self.prob_threshold = next.prob_threshold;
            self.alias = next.alias;
            self.weight_values = next.weight_values;
            self.total = next.total;
            self.positive_count = next.positive_count;
            self.constant_index = next.constant_index;
        }

        pub fn updateWeights(self: *Self, updates: []const Update) !void {
            try self.updateMany(updates);
        }

        pub fn updateByIndex(self: *Self, comptime weightFn: fn (usize) Weight) !void {
            const input_weights = try weightsFromIndices(self.allocator, self.prob.len, weightFn);
            defer self.allocator.free(input_weights);
            try self.update(input_weights);
        }

        pub fn updateBy(
            self: *Self,
            comptime T: type,
            items: []const T,
            comptime weightFn: fn (*const T) Weight,
        ) !void {
            if (items.len != self.prob.len) return error.InvalidParameter;
            const input_weights = try weightsFromItems(self.allocator, T, items, weightFn);
            defer self.allocator.free(input_weights);
            try self.update(input_weights);
        }

        pub fn len(self: Self) usize {
            return self.prob.len;
        }

        pub fn numChoices(self: Self) usize {
            return self.prob.len;
        }

        pub fn isEmpty(self: Self) bool {
            return self.len() == 0;
        }

        pub fn totalWeight(self: Self) f64 {
            return self.total;
        }

        pub fn positiveCount(self: Self) usize {
            return self.positive_count;
        }

        pub fn weights(self: Self, allocator: std.mem.Allocator) ![]f64 {
            const out = try allocator.alloc(f64, self.prob.len);
            errdefer allocator.free(out);
            try self.weightsInto(out);
            return out;
        }

        pub fn weightsInto(self: Self, out: []f64) Error!void {
            if (out.len != self.prob.len) return error.InvalidLength;
            @memcpy(out, self.weight_values);
        }

        pub fn probabilities(self: Self, allocator: std.mem.Allocator) ![]f64 {
            const out = try allocator.alloc(f64, self.prob.len);
            errdefer allocator.free(out);
            try self.probabilitiesInto(out);
            return out;
        }

        pub fn probabilitiesInto(self: Self, out: []f64) Error!void {
            try self.weightsInto(out);
            for (out) |*value| value.* /= self.total;
        }

        pub fn weightAt(self: Self, index: usize) Error!f64 {
            if (index >= self.prob.len) return error.InvalidParameter;
            return self.weight_values[index];
        }

        pub fn weight(self: Self, index: usize) ?f64 {
            return self.weightAt(index) catch null;
        }

        pub fn weightIter(self: Self) WeightIterator {
            return .{ .table = self };
        }

        pub fn probabilityAt(self: Self, index: usize) Error!f64 {
            return try self.weightAt(index) / self.total;
        }

        pub fn probability(self: Self, index: usize) ?f64 {
            return self.probabilityAt(index) catch null;
        }

        pub fn probabilityIter(self: Self) ProbabilityIterator {
            return .{ .table = self };
        }

        pub fn constantIndex(self: Self) ?usize {
            return self.constant_index;
        }

        pub fn sample(self: Self, rng: Rng) usize {
            return self.sampleFrom(rng);
        }

        pub fn sampleIndex(self: Self, rng: Rng) usize {
            return self.sample(rng);
        }

        pub fn sampleChecked(self: Self, rng: Rng) Error!usize {
            return self.sampleCheckedFrom(rng);
        }

        pub fn sampleIndexChecked(self: Self, rng: Rng) Error!usize {
            return self.sampleChecked(rng);
        }

        pub fn sampleU32(self: Self, rng: Rng) u32 {
            return self.sampleU32Checked(rng) catch unreachable;
        }

        pub fn sampleIndexU32(self: Self, rng: Rng) u32 {
            return self.sampleU32(rng);
        }

        pub fn sampleU32Checked(self: Self, rng: Rng) Error!u32 {
            return self.sampleU32CheckedFrom(rng);
        }

        pub fn sampleIndexU32Checked(self: Self, rng: Rng) Error!u32 {
            return self.sampleU32Checked(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) usize {
            if (self.constant_index) |index| return index;
            if (aliasTableCanSampleWithOneWord(self.prob.len)) {
                const raw = Rng.nextFrom(source);
                const column = @as(usize, @intCast(raw & @as(u64, @intCast(self.prob.len - 1))));
                return if ((raw >> 11) < self.prob_threshold[column]) column else self.alias[column];
            }
            const column = Rng.uintLessThanFrom(source, usize, self.prob.len);
            return if (Rng.floatFrom(source, f64) < self.prob[column]) column else self.alias[column];
        }

        pub fn sampleIndexFrom(self: Self, source: anytype) usize {
            return self.sampleFrom(source);
        }

        pub fn sampleCheckedFrom(self: Self, source: anytype) Error!usize {
            return self.sampleFrom(source);
        }

        pub fn sampleIndexCheckedFrom(self: Self, source: anytype) Error!usize {
            return self.sampleCheckedFrom(source);
        }

        pub fn sampleU32From(self: Self, source: anytype) u32 {
            return self.sampleU32CheckedFrom(source) catch unreachable;
        }

        pub fn sampleIndexU32From(self: Self, source: anytype) u32 {
            return self.sampleU32From(source);
        }

        pub fn sampleU32CheckedFrom(self: Self, source: anytype) Error!u32 {
            if (self.prob.len > std.math.maxInt(u32)) return error.InvalidParameter;
            return @intCast(self.sampleFrom(source));
        }

        pub fn sampleIndexU32CheckedFrom(self: Self, source: anytype) Error!u32 {
            return self.sampleU32CheckedFrom(source);
        }

        pub fn fill(self: Self, rng: Rng, dest: []usize) void {
            self.fillFrom(rng, dest);
        }

        pub fn fillIndices(self: Self, rng: Rng, dest: []usize) void {
            self.fill(rng, dest);
        }

        pub fn fillChecked(self: Self, rng: Rng, dest: []usize) Error!void {
            try self.fillCheckedFrom(rng, dest);
        }

        pub fn fillIndicesChecked(self: Self, rng: Rng, dest: []usize) Error!void {
            try self.fillChecked(rng, dest);
        }

        pub fn fillU32(self: Self, rng: Rng, dest: []u32) void {
            self.fillU32Checked(rng, dest) catch unreachable;
        }

        pub fn fillIndicesU32(self: Self, rng: Rng, dest: []u32) void {
            self.fillU32(rng, dest);
        }

        pub fn fillU32Checked(self: Self, rng: Rng, dest: []u32) Error!void {
            try self.fillU32CheckedFrom(rng, dest);
        }

        pub fn fillIndicesU32Checked(self: Self, rng: Rng, dest: []u32) Error!void {
            try self.fillU32Checked(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []usize) void {
            if (dest.len == 0) return;
            if (self.constant_index) |index| {
                @memset(dest, index);
                return;
            }
            const table_len = self.prob.len;
            if (aliasTableCanSampleWithOneWord(table_len)) {
                for (dest) |*item| {
                    const raw = Rng.nextFrom(source);
                    const column = @as(usize, @intCast(raw & @as(u64, @intCast(table_len - 1))));
                    item.* = if ((raw >> 11) < self.prob_threshold[column]) column else self.alias[column];
                }
                return;
            }
            for (dest) |*item| {
                const column = Rng.uintLessThanFrom(source, usize, table_len);
                item.* = if (Rng.floatFrom(source, f64) < self.prob[column]) column else self.alias[column];
            }
        }

        pub fn fillIndicesFrom(self: Self, source: anytype, dest: []usize) void {
            self.fillFrom(source, dest);
        }

        pub fn fillCheckedFrom(self: Self, source: anytype, dest: []usize) Error!void {
            self.fillFrom(source, dest);
        }

        pub fn fillIndicesCheckedFrom(self: Self, source: anytype, dest: []usize) Error!void {
            try self.fillCheckedFrom(source, dest);
        }

        pub fn fillU32From(self: Self, source: anytype, dest: []u32) void {
            self.fillU32CheckedFrom(source, dest) catch unreachable;
        }

        pub fn fillIndicesU32From(self: Self, source: anytype, dest: []u32) void {
            self.fillU32From(source, dest);
        }

        pub fn fillU32CheckedFrom(self: Self, source: anytype, dest: []u32) Error!void {
            if (dest.len == 0) return;
            if (self.prob.len > std.math.maxInt(u32)) return error.InvalidParameter;
            if (self.constant_index) |index| {
                @memset(dest, @intCast(index));
                return;
            }
            const table_len = self.prob.len;
            if (aliasTableCanSampleWithOneWord(table_len)) {
                for (dest) |*item| {
                    const raw = Rng.nextFrom(source);
                    const column = @as(usize, @intCast(raw & @as(u64, @intCast(table_len - 1))));
                    item.* = @intCast(if ((raw >> 11) < self.prob_threshold[column]) column else self.alias[column]);
                }
                return;
            }
            for (dest) |*item| {
                const column = Rng.uintLessThanFrom(source, usize, table_len);
                item.* = @intCast(if (Rng.floatFrom(source, f64) < self.prob[column]) column else self.alias[column]);
            }
        }

        pub fn fillIndicesU32CheckedFrom(self: Self, source: anytype, dest: []u32) Error!void {
            try self.fillU32CheckedFrom(source, dest);
        }

        pub fn indices(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]usize {
            return self.indicesFrom(allocator, rng, amount);
        }

        pub fn indicesFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]usize {
            const out = try allocator.alloc(usize, amount);
            errdefer allocator.free(out);
            self.fillFrom(source, out);
            return out;
        }

        pub fn indicesChecked(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]usize {
            return self.indicesCheckedFrom(allocator, rng, amount);
        }

        pub fn indicesCheckedFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]usize {
            return self.indicesFrom(allocator, source, amount);
        }

        pub fn indicesU32(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]u32 {
            return self.indicesU32From(allocator, rng, amount);
        }

        pub fn indicesU32From(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]u32 {
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            const out = try allocator.alloc(u32, amount);
            errdefer allocator.free(out);
            try self.fillU32CheckedFrom(source, out);
            return out;
        }

        pub fn indicesU32Checked(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]u32 {
            return self.indicesU32CheckedFrom(allocator, rng, amount);
        }

        pub fn indicesU32CheckedFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]u32 {
            return self.indicesU32From(allocator, source, amount);
        }

        pub fn indexArray(self: Self, rng: Rng, comptime N: usize) [N]usize {
            return self.indexArrayFrom(rng, N);
        }

        pub fn indexArrayFrom(self: Self, source: anytype, comptime N: usize) [N]usize {
            var out: [N]usize = undefined;
            self.fillFrom(source, &out);
            return out;
        }

        pub fn indexArrayChecked(self: Self, rng: Rng, comptime N: usize) Error![N]usize {
            return self.indexArrayCheckedFrom(rng, N);
        }

        pub fn indexArrayCheckedFrom(self: Self, source: anytype, comptime N: usize) Error![N]usize {
            return self.indexArrayFrom(source, N);
        }

        pub fn indexArrayU32(self: Self, rng: Rng, comptime N: usize) [N]u32 {
            return self.indexArrayU32Checked(rng, N) catch unreachable;
        }

        pub fn indexArrayU32Checked(self: Self, rng: Rng, comptime N: usize) Error![N]u32 {
            return self.indexArrayU32CheckedFrom(rng, N);
        }

        pub fn indexArrayU32From(self: Self, source: anytype, comptime N: usize) [N]u32 {
            return self.indexArrayU32CheckedFrom(source, N) catch unreachable;
        }

        pub fn indexArrayU32CheckedFrom(self: Self, source: anytype, comptime N: usize) Error![N]u32 {
            var out: [N]u32 = undefined;
            try self.fillU32CheckedFrom(source, &out);
            return out;
        }

        pub fn iter(self: Self, rng: Rng) Rng.SampleIterator(Self, usize) {
            return rng.sampleIter(usize, self);
        }

        pub fn iterFrom(self: Self, source: anytype) Rng.SampleIteratorFrom(@TypeOf(source), Self, usize) {
            return Rng.sampleIterFrom(source, usize, self);
        }

        pub fn iterChecked(self: Self, rng: Rng) Error!Rng.SampleIterator(Self, usize) {
            return self.iter(rng);
        }

        pub fn iterCheckedFrom(self: Self, source: anytype) Error!Rng.SampleIteratorFrom(@TypeOf(source), Self, usize) {
            return self.iterFrom(source);
        }

        pub fn iterU32(self: Self, rng: Rng) U32IndexIterator(Rng) {
            return .{ .source = rng, .table = self };
        }

        pub fn iterU32From(self: Self, source: anytype) U32IndexIterator(@TypeOf(source)) {
            return .{ .source = source, .table = self };
        }

        pub fn iterU32Checked(self: Self, rng: Rng) Error!U32IndexIterator(Rng) {
            return self.iterU32CheckedFrom(rng);
        }

        pub fn iterU32CheckedFrom(self: Self, source: anytype) Error!U32IndexIterator(@TypeOf(source)) {
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            return self.iterU32From(source);
        }

        pub fn U32IndexIterator(comptime Source: type) type {
            return struct {
                const Iterator = @This();

                source: Source,
                table: Self,

                pub fn next(self: *Iterator) ?u32 {
                    return self.nextValue();
                }

                pub fn nextValue(self: *Iterator) u32 {
                    return self.table.sampleU32CheckedFrom(self.source) catch unreachable;
                }

                pub fn fill(self: *Iterator, dest: []u32) void {
                    self.table.fillU32From(self.source, dest);
                }
            };
        }

        fn weightsFromIndices(
            allocator: std.mem.Allocator,
            length: usize,
            comptime weightFn: fn (usize) Weight,
        ) ![]Weight {
            const out = try allocator.alloc(Weight, length);
            errdefer allocator.free(out);
            for (out, 0..) |*slot, index| slot.* = weightFn(index);
            return out;
        }

        fn weightsFromItems(
            allocator: std.mem.Allocator,
            comptime T: type,
            items: []const T,
            comptime weightFn: fn (*const T) Weight,
        ) ![]Weight {
            const out = try allocator.alloc(Weight, items.len);
            errdefer allocator.free(out);
            for (items, out) |*item, *slot| slot.* = weightFn(item);
            return out;
        }

        fn weightToF64(input_weight: anytype) Error!f64 {
            const value: f64 = switch (@typeInfo(@TypeOf(input_weight))) {
                .int => @floatFromInt(input_weight),
                .float => @floatCast(input_weight),
                else => @compileError("alias weights must be numeric"),
            };
            if (!(value >= 0) or !std.math.isFinite(value)) return error.InvalidWeight;
            return value;
        }

        fn validateStaticWeightTotal(total_weight: f64) Error!void {
            if (!std.math.isFinite(total_weight)) return error.Overflow;
            if (total_weight == 0) return error.InsufficientNonZero;
            if (!(total_weight > 0)) return error.InvalidWeight;
        }
    };
}

fn aliasTableCanSampleWithOneWord(len: usize) bool {
    return len > 1 and len <= 2048 and std.math.isPowerOfTwo(len);
}

fn aliasProbabilityThreshold(probability: f64) u64 {
    const scale = 9007199254740992.0;
    if (probability <= 0) return 0;
    if (probability >= 1) return @as(u64, 1) << 53;
    return @intFromFloat(@ceil(probability * scale));
}

pub fn WeightedTree(comptime Weight: type) type {
    return struct {
        const Self = @This();

        subtotals: std.ArrayList(f64),
        positive_count: usize = 0,
        positive_index: ?usize = null,
        allocator: std.mem.Allocator,

        pub const Update = struct {
            index: usize,
            weight: Weight,
        };

        pub const WeightIterator = struct {
            const Iterator = @This();

            tree: Self,
            index: usize = 0,

            pub fn next(self: *Iterator) ?f64 {
                const value = self.tree.weight(self.index) orelse return null;
                self.index += 1;
                return value;
            }

            pub fn remaining(self: Iterator) usize {
                return self.tree.len() - self.index;
            }

            pub fn len(self: Iterator) usize {
                return self.remaining();
            }

            pub fn sizeHint(self: Iterator) struct { lower: usize, upper: ?usize } {
                const length = self.remaining();
                return .{ .lower = length, .upper = length };
            }

            pub fn fill(self: *Iterator, dest: []f64) usize {
                const count = @min(dest.len, self.remaining());
                for (dest[0..count], self.index..) |*slot, index| slot.* = self.tree.get(index) catch unreachable;
                self.index += count;
                return count;
            }
        };

        pub const ProbabilityIterator = struct {
            const Iterator = @This();

            tree: Self,
            index: usize = 0,

            pub fn next(self: *Iterator) ?f64 {
                const value = self.tree.probability(self.index) orelse return null;
                self.index += 1;
                return value;
            }

            pub fn remaining(self: Iterator) usize {
                return self.tree.len() - self.index;
            }

            pub fn len(self: Iterator) usize {
                return self.remaining();
            }

            pub fn sizeHint(self: Iterator) struct { lower: usize, upper: ?usize } {
                const length = self.remaining();
                return .{ .lower = length, .upper = length };
            }

            pub fn fill(self: *Iterator, dest: []f64) usize {
                const count = @min(dest.len, self.remaining());
                if (count == 0) return 0;
                const total = self.tree.totalWeight();
                if (!(total > 0) or !std.math.isFinite(total)) return 0;
                for (dest[0..count], self.index..) |*slot, index| slot.* = (self.tree.get(index) catch unreachable) / total;
                self.index += count;
                return count;
            }
        };

        pub fn init(allocator: std.mem.Allocator, input_weights: []const Weight) !Self {
            var subtotals = try std.ArrayList(f64).initCapacity(allocator, input_weights.len);
            errdefer subtotals.deinit(allocator);

            var positive_count: usize = 0;
            var positive_index: ?usize = null;
            for (input_weights, 0..) |input_weight, index| {
                const value = try weightToF64(input_weight);
                try subtotals.append(allocator, value);
                if (value > 0) {
                    positive_count += 1;
                    if (positive_index == null) positive_index = index;
                }
            }
            try buildSubtotals(subtotals.items);

            return .{
                .subtotals = subtotals,
                .positive_count = positive_count,
                .positive_index = positive_index,
                .allocator = allocator,
            };
        }

        pub fn initByIndex(
            allocator: std.mem.Allocator,
            length: usize,
            comptime weightFn: fn (usize) Weight,
        ) !Self {
            var subtotals = try std.ArrayList(f64).initCapacity(allocator, length);
            errdefer subtotals.deinit(allocator);

            var positive_count: usize = 0;
            var positive_index: ?usize = null;
            var index: usize = 0;
            while (index < length) : (index += 1) {
                const value = try weightToF64(weightFn(index));
                try subtotals.append(allocator, value);
                if (value > 0) {
                    positive_count += 1;
                    if (positive_index == null) positive_index = index;
                }
            }
            try buildSubtotals(subtotals.items);

            return .{
                .subtotals = subtotals,
                .positive_count = positive_count,
                .positive_index = positive_index,
                .allocator = allocator,
            };
        }

        pub fn initBy(
            allocator: std.mem.Allocator,
            comptime T: type,
            items: []const T,
            comptime weightFn: fn (*const T) Weight,
        ) !Self {
            var subtotals = try std.ArrayList(f64).initCapacity(allocator, items.len);
            errdefer subtotals.deinit(allocator);

            var positive_count: usize = 0;
            var positive_index: ?usize = null;
            for (items, 0..) |*item, index| {
                const value = try weightToF64(weightFn(item));
                try subtotals.append(allocator, value);
                if (value > 0) {
                    positive_count += 1;
                    if (positive_index == null) positive_index = index;
                }
            }
            try buildSubtotals(subtotals.items);

            return .{
                .subtotals = subtotals,
                .positive_count = positive_count,
                .positive_index = positive_index,
                .allocator = allocator,
            };
        }

        pub fn deinit(self: *Self) void {
            self.subtotals.deinit(self.allocator);
            self.* = undefined;
        }

        pub fn len(self: Self) usize {
            return self.subtotals.items.len;
        }

        pub fn numChoices(self: Self) usize {
            return self.subtotals.items.len;
        }

        pub fn isEmpty(self: Self) bool {
            return self.len() == 0;
        }

        pub fn totalWeight(self: Self) f64 {
            return if (self.subtotals.items.len == 0) 0 else self.subtotals.items[0];
        }

        pub fn isValid(self: Self) bool {
            const total = self.totalWeight();
            return total > 0 and std.math.isFinite(total);
        }

        pub fn positiveCount(self: Self) usize {
            return self.positive_count;
        }

        pub fn constantIndex(self: Self) ?usize {
            return if (self.positive_count == 1) self.positive_index else null;
        }

        pub fn get(self: Self, index: usize) Error!f64 {
            if (index >= self.subtotals.items.len) return error.InvalidParameter;
            return self.subtotals.items[index] - self.subtotal(2 * index + 1) - self.subtotal(2 * index + 2);
        }

        pub fn weightAt(self: Self, index: usize) Error!f64 {
            return self.get(index);
        }

        pub fn weight(self: Self, index: usize) ?f64 {
            return self.weightAt(index) catch null;
        }

        pub fn weightIter(self: Self) WeightIterator {
            return .{ .tree = self };
        }

        pub fn probabilityAt(self: Self, index: usize) Error!f64 {
            const current_weight = try self.get(index);
            const total = self.totalWeight();
            if (!(total > 0) or !std.math.isFinite(total)) return error.InvalidWeight;
            return current_weight / total;
        }

        pub fn probability(self: Self, index: usize) ?f64 {
            return self.probabilityAt(index) catch null;
        }

        pub fn probabilityIter(self: Self) ProbabilityIterator {
            return .{ .tree = self };
        }

        pub fn weights(self: Self, allocator: std.mem.Allocator) ![]f64 {
            const out = try allocator.alloc(f64, self.len());
            errdefer allocator.free(out);
            try self.weightsInto(out);
            return out;
        }

        pub fn weightsInto(self: Self, out: []f64) Error!void {
            if (out.len != self.len()) return error.InvalidLength;
            for (out, 0..) |*slot, index| slot.* = try self.get(index);
        }

        pub fn probabilities(self: Self, allocator: std.mem.Allocator) ![]f64 {
            const out = try allocator.alloc(f64, self.len());
            errdefer allocator.free(out);
            try self.probabilitiesInto(out);
            return out;
        }

        pub fn probabilitiesInto(self: Self, out: []f64) Error!void {
            if (out.len != self.len()) return error.InvalidLength;
            if (out.len == 0) return;
            const total = self.totalWeight();
            if (!(total > 0) or !std.math.isFinite(total)) return error.InvalidWeight;
            for (out, 0..) |*slot, index| slot.* = (try self.get(index)) / total;
        }

        pub fn push(self: *Self, input_weight: Weight) !void {
            const value = try weightToF64(input_weight);
            const next_total = self.totalWeight() + value;
            if (!std.math.isFinite(next_total)) return error.InvalidWeight;

            try self.subtotals.append(self.allocator, value);
            var index = self.subtotals.items.len - 1;
            while (index != 0) {
                index = (index - 1) / 2;
                self.subtotals.items[index] += value;
            }
            if (value > 0) {
                self.positive_count += 1;
                if (self.positive_index == null) self.positive_index = self.subtotals.items.len - 1;
            }
        }

        pub fn pop(self: *Self) ?f64 {
            if (self.subtotals.items.len == 0) return null;

            const index = self.subtotals.items.len - 1;
            const current_weight = self.get(index) catch unreachable;
            _ = self.subtotals.pop();

            var parent_index = index;
            while (parent_index != 0) {
                parent_index = (parent_index - 1) / 2;
                self.subtotals.items[parent_index] -= current_weight;
            }
            if (current_weight > 0) {
                self.positive_count -= 1;
                if (self.positive_count == 0) {
                    self.positive_index = null;
                } else if (self.positive_index == index) {
                    self.positive_index = self.findFirstPositive();
                }
            }
            return current_weight;
        }

        pub fn update(self: *Self, index: usize, input_weight: Weight) !void {
            if (index >= self.subtotals.items.len) return error.InvalidParameter;

            const value = try weightToF64(input_weight);
            const old = try self.get(index);
            const delta = value - old;
            const next_total = self.totalWeight() + delta;
            if (next_total < 0 or !std.math.isFinite(next_total)) return error.InvalidWeight;

            var cursor = index;
            while (true) {
                self.subtotals.items[cursor] += delta;
                if (cursor == 0) break;
                cursor = (cursor - 1) / 2;
            }
            self.updatePositiveState(index, old, value);
        }

        pub fn updateMany(self: *Self, updates: []const Update) !void {
            if (updates.len == 0) return;

            var previous_index: ?usize = null;
            var next_total = self.totalWeight();
            for (updates) |item| {
                if (item.index >= self.subtotals.items.len) return error.InvalidParameter;
                if (previous_index) |previous| {
                    if (previous >= item.index) return error.InvalidParameter;
                }
                const value = try weightToF64(item.weight);
                const old = try self.get(item.index);
                next_total += value - old;
                if (next_total < 0 or !std.math.isFinite(next_total)) return error.InvalidWeight;
                previous_index = item.index;
            }

            for (updates) |item| {
                const value = weightToF64(item.weight) catch unreachable;
                const old = self.get(item.index) catch unreachable;
                const delta = value - old;
                if (delta < 0) {
                    self.applyDelta(item.index, delta);
                    self.updatePositiveState(item.index, old, value);
                }
            }
            for (updates) |item| {
                const value = weightToF64(item.weight) catch unreachable;
                const old = self.get(item.index) catch unreachable;
                const delta = value - old;
                if (delta >= 0) {
                    self.applyDelta(item.index, delta);
                    self.updatePositiveState(item.index, old, value);
                }
            }
        }

        pub fn updateWeights(self: *Self, updates: []const Update) !void {
            try self.updateMany(updates);
        }

        pub fn updateAll(self: *Self, input_weights: []const Weight) !void {
            if (input_weights.len != self.len()) return error.InvalidParameter;
            const next = try Self.init(self.allocator, input_weights);
            self.subtotals.deinit(self.allocator);
            self.* = next;
        }

        pub fn updateAllByIndex(self: *Self, comptime weightFn: fn (usize) Weight) !void {
            const next = try Self.initByIndex(self.allocator, self.len(), weightFn);
            self.subtotals.deinit(self.allocator);
            self.* = next;
        }

        pub fn updateAllBy(
            self: *Self,
            comptime T: type,
            items: []const T,
            comptime weightFn: fn (*const T) Weight,
        ) !void {
            if (items.len != self.len()) return error.InvalidParameter;
            const next = try Self.initBy(self.allocator, T, items, weightFn);
            self.subtotals.deinit(self.allocator);
            self.* = next;
        }

        pub fn sample(self: Self, rng: Rng) usize {
            return self.sampleChecked(rng) catch unreachable;
        }

        pub fn sampleIndex(self: Self, rng: Rng) usize {
            return self.sample(rng);
        }

        pub fn sampleU32(self: Self, rng: Rng) u32 {
            return self.sampleU32Checked(rng) catch unreachable;
        }

        pub fn sampleIndexU32(self: Self, rng: Rng) u32 {
            return self.sampleU32(rng);
        }

        pub fn sampleChecked(self: Self, rng: Rng) Error!usize {
            return self.sampleCheckedFrom(rng);
        }

        pub fn sampleIndexChecked(self: Self, rng: Rng) Error!usize {
            return self.sampleChecked(rng);
        }

        pub fn sampleU32Checked(self: Self, rng: Rng) Error!u32 {
            return self.sampleU32CheckedFrom(rng);
        }

        pub fn sampleIndexU32Checked(self: Self, rng: Rng) Error!u32 {
            return self.sampleU32Checked(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) usize {
            return self.sampleCheckedFrom(source) catch unreachable;
        }

        pub fn sampleIndexFrom(self: Self, source: anytype) usize {
            return self.sampleFrom(source);
        }

        pub fn sampleU32From(self: Self, source: anytype) u32 {
            return self.sampleU32CheckedFrom(source) catch unreachable;
        }

        pub fn sampleIndexU32From(self: Self, source: anytype) u32 {
            return self.sampleU32From(source);
        }

        pub fn fill(self: Self, rng: Rng, dest: []usize) void {
            self.fillChecked(rng, dest) catch unreachable;
        }

        pub fn fillIndices(self: Self, rng: Rng, dest: []usize) void {
            self.fill(rng, dest);
        }

        pub fn fillU32(self: Self, rng: Rng, dest: []u32) void {
            self.fillU32Checked(rng, dest) catch unreachable;
        }

        pub fn fillIndicesU32(self: Self, rng: Rng, dest: []u32) void {
            self.fillU32(rng, dest);
        }

        pub fn fillChecked(self: Self, rng: Rng, dest: []usize) Error!void {
            try self.fillCheckedFrom(rng, dest);
        }

        pub fn fillIndicesChecked(self: Self, rng: Rng, dest: []usize) Error!void {
            try self.fillChecked(rng, dest);
        }

        pub fn fillU32Checked(self: Self, rng: Rng, dest: []u32) Error!void {
            try self.fillU32CheckedFrom(rng, dest);
        }

        pub fn fillIndicesU32Checked(self: Self, rng: Rng, dest: []u32) Error!void {
            try self.fillU32Checked(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []usize) void {
            self.fillCheckedFrom(source, dest) catch unreachable;
        }

        pub fn fillIndicesFrom(self: Self, source: anytype, dest: []usize) void {
            self.fillFrom(source, dest);
        }

        pub fn fillU32From(self: Self, source: anytype, dest: []u32) void {
            self.fillU32CheckedFrom(source, dest) catch unreachable;
        }

        pub fn fillIndicesU32From(self: Self, source: anytype, dest: []u32) void {
            self.fillU32From(source, dest);
        }

        pub fn indices(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]usize {
            return self.indicesFrom(allocator, rng, amount);
        }

        pub fn indicesFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]usize {
            const out = try allocator.alloc(usize, amount);
            errdefer allocator.free(out);
            self.fillFrom(source, out);
            return out;
        }

        pub fn indicesChecked(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]usize {
            return self.indicesCheckedFrom(allocator, rng, amount);
        }

        pub fn indicesCheckedFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]usize {
            if (amount != 0 and !self.isValid()) return error.InvalidWeight;
            const out = try allocator.alloc(usize, amount);
            errdefer allocator.free(out);
            try self.fillCheckedFrom(source, out);
            return out;
        }

        pub fn indicesU32(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]u32 {
            return self.indicesU32From(allocator, rng, amount);
        }

        pub fn indicesU32From(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]u32 {
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            const out = try allocator.alloc(u32, amount);
            errdefer allocator.free(out);
            self.fillU32From(source, out);
            return out;
        }

        pub fn indicesU32Checked(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]u32 {
            return self.indicesU32CheckedFrom(allocator, rng, amount);
        }

        pub fn indicesU32CheckedFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]u32 {
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            if (amount != 0 and !self.isValid()) return error.InvalidWeight;
            const out = try allocator.alloc(u32, amount);
            errdefer allocator.free(out);
            try self.fillU32CheckedFrom(source, out);
            return out;
        }

        pub fn indexArray(self: Self, rng: Rng, comptime N: usize) [N]usize {
            return self.indexArrayFrom(rng, N);
        }

        pub fn indexArrayFrom(self: Self, source: anytype, comptime N: usize) [N]usize {
            var out: [N]usize = undefined;
            self.fillFrom(source, &out);
            return out;
        }

        pub fn indexArrayChecked(self: Self, rng: Rng, comptime N: usize) Error![N]usize {
            return self.indexArrayCheckedFrom(rng, N);
        }

        pub fn indexArrayCheckedFrom(self: Self, source: anytype, comptime N: usize) Error![N]usize {
            var out: [N]usize = undefined;
            try self.fillCheckedFrom(source, &out);
            return out;
        }

        pub fn indexArrayU32(self: Self, rng: Rng, comptime N: usize) [N]u32 {
            return self.indexArrayU32Checked(rng, N) catch unreachable;
        }

        pub fn indexArrayU32Checked(self: Self, rng: Rng, comptime N: usize) Error![N]u32 {
            return self.indexArrayU32CheckedFrom(rng, N);
        }

        pub fn indexArrayU32From(self: Self, source: anytype, comptime N: usize) [N]u32 {
            return self.indexArrayU32CheckedFrom(source, N) catch unreachable;
        }

        pub fn indexArrayU32CheckedFrom(self: Self, source: anytype, comptime N: usize) Error![N]u32 {
            var out: [N]u32 = undefined;
            try self.fillU32CheckedFrom(source, &out);
            return out;
        }

        pub fn iter(self: Self, rng: Rng) Rng.SampleIterator(Self, usize) {
            return rng.sampleIter(usize, self);
        }

        pub fn iterFrom(self: Self, source: anytype) Rng.SampleIteratorFrom(@TypeOf(source), Self, usize) {
            return Rng.sampleIterFrom(source, usize, self);
        }

        pub fn iterChecked(self: Self, rng: Rng) Error!Rng.SampleIterator(Self, usize) {
            if (!self.isValid()) return error.InvalidWeight;
            return self.iter(rng);
        }

        pub fn iterCheckedFrom(self: Self, source: anytype) Error!Rng.SampleIteratorFrom(@TypeOf(source), Self, usize) {
            if (!self.isValid()) return error.InvalidWeight;
            return self.iterFrom(source);
        }

        pub fn iterU32(self: Self, rng: Rng) U32IndexIterator(Rng) {
            return .{ .source = rng, .tree = self };
        }

        pub fn iterU32From(self: Self, source: anytype) U32IndexIterator(@TypeOf(source)) {
            return .{ .source = source, .tree = self };
        }

        pub fn iterU32Checked(self: Self, rng: Rng) Error!U32IndexIterator(Rng) {
            return self.iterU32CheckedFrom(rng);
        }

        pub fn iterU32CheckedFrom(self: Self, source: anytype) Error!U32IndexIterator(@TypeOf(source)) {
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            if (!self.isValid()) return error.InvalidWeight;
            return self.iterU32From(source);
        }

        pub fn U32IndexIterator(comptime Source: type) type {
            return struct {
                const Iterator = @This();

                source: Source,
                tree: Self,

                pub fn next(self: *Iterator) ?u32 {
                    return self.nextValue();
                }

                pub fn nextValue(self: *Iterator) u32 {
                    return self.tree.sampleU32CheckedFrom(self.source) catch unreachable;
                }

                pub fn fill(self: *Iterator, dest: []u32) void {
                    self.tree.fillU32From(self.source, dest);
                }
            };
        }

        pub fn fillIndicesCheckedFrom(self: Self, source: anytype, dest: []usize) Error!void {
            try self.fillCheckedFrom(source, dest);
        }

        pub fn fillCheckedFrom(self: Self, source: anytype, dest: []usize) Error!void {
            if (dest.len == 0) return;
            const total = self.totalWeight();
            if (!(total > 0) or !std.math.isFinite(total)) return error.InvalidWeight;
            if (self.positive_count == 1) {
                @memset(dest, self.positive_index.?);
                return;
            }
            self.fillWithTotalFrom(source, dest, total);
        }

        pub fn fillU32CheckedFrom(self: Self, source: anytype, dest: []u32) Error!void {
            if (dest.len == 0) return;
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            const total = self.totalWeight();
            if (!(total > 0) or !std.math.isFinite(total)) return error.InvalidWeight;
            if (self.positive_count == 1) {
                @memset(dest, @intCast(self.positive_index.?));
                return;
            }
            self.fillU32WithTotalFrom(source, dest, total);
        }

        pub fn fillIndicesU32CheckedFrom(self: Self, source: anytype, dest: []u32) Error!void {
            try self.fillU32CheckedFrom(source, dest);
        }

        pub fn sampleCheckedFrom(self: Self, source: anytype) Error!usize {
            const total = self.totalWeight();
            if (!(total > 0) or !std.math.isFinite(total)) return error.InvalidWeight;
            if (self.positive_count == 1) return self.positive_index.?;

            return self.sampleWithTotalFrom(source, total);
        }

        pub fn sampleIndexCheckedFrom(self: Self, source: anytype) Error!usize {
            return self.sampleCheckedFrom(source);
        }

        pub fn sampleU32CheckedFrom(self: Self, source: anytype) Error!u32 {
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            return @intCast(try self.sampleCheckedFrom(source));
        }

        pub fn sampleIndexU32CheckedFrom(self: Self, source: anytype) Error!u32 {
            return self.sampleU32CheckedFrom(source);
        }

        fn sampleWithTotalFrom(self: Self, source: anytype, total: f64) usize {
            var out: [1]usize = undefined;
            self.fillWithTotalFrom(source, &out, total);
            return out[0];
        }

        fn fillWithTotalFrom(self: Self, source: anytype, dest: []usize, total: f64) void {
            for (dest) |*slot| {
                var target = Rng.floatFrom(source, f64) * total;
                var index: usize = 0;
                while (true) {
                    const left_index = 2 * index + 1;
                    const left = self.subtotal(left_index);
                    if (target < left) {
                        index = left_index;
                        continue;
                    }
                    target -= left;

                    const right_index = 2 * index + 2;
                    const right = self.subtotal(right_index);
                    if (target < right) {
                        index = right_index;
                        continue;
                    }
                    target -= right;

                    const own = self.subtotals.items[index] - left - right;
                    if (target < own or own > 0) {
                        slot.* = index;
                        break;
                    }
                }
            }
        }

        fn fillU32WithTotalFrom(self: Self, source: anytype, dest: []u32, total: f64) void {
            for (dest) |*slot| {
                var target = Rng.floatFrom(source, f64) * total;
                var index: usize = 0;
                while (true) {
                    const left_index = 2 * index + 1;
                    const left = self.subtotal(left_index);
                    if (target < left) {
                        index = left_index;
                        continue;
                    }
                    target -= left;

                    const right_index = 2 * index + 2;
                    const right = self.subtotal(right_index);
                    if (target < right) {
                        index = right_index;
                        continue;
                    }
                    target -= right;

                    const own = self.subtotals.items[index] - left - right;
                    if (target < own or own > 0) {
                        slot.* = @intCast(index);
                        break;
                    }
                }
            }
        }

        fn subtotal(self: Self, index: usize) f64 {
            return if (index < self.subtotals.items.len) self.subtotals.items[index] else 0;
        }

        fn applyDelta(self: *Self, index: usize, delta: f64) void {
            var cursor = index;
            while (true) {
                self.subtotals.items[cursor] += delta;
                if (cursor == 0) break;
                cursor = (cursor - 1) / 2;
            }
        }

        fn updatePositiveState(self: *Self, index: usize, old: f64, new: f64) void {
            const old_positive = old > 0;
            const new_positive = new > 0;
            if (!old_positive and new_positive) {
                self.positive_count += 1;
                if (self.positive_index == null) self.positive_index = index;
            } else if (old_positive and !new_positive) {
                self.positive_count -= 1;
                if (self.positive_count == 0) {
                    self.positive_index = null;
                } else if (self.positive_index == index) {
                    self.positive_index = self.findFirstPositive();
                }
            } else if (old_positive and new_positive and self.positive_count == 1) {
                self.positive_index = index;
            }
        }

        fn findFirstPositive(self: Self) ?usize {
            var index: usize = 0;
            while (index < self.subtotals.items.len) : (index += 1) {
                if ((self.get(index) catch unreachable) > 0) return index;
            }
            return null;
        }

        fn weightToF64(input_weight: Weight) Error!f64 {
            const value: f64 = switch (@typeInfo(Weight)) {
                .int => @floatFromInt(input_weight),
                .float => @floatCast(input_weight),
                else => @compileError("weighted tree weights must be numeric"),
            };
            if (!(value >= 0) or !std.math.isFinite(value)) return error.InvalidWeight;
            return value;
        }

        fn buildSubtotals(subtotals: []f64) Error!void {
            var i = subtotals.len;
            while (i > 1) {
                i -= 1;
                const parent = (i - 1) / 2;
                subtotals[parent] += subtotals[i];
                if (!std.math.isFinite(subtotals[parent])) return error.InvalidWeight;
            }
        }
    };
}

pub fn WeightedIntTree(comptime Weight: type) type {
    return struct {
        const Self = @This();

        subtotals: std.ArrayList(u64),
        positive_count: usize = 0,
        positive_index: ?usize = null,
        allocator: std.mem.Allocator,

        pub const Update = struct {
            index: usize,
            weight: Weight,
        };

        pub const WeightIterator = struct {
            const Iterator = @This();

            tree: Self,
            index: usize = 0,

            pub fn next(self: *Iterator) ?u64 {
                const value = self.tree.weight(self.index) orelse return null;
                self.index += 1;
                return value;
            }

            pub fn remaining(self: Iterator) usize {
                return self.tree.len() - self.index;
            }

            pub fn len(self: Iterator) usize {
                return self.remaining();
            }

            pub fn sizeHint(self: Iterator) struct { lower: usize, upper: ?usize } {
                const length = self.remaining();
                return .{ .lower = length, .upper = length };
            }

            pub fn fill(self: *Iterator, dest: []u64) usize {
                const count = @min(dest.len, self.remaining());
                for (dest[0..count], self.index..) |*slot, index| slot.* = self.tree.get(index) catch unreachable;
                self.index += count;
                return count;
            }
        };

        pub const ProbabilityIterator = struct {
            const Iterator = @This();

            tree: Self,
            index: usize = 0,

            pub fn next(self: *Iterator) ?f64 {
                const value = self.tree.probability(self.index) orelse return null;
                self.index += 1;
                return value;
            }

            pub fn remaining(self: Iterator) usize {
                return self.tree.len() - self.index;
            }

            pub fn len(self: Iterator) usize {
                return self.remaining();
            }

            pub fn sizeHint(self: Iterator) struct { lower: usize, upper: ?usize } {
                const length = self.remaining();
                return .{ .lower = length, .upper = length };
            }

            pub fn fill(self: *Iterator, dest: []f64) usize {
                const count = @min(dest.len, self.remaining());
                if (count == 0) return 0;
                const total = self.tree.totalWeight();
                if (total == 0) return 0;
                const total_float = @as(f64, @floatFromInt(total));
                for (dest[0..count], self.index..) |*slot, index| slot.* = @as(f64, @floatFromInt(self.tree.get(index) catch unreachable)) / total_float;
                self.index += count;
                return count;
            }
        };

        pub fn init(allocator: std.mem.Allocator, input_weights: []const Weight) !Self {
            comptime requireUnsignedWeight(Weight);
            var subtotals = try std.ArrayList(u64).initCapacity(allocator, input_weights.len);
            errdefer subtotals.deinit(allocator);

            var positive_count: usize = 0;
            var positive_index: ?usize = null;
            for (input_weights, 0..) |input_weight, index| {
                const value = try weightToU64(input_weight);
                try subtotals.append(allocator, value);
                if (value > 0) {
                    positive_count += 1;
                    if (positive_index == null) positive_index = index;
                }
            }
            try buildSubtotals(subtotals.items);

            return .{
                .subtotals = subtotals,
                .positive_count = positive_count,
                .positive_index = positive_index,
                .allocator = allocator,
            };
        }

        pub fn initByIndex(
            allocator: std.mem.Allocator,
            length: usize,
            comptime weightFn: fn (usize) Weight,
        ) !Self {
            comptime requireUnsignedWeight(Weight);
            var subtotals = try std.ArrayList(u64).initCapacity(allocator, length);
            errdefer subtotals.deinit(allocator);

            var positive_count: usize = 0;
            var positive_index: ?usize = null;
            var index: usize = 0;
            while (index < length) : (index += 1) {
                const value = try weightToU64(weightFn(index));
                try subtotals.append(allocator, value);
                if (value > 0) {
                    positive_count += 1;
                    if (positive_index == null) positive_index = index;
                }
            }
            try buildSubtotals(subtotals.items);

            return .{
                .subtotals = subtotals,
                .positive_count = positive_count,
                .positive_index = positive_index,
                .allocator = allocator,
            };
        }

        pub fn initBy(
            allocator: std.mem.Allocator,
            comptime T: type,
            items: []const T,
            comptime weightFn: fn (*const T) Weight,
        ) !Self {
            comptime requireUnsignedWeight(Weight);
            var subtotals = try std.ArrayList(u64).initCapacity(allocator, items.len);
            errdefer subtotals.deinit(allocator);

            var positive_count: usize = 0;
            var positive_index: ?usize = null;
            for (items, 0..) |*item, index| {
                const value = try weightToU64(weightFn(item));
                try subtotals.append(allocator, value);
                if (value > 0) {
                    positive_count += 1;
                    if (positive_index == null) positive_index = index;
                }
            }
            try buildSubtotals(subtotals.items);

            return .{
                .subtotals = subtotals,
                .positive_count = positive_count,
                .positive_index = positive_index,
                .allocator = allocator,
            };
        }

        pub fn deinit(self: *Self) void {
            self.subtotals.deinit(self.allocator);
            self.* = undefined;
        }

        pub fn len(self: Self) usize {
            return self.subtotals.items.len;
        }

        pub fn numChoices(self: Self) usize {
            return self.subtotals.items.len;
        }

        pub fn isEmpty(self: Self) bool {
            return self.len() == 0;
        }

        pub fn totalWeight(self: Self) u64 {
            return if (self.subtotals.items.len == 0) 0 else self.subtotals.items[0];
        }

        pub fn isValid(self: Self) bool {
            return self.totalWeight() > 0;
        }

        pub fn positiveCount(self: Self) usize {
            return self.positive_count;
        }

        pub fn constantIndex(self: Self) ?usize {
            return if (self.positive_count == 1) self.positive_index else null;
        }

        pub fn get(self: Self, index: usize) Error!u64 {
            if (index >= self.subtotals.items.len) return error.InvalidParameter;
            return self.subtotals.items[index] - self.subtotal(2 * index + 1) - self.subtotal(2 * index + 2);
        }

        pub fn weightAt(self: Self, index: usize) Error!u64 {
            return self.get(index);
        }

        pub fn weight(self: Self, index: usize) ?u64 {
            return self.weightAt(index) catch null;
        }

        pub fn weightIter(self: Self) WeightIterator {
            return .{ .tree = self };
        }

        pub fn probabilityAt(self: Self, index: usize) Error!f64 {
            const current_weight = try self.get(index);
            const total = self.totalWeight();
            if (total == 0) return error.InvalidWeight;
            return @as(f64, @floatFromInt(current_weight)) / @as(f64, @floatFromInt(total));
        }

        pub fn probability(self: Self, index: usize) ?f64 {
            return self.probabilityAt(index) catch null;
        }

        pub fn probabilityIter(self: Self) ProbabilityIterator {
            return .{ .tree = self };
        }

        pub fn weights(self: Self, allocator: std.mem.Allocator) ![]u64 {
            const out = try allocator.alloc(u64, self.len());
            errdefer allocator.free(out);
            try self.weightsInto(out);
            return out;
        }

        pub fn weightsInto(self: Self, out: []u64) Error!void {
            if (out.len != self.len()) return error.InvalidLength;
            for (out, 0..) |*slot, index| slot.* = try self.get(index);
        }

        pub fn probabilities(self: Self, allocator: std.mem.Allocator) ![]f64 {
            const out = try allocator.alloc(f64, self.len());
            errdefer allocator.free(out);
            try self.probabilitiesInto(out);
            return out;
        }

        pub fn probabilitiesInto(self: Self, out: []f64) Error!void {
            if (out.len != self.len()) return error.InvalidLength;
            if (out.len == 0) return;
            const total = self.totalWeight();
            if (total == 0) return error.InvalidWeight;
            const total_float = @as(f64, @floatFromInt(total));
            for (out, 0..) |*slot, index| slot.* = @as(f64, @floatFromInt(try self.get(index))) / total_float;
        }

        pub fn push(self: *Self, input_weight: Weight) !void {
            const value = try weightToU64(input_weight);
            const next_total = std.math.add(u64, self.totalWeight(), value) catch return error.InvalidWeight;

            try self.subtotals.append(self.allocator, value);
            var index = self.subtotals.items.len - 1;
            while (index != 0) {
                index = (index - 1) / 2;
                self.subtotals.items[index] += value;
            }
            if (value > 0) {
                self.positive_count += 1;
                if (self.positive_index == null) self.positive_index = self.subtotals.items.len - 1;
            }
            std.debug.assert(self.totalWeight() == next_total);
        }

        pub fn pop(self: *Self) ?u64 {
            if (self.subtotals.items.len == 0) return null;

            const index = self.subtotals.items.len - 1;
            const current_weight = self.get(index) catch unreachable;
            _ = self.subtotals.pop();

            var parent_index = index;
            while (parent_index != 0) {
                parent_index = (parent_index - 1) / 2;
                self.subtotals.items[parent_index] -= current_weight;
            }
            if (current_weight > 0) {
                self.positive_count -= 1;
                if (self.positive_count == 0) {
                    self.positive_index = null;
                } else if (self.positive_index == index) {
                    self.positive_index = self.findFirstPositive();
                }
            }
            return current_weight;
        }

        pub fn update(self: *Self, index: usize, input_weight: Weight) !void {
            if (index >= self.subtotals.items.len) return error.InvalidParameter;
            const value = try weightToU64(input_weight);
            const old = try self.get(index);
            if (value >= old) {
                const delta = value - old;
                _ = std.math.add(u64, self.totalWeight(), delta) catch return error.InvalidWeight;
                var cursor = index;
                while (true) {
                    self.subtotals.items[cursor] += delta;
                    if (cursor == 0) break;
                    cursor = (cursor - 1) / 2;
                }
            } else {
                const delta = old - value;
                var cursor = index;
                while (true) {
                    self.subtotals.items[cursor] -= delta;
                    if (cursor == 0) break;
                    cursor = (cursor - 1) / 2;
                }
            }
            self.updatePositiveState(index, old, value);
        }

        pub fn updateMany(self: *Self, updates: []const Update) !void {
            if (updates.len == 0) return;

            var previous_index: ?usize = null;
            var next_total = self.totalWeight();
            for (updates) |item| {
                if (item.index >= self.subtotals.items.len) return error.InvalidParameter;
                if (previous_index) |previous| {
                    if (previous >= item.index) return error.InvalidParameter;
                }
                const value = try weightToU64(item.weight);
                const old = try self.get(item.index);
                if (value >= old) {
                    const delta = value - old;
                    next_total = std.math.add(u64, next_total, delta) catch return error.InvalidWeight;
                } else {
                    next_total -= old - value;
                }
                previous_index = item.index;
            }

            for (updates) |item| {
                const value = weightToU64(item.weight) catch unreachable;
                const old = self.get(item.index) catch unreachable;
                if (value < old) {
                    self.applyDeltaSub(item.index, old - value);
                    self.updatePositiveState(item.index, old, value);
                }
            }
            for (updates) |item| {
                const value = weightToU64(item.weight) catch unreachable;
                const old = self.get(item.index) catch unreachable;
                if (value >= old) {
                    self.applyDeltaAdd(item.index, value - old);
                    self.updatePositiveState(item.index, old, value);
                }
            }
        }

        pub fn updateWeights(self: *Self, updates: []const Update) !void {
            try self.updateMany(updates);
        }

        pub fn updateAll(self: *Self, input_weights: []const Weight) !void {
            if (input_weights.len != self.len()) return error.InvalidParameter;
            const next = try Self.init(self.allocator, input_weights);
            self.subtotals.deinit(self.allocator);
            self.* = next;
        }

        pub fn updateAllByIndex(self: *Self, comptime weightFn: fn (usize) Weight) !void {
            const next = try Self.initByIndex(self.allocator, self.len(), weightFn);
            self.subtotals.deinit(self.allocator);
            self.* = next;
        }

        pub fn updateAllBy(
            self: *Self,
            comptime T: type,
            items: []const T,
            comptime weightFn: fn (*const T) Weight,
        ) !void {
            if (items.len != self.len()) return error.InvalidParameter;
            const next = try Self.initBy(self.allocator, T, items, weightFn);
            self.subtotals.deinit(self.allocator);
            self.* = next;
        }

        pub fn sample(self: Self, rng: Rng) usize {
            return self.sampleChecked(rng) catch unreachable;
        }

        pub fn sampleIndex(self: Self, rng: Rng) usize {
            return self.sample(rng);
        }

        pub fn sampleU32(self: Self, rng: Rng) u32 {
            return self.sampleU32Checked(rng) catch unreachable;
        }

        pub fn sampleIndexU32(self: Self, rng: Rng) u32 {
            return self.sampleU32(rng);
        }

        pub fn sampleChecked(self: Self, rng: Rng) Error!usize {
            return self.sampleCheckedFrom(rng);
        }

        pub fn sampleIndexChecked(self: Self, rng: Rng) Error!usize {
            return self.sampleChecked(rng);
        }

        pub fn sampleU32Checked(self: Self, rng: Rng) Error!u32 {
            return self.sampleU32CheckedFrom(rng);
        }

        pub fn sampleIndexU32Checked(self: Self, rng: Rng) Error!u32 {
            return self.sampleU32Checked(rng);
        }

        pub fn sampleFrom(self: Self, source: anytype) usize {
            return self.sampleCheckedFrom(source) catch unreachable;
        }

        pub fn sampleIndexFrom(self: Self, source: anytype) usize {
            return self.sampleFrom(source);
        }

        pub fn sampleU32From(self: Self, source: anytype) u32 {
            return self.sampleU32CheckedFrom(source) catch unreachable;
        }

        pub fn sampleIndexU32From(self: Self, source: anytype) u32 {
            return self.sampleU32From(source);
        }

        pub fn fill(self: Self, rng: Rng, dest: []usize) void {
            self.fillChecked(rng, dest) catch unreachable;
        }

        pub fn fillIndices(self: Self, rng: Rng, dest: []usize) void {
            self.fill(rng, dest);
        }

        pub fn fillU32(self: Self, rng: Rng, dest: []u32) void {
            self.fillU32Checked(rng, dest) catch unreachable;
        }

        pub fn fillIndicesU32(self: Self, rng: Rng, dest: []u32) void {
            self.fillU32(rng, dest);
        }

        pub fn fillChecked(self: Self, rng: Rng, dest: []usize) Error!void {
            try self.fillCheckedFrom(rng, dest);
        }

        pub fn fillIndicesChecked(self: Self, rng: Rng, dest: []usize) Error!void {
            try self.fillChecked(rng, dest);
        }

        pub fn fillU32Checked(self: Self, rng: Rng, dest: []u32) Error!void {
            try self.fillU32CheckedFrom(rng, dest);
        }

        pub fn fillIndicesU32Checked(self: Self, rng: Rng, dest: []u32) Error!void {
            try self.fillU32Checked(rng, dest);
        }

        pub fn fillFrom(self: Self, source: anytype, dest: []usize) void {
            self.fillCheckedFrom(source, dest) catch unreachable;
        }

        pub fn fillIndicesFrom(self: Self, source: anytype, dest: []usize) void {
            self.fillFrom(source, dest);
        }

        pub fn fillU32From(self: Self, source: anytype, dest: []u32) void {
            self.fillU32CheckedFrom(source, dest) catch unreachable;
        }

        pub fn fillIndicesU32From(self: Self, source: anytype, dest: []u32) void {
            self.fillU32From(source, dest);
        }

        pub fn indices(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]usize {
            return self.indicesFrom(allocator, rng, amount);
        }

        pub fn indicesFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]usize {
            const out = try allocator.alloc(usize, amount);
            errdefer allocator.free(out);
            self.fillFrom(source, out);
            return out;
        }

        pub fn indicesChecked(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]usize {
            return self.indicesCheckedFrom(allocator, rng, amount);
        }

        pub fn indicesCheckedFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]usize {
            if (amount != 0 and !self.isValid()) return error.InvalidWeight;
            const out = try allocator.alloc(usize, amount);
            errdefer allocator.free(out);
            try self.fillCheckedFrom(source, out);
            return out;
        }

        pub fn indicesU32(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]u32 {
            return self.indicesU32From(allocator, rng, amount);
        }

        pub fn indicesU32From(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]u32 {
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            const out = try allocator.alloc(u32, amount);
            errdefer allocator.free(out);
            self.fillU32From(source, out);
            return out;
        }

        pub fn indicesU32Checked(self: Self, allocator: std.mem.Allocator, rng: Rng, amount: usize) ![]u32 {
            return self.indicesU32CheckedFrom(allocator, rng, amount);
        }

        pub fn indicesU32CheckedFrom(self: Self, allocator: std.mem.Allocator, source: anytype, amount: usize) ![]u32 {
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            if (amount != 0 and !self.isValid()) return error.InvalidWeight;
            const out = try allocator.alloc(u32, amount);
            errdefer allocator.free(out);
            try self.fillU32CheckedFrom(source, out);
            return out;
        }

        pub fn indexArray(self: Self, rng: Rng, comptime N: usize) [N]usize {
            return self.indexArrayFrom(rng, N);
        }

        pub fn indexArrayFrom(self: Self, source: anytype, comptime N: usize) [N]usize {
            var out: [N]usize = undefined;
            self.fillFrom(source, &out);
            return out;
        }

        pub fn indexArrayChecked(self: Self, rng: Rng, comptime N: usize) Error![N]usize {
            return self.indexArrayCheckedFrom(rng, N);
        }

        pub fn indexArrayCheckedFrom(self: Self, source: anytype, comptime N: usize) Error![N]usize {
            var out: [N]usize = undefined;
            try self.fillCheckedFrom(source, &out);
            return out;
        }

        pub fn indexArrayU32(self: Self, rng: Rng, comptime N: usize) [N]u32 {
            return self.indexArrayU32Checked(rng, N) catch unreachable;
        }

        pub fn indexArrayU32Checked(self: Self, rng: Rng, comptime N: usize) Error![N]u32 {
            return self.indexArrayU32CheckedFrom(rng, N);
        }

        pub fn indexArrayU32From(self: Self, source: anytype, comptime N: usize) [N]u32 {
            return self.indexArrayU32CheckedFrom(source, N) catch unreachable;
        }

        pub fn indexArrayU32CheckedFrom(self: Self, source: anytype, comptime N: usize) Error![N]u32 {
            var out: [N]u32 = undefined;
            try self.fillU32CheckedFrom(source, &out);
            return out;
        }

        pub fn iter(self: Self, rng: Rng) Rng.SampleIterator(Self, usize) {
            return rng.sampleIter(usize, self);
        }

        pub fn iterFrom(self: Self, source: anytype) Rng.SampleIteratorFrom(@TypeOf(source), Self, usize) {
            return Rng.sampleIterFrom(source, usize, self);
        }

        pub fn iterChecked(self: Self, rng: Rng) Error!Rng.SampleIterator(Self, usize) {
            if (!self.isValid()) return error.InvalidWeight;
            return self.iter(rng);
        }

        pub fn iterCheckedFrom(self: Self, source: anytype) Error!Rng.SampleIteratorFrom(@TypeOf(source), Self, usize) {
            if (!self.isValid()) return error.InvalidWeight;
            return self.iterFrom(source);
        }

        pub fn iterU32(self: Self, rng: Rng) U32IndexIterator(Rng) {
            return .{ .source = rng, .tree = self };
        }

        pub fn iterU32From(self: Self, source: anytype) U32IndexIterator(@TypeOf(source)) {
            return .{ .source = source, .tree = self };
        }

        pub fn iterU32Checked(self: Self, rng: Rng) Error!U32IndexIterator(Rng) {
            return self.iterU32CheckedFrom(rng);
        }

        pub fn iterU32CheckedFrom(self: Self, source: anytype) Error!U32IndexIterator(@TypeOf(source)) {
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            if (!self.isValid()) return error.InvalidWeight;
            return self.iterU32From(source);
        }

        pub fn U32IndexIterator(comptime Source: type) type {
            return struct {
                const Iterator = @This();

                source: Source,
                tree: Self,

                pub fn next(self: *Iterator) ?u32 {
                    return self.nextValue();
                }

                pub fn nextValue(self: *Iterator) u32 {
                    return self.tree.sampleU32CheckedFrom(self.source) catch unreachable;
                }

                pub fn fill(self: *Iterator, dest: []u32) void {
                    self.tree.fillU32From(self.source, dest);
                }
            };
        }

        pub fn fillIndicesCheckedFrom(self: Self, source: anytype, dest: []usize) Error!void {
            try self.fillCheckedFrom(source, dest);
        }

        pub fn fillCheckedFrom(self: Self, source: anytype, dest: []usize) Error!void {
            if (dest.len == 0) return;
            const total = self.totalWeight();
            if (total == 0) return error.InvalidWeight;
            if (self.positive_count == 1) {
                @memset(dest, self.positive_index.?);
                return;
            }
            self.fillWithTotalFrom(source, dest, total);
        }

        pub fn fillU32CheckedFrom(self: Self, source: anytype, dest: []u32) Error!void {
            if (dest.len == 0) return;
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            const total = self.totalWeight();
            if (total == 0) return error.InvalidWeight;
            if (self.positive_count == 1) {
                @memset(dest, @intCast(self.positive_index.?));
                return;
            }
            self.fillU32WithTotalFrom(source, dest, total);
        }

        pub fn fillIndicesU32CheckedFrom(self: Self, source: anytype, dest: []u32) Error!void {
            try self.fillU32CheckedFrom(source, dest);
        }

        pub fn sampleCheckedFrom(self: Self, source: anytype) Error!usize {
            const total = self.totalWeight();
            if (total == 0) return error.InvalidWeight;
            if (self.positive_count == 1) return self.positive_index.?;

            return self.sampleWithTotalFrom(source, total);
        }

        pub fn sampleIndexCheckedFrom(self: Self, source: anytype) Error!usize {
            return self.sampleCheckedFrom(source);
        }

        pub fn sampleU32CheckedFrom(self: Self, source: anytype) Error!u32 {
            if (self.len() > std.math.maxInt(u32)) return error.InvalidParameter;
            return @intCast(try self.sampleCheckedFrom(source));
        }

        pub fn sampleIndexU32CheckedFrom(self: Self, source: anytype) Error!u32 {
            return self.sampleU32CheckedFrom(source);
        }

        fn sampleWithTotalFrom(self: Self, source: anytype, total: u64) usize {
            var out: [1]usize = undefined;
            self.fillWithTotalFrom(source, &out, total);
            return out[0];
        }

        fn fillWithTotalFrom(self: Self, source: anytype, dest: []usize, total: u64) void {
            for (dest) |*slot| {
                var target = Rng.uintLessThanFrom(source, u64, total);
                var index: usize = 0;
                while (true) {
                    const left_index = 2 * index + 1;
                    const left = self.subtotal(left_index);
                    if (target < left) {
                        index = left_index;
                        continue;
                    }
                    target -= left;

                    const right_index = 2 * index + 2;
                    const right = self.subtotal(right_index);
                    if (target < right) {
                        index = right_index;
                        continue;
                    }
                    target -= right;

                    const own = self.subtotals.items[index] - left - right;
                    if (target < own or own > 0) {
                        slot.* = index;
                        break;
                    }
                }
            }
        }

        fn fillU32WithTotalFrom(self: Self, source: anytype, dest: []u32, total: u64) void {
            for (dest) |*slot| {
                var target = Rng.uintLessThanFrom(source, u64, total);
                var index: usize = 0;
                while (true) {
                    const left_index = 2 * index + 1;
                    const left = self.subtotal(left_index);
                    if (target < left) {
                        index = left_index;
                        continue;
                    }
                    target -= left;

                    const right_index = 2 * index + 2;
                    const right = self.subtotal(right_index);
                    if (target < right) {
                        index = right_index;
                        continue;
                    }
                    target -= right;

                    const own = self.subtotals.items[index] - left - right;
                    if (target < own or own > 0) {
                        slot.* = @intCast(index);
                        break;
                    }
                }
            }
        }

        fn subtotal(self: Self, index: usize) u64 {
            return if (index < self.subtotals.items.len) self.subtotals.items[index] else 0;
        }

        fn applyDeltaAdd(self: *Self, index: usize, delta: u64) void {
            var cursor = index;
            while (true) {
                self.subtotals.items[cursor] = std.math.add(u64, self.subtotals.items[cursor], delta) catch unreachable;
                if (cursor == 0) break;
                cursor = (cursor - 1) / 2;
            }
        }

        fn applyDeltaSub(self: *Self, index: usize, delta: u64) void {
            var cursor = index;
            while (true) {
                self.subtotals.items[cursor] -= delta;
                if (cursor == 0) break;
                cursor = (cursor - 1) / 2;
            }
        }

        fn updatePositiveState(self: *Self, index: usize, old: u64, new: u64) void {
            const old_positive = old > 0;
            const new_positive = new > 0;
            if (!old_positive and new_positive) {
                self.positive_count += 1;
                if (self.positive_index == null) self.positive_index = index;
            } else if (old_positive and !new_positive) {
                self.positive_count -= 1;
                if (self.positive_count == 0) {
                    self.positive_index = null;
                } else if (self.positive_index == index) {
                    self.positive_index = self.findFirstPositive();
                }
            } else if (old_positive and new_positive and self.positive_count == 1) {
                self.positive_index = index;
            }
        }

        fn findFirstPositive(self: Self) ?usize {
            var index: usize = 0;
            while (index < self.subtotals.items.len) : (index += 1) {
                if ((self.get(index) catch unreachable) > 0) return index;
            }
            return null;
        }

        fn buildSubtotals(subtotals: []u64) Error!void {
            var i = subtotals.len;
            while (i > 1) {
                i -= 1;
                const parent = (i - 1) / 2;
                subtotals[parent] = std.math.add(u64, subtotals[parent], subtotals[i]) catch return error.InvalidWeight;
            }
        }

        fn weightToU64(input_weight: Weight) Error!u64 {
            if (@typeInfo(Weight).int.bits > 64 and input_weight > std.math.maxInt(u64)) return error.InvalidWeight;
            return @intCast(input_weight);
        }
    };
}

fn requireUnsignedWeight(comptime Weight: type) void {
    if (@typeInfo(Weight) != .int or @typeInfo(Weight).int.signedness != .unsigned) {
        @compileError("WeightedIntTree weights must be unsigned integers");
    }
}

fn validateUniformRange(comptime T: type, low: T, high: T, comptime allow_equal: bool) Error!void {
    switch (@typeInfo(T)) {
        .int => {
            if (allow_equal) {
                if (low > high) return error.EmptyRange;
            } else if (low >= high) return error.EmptyRange;
        },
        .float => try validateFiniteFloatRange(T, low, high, allow_equal),
        else => @compileError("Uniform supports integer and floating-point types"),
    }
}

fn validateFiniteFloatRange(comptime T: type, low: T, high: T, comptime allow_equal: bool) Error!void {
    requireFloat(T);
    if (!std.math.isFinite(low) or !std.math.isFinite(high)) return error.NonFinite;
    if (allow_equal) {
        if (low > high) return error.EmptyRange;
    } else if (low >= high) return error.EmptyRange;
    if (!std.math.isFinite(high - low)) return error.NonFinite;
}

fn requireFloat(comptime T: type) void {
    if (@typeInfo(T) != .float) @compileError("expected float type, found " ++ @typeName(T));
}

fn requireFloatOrFloatVector(comptime T: type) void {
    switch (@typeInfo(T)) {
        .float => {},
        .vector => |info| requireFloat(info.child),
        else => @compileError("expected float or float vector type, found " ++ @typeName(T)),
    }
}

fn vectorInfo(comptime VectorType: type) @TypeOf(@typeInfo(VectorType).vector) {
    const info = @typeInfo(VectorType);
    if (info != .vector) @compileError("expected vector type, found " ++ @typeName(VectorType));
    return info.vector;
}

fn vectorChild(comptime VectorType: type) type {
    @setEvalBranchQuota(2000);
    return vectorInfo(VectorType).child;
}

fn zeroOf(comptime T: type) T {
    requireFloatOrFloatVector(T);
    return switch (@typeInfo(T)) {
        .float => 0,
        .vector => @splat(0),
        else => unreachable,
    };
}

fn oneOf(comptime T: type) T {
    requireFloatOrFloatVector(T);
    return switch (@typeInfo(T)) {
        .float => 1,
        .vector => @splat(1),
        else => unreachable,
    };
}

fn splatOrScalar(comptime T: type, comptime value: comptime_float) T {
    requireFloatOrFloatVector(T);
    return switch (@typeInfo(T)) {
        .float => value,
        .vector => |info| @splat(@as(info.child, value)),
        else => unreachable,
    };
}

fn open01From(source: anytype, comptime T: type) T {
    requireFloatOrFloatVector(T);
    return switch (@typeInfo(T)) {
        .float => Rng.floatOpenFrom(source, T),
        .vector => Rng.vectorOpenFrom(source, T),
        else => unreachable,
    };
}

fn openClosed01From(source: anytype, comptime T: type) T {
    requireFloatOrFloatVector(T);
    return switch (@typeInfo(T)) {
        .float => Rng.floatOpenClosedFrom(source, T),
        .vector => Rng.vectorOpenClosedFrom(source, T),
        else => unreachable,
    };
}

fn vectorOpenMidpointF32From(source: anytype, comptime VectorType: type) VectorType {
    const info = vectorInfo(VectorType);
    if (info.child != f32) @compileError("vectorOpenMidpointF32From expects an f32 vector");

    var out: VectorType = undefined;
    var bits: u64 = 0;
    inline for (0..info.len) |lane| {
        if (lane % 2 == 0) bits = Rng.nextFrom(source);
        const raw: u24 = if (lane % 2 == 0)
            @truncate(bits >> 40)
        else
            @truncate(bits >> 16);
        out[lane] = (@as(f32, @floatFromInt(raw)) + 0.5) * (1.0 / 16777216.0);
    }
    return out;
}

fn vectorExpTableFrom(source: anytype, comptime VectorType: type, comptime table: anytype) VectorType {
    const info = vectorInfo(VectorType);
    var out: VectorType = undefined;
    var bits: u64 = 0;
    inline for (0..info.len) |lane| {
        if (lane % 4 == 0) bits = Rng.nextFrom(source);
        const shift: u6 = @intCast((lane % 4) * 14);
        const index: usize = @intCast((bits >> shift) & 0x3fff);
        out[lane] = table[index];
    }
    return out;
}

fn approxNegLogF32Vector(u: anytype) @TypeOf(u) {
    const Vec = @TypeOf(u);
    const info = vectorInfo(Vec);
    if (info.child != f32) @compileError("approxNegLogF32Vector expects an f32 vector");
    const VecU = @Vector(info.len, u32);
    const bits: VecU = @bitCast(u);
    const exponent_bits = (bits >> @as(VecU, @splat(23))) & @as(VecU, @splat(0xff));
    const mantissa_bits = (bits & @as(VecU, @splat(0x7fffff))) | @as(VecU, @splat(@as(u32, 0x7f) << 23));
    var exponent = @as(Vec, @floatFromInt(@as(@Vector(info.len, i32), @intCast(exponent_bits)))) - @as(Vec, @splat(127.0));
    var m = @as(Vec, @bitCast(mantissa_bits));
    const high_mask = m > @as(Vec, @splat(1.4142135623730951));
    m = @select(f32, high_mask, m * @as(Vec, @splat(0.5)), m);
    exponent += @select(f32, high_mask, @as(Vec, @splat(1.0)), @as(Vec, @splat(0.0)));

    const z = (m - @as(Vec, @splat(1.0))) / (m + @as(Vec, @splat(1.0)));
    const z2 = z * z;
    const z4 = z2 * z2;
    const z8 = z4 * z4;
    const poly = @as(Vec, @splat(1.0)) +
        z2 * @as(Vec, @splat(1.0 / 3.0)) +
        z4 * @as(Vec, @splat(1.0 / 5.0)) +
        z4 * z2 * @as(Vec, @splat(1.0 / 7.0)) +
        z8 * @as(Vec, @splat(1.0 / 9.0));
    const log_m = @as(Vec, @splat(2.0)) * z * poly;
    return -(exponent * @as(Vec, @splat(std.math.ln2)) + log_m);
}

fn fillOpen01From(source: anytype, comptime T: type, dest: []T) void {
