}

fn libmvecScalarExp(comptime T: type, value: T) T {
    return @exp(value);
}

fn dlsymExpValue(comptime T: type, exp_fn: LibmExpF64, value: T) T {
    return switch (T) {
        f64 => exp_fn(value),
        f32 => @floatCast(exp_fn(@floatCast(value))),
        else => unreachable,
    };
}

fn dlsymExpInPlace(comptime T: type, exp_fn: LibmExpF64, dest: []T) void {
    for (dest) |*item| item.* = dlsymExpValue(T, exp_fn, item.*);
}

fn libmvecExpInPlaceF64(dest: []f64, exp_fn: LibmvecExpF64x4) void {
    var i: usize = 0;
    while (i + 4 <= dest.len) : (i += 4) {
        const vec: @Vector(4, f64) = .{ dest[i], dest[i + 1], dest[i + 2], dest[i + 3] };
        const out = exp_fn(vec);
        inline for (0..4) |lane| dest[i + lane] = out[lane];
    }
    while (i < dest.len) : (i += 1) dest[i] = @exp(dest[i]);
}

fn libmvecExpInPlaceF32(dest: []f32, exp_fn: LibmvecExpF32x8) void {
    var i: usize = 0;
    while (i + 8 <= dest.len) : (i += 8) {
        const vec: @Vector(8, f32) = .{
            dest[i],
            dest[i + 1],
            dest[i + 2],
            dest[i + 3],
            dest[i + 4],
            dest[i + 5],
            dest[i + 6],
            dest[i + 7],
        };
        const out = exp_fn(vec);
        inline for (0..8) |lane| dest[i + lane] = out[lane];
    }
    while (i < dest.len) : (i += 1) dest[i] = @exp(dest[i]);
}

fn logNormalApproxF32ParametersValid(mean: f32, stddev: f32) bool {
    return std.math.isFinite(mean) and
        std.math.isFinite(stddev) and
        stddev >= 0 and
        @abs(mean) <= log_normal_approx_f32_max_abs_mean and
        stddev <= log_normal_approx_f32_max_stddev;
}

fn logNormalExp2F32ParametersValid(mean: f32, stddev: f32) bool {
    return std.math.isFinite(mean) and
        std.math.isFinite(stddev) and
        stddev >= 0 and
        @abs(mean) <= log_normal_exp2_f32_max_abs_mean and
        stddev <= log_normal_exp2_f32_max_stddev;
}

fn expm1ApproxPositiveF32(value: f32) f32 {
    return std.math.expm1(value) + 1.0;
}

fn expm1ApproxPositiveInPlaceF32(dest: []f32) void {
    for (dest) |*item| item.* = expm1ApproxPositiveF32(item.*);
}

fn exp2ApproxPositiveF32(value: f32) f32 {
    return @exp2(value * std.math.log2e);
}

fn exp2ApproxPositiveInPlaceF32(dest: []f32) void {
    for (dest) |*item| item.* = exp2ApproxPositiveF32(item.*);
}

fn floatDistancePositiveF32(a: f32, b: f32) u32 {
    std.debug.assert(a >= 0 and b >= 0);
    const ai: u32 = @bitCast(a);
    const bi: u32 = @bitCast(b);
    return if (ai >= bi) ai - bi else bi - ai;
}

fn expectNearBitsF32(expected_bits: u32, actual: f32, max_ulp: u32) !void {
    const expected: f32 = @bitCast(expected_bits);
    try std.testing.expect(floatDistancePositiveF32(expected, actual) <= max_ulp);
}

fn floatDistancePositiveF64(a: f64, b: f64) u64 {
    std.debug.assert(a >= 0 and b >= 0);
    const ai: u64 = @bitCast(a);
    const bi: u64 = @bitCast(b);
    return if (ai >= bi) ai - bi else bi - ai;
}

fn expVectorSliceInPlace(comptime VectorType: type, dest: []VectorType) void {
    const info = vectorInfo(VectorType);
    requireFloat(info.child);
    for (dest) |*item| item.* = @exp(item.*);
}

fn absVectorSliceInPlace(comptime VectorType: type, dest: []VectorType) void {
