fn weibullFromOpenUniformsVector(comptime T: type, comptime VectorType: type, dest: []T, scale: T, inverse_shape: T) void {
    const len = @typeInfo(VectorType).vector.len;
    const scale_vec: VectorType = @splat(scale);
