    var i: usize = 0;
    while (i + len <= dest.len) : (i += len) {
        var uniform_vec: VectorType = undefined;
        inline for (0..len) |lane| uniform_vec[lane] = dest[i + lane];
        const out = scale_vec * @exp(@log(-@log(uniform_vec)) * inverse_shape_vec);
