    }
}

test "basic distributions stay in expected ranges" {
    const alea = @import("root.zig");
    var engine = alea.Xoshiro256.init(1234);
    const rng = Rng.init(&engine);

    try std.testing.expect(uniform(rng, u32, 5, 9) >= 5);
    try std.testing.expect(uniform(rng, f64, -1, 1) < 1);
    try std.testing.expect(try uniformChecked(rng, u32, 5, 9) >= 5);
    try std.testing.expect(try uniformCheckedFrom(&engine, f64, -1, 1) < 1);
    try std.testing.expect(try sampleSingle(rng, u32, 5, 9) < 9);
    try std.testing.expect(try sampleSingleFrom(&engine, f64, -1, 1) < 1);
    try std.testing.expect(try uniformInclusiveChecked(rng, u32, 5, 9) <= 9);
    try std.testing.expect(try uniformInclusiveCheckedFrom(&engine, f64, -1, 1) <= 1);
    try std.testing.expect(try sampleSingleInclusive(rng, u32, 5, 9) <= 9);
    try std.testing.expect(try sampleSingleInclusiveFrom(&engine, f64, -1, 1) <= 1);
    try std.testing.expectError(error.EmptyRange, uniformCheckedFrom(&engine, u32, 9, 5));
    try std.testing.expectError(error.EmptyRange, sampleSingleFrom(&engine, u32, 9, 5));
    try std.testing.expectError(error.NonFinite, uniformInclusiveCheckedFrom(&engine, f64, std.math.inf(f64), 1));
    try std.testing.expectError(error.NonFinite, sampleSingleInclusiveFrom(&engine, f64, std.math.inf(f64), 1));
    var uniform_int_buf: [8]u32 = undefined;
    fillUniform(rng, u32, &uniform_int_buf, 5, 9);
    for (uniform_int_buf) |value| try std.testing.expect(value >= 5 and value < 9);
    fillUniformFrom(&engine, u32, &uniform_int_buf, 5, 9);
    for (uniform_int_buf) |value| try std.testing.expect(value >= 5 and value < 9);
    try fillUniformChecked(rng, u32, &uniform_int_buf, 5, 9);
    for (uniform_int_buf) |value| try std.testing.expect(value >= 5 and value < 9);
    try fillUniformCheckedFrom(&engine, u32, &uniform_int_buf, 5, 9);
    for (uniform_int_buf) |value| try std.testing.expect(value >= 5 and value < 9);
    try std.testing.expectError(error.EmptyRange, fillUniformCheckedFrom(&engine, u32, &uniform_int_buf, 9, 5));
    var uniform_float_buf: [8]f64 = undefined;
    fillUniform(rng, f64, &uniform_float_buf, -1, 1);
    for (uniform_float_buf) |value| try std.testing.expect(value >= -1 and value < 1);
    try fillUniformCheckedFrom(&engine, f64, &uniform_float_buf, -1, 1);
    for (uniform_float_buf) |value| try std.testing.expect(value >= -1 and value < 1);
    var inclusive_int_buf: [8]u32 = undefined;
    fillUniformInclusive(rng, u32, &inclusive_int_buf, 5, 9);
    for (inclusive_int_buf) |value| try std.testing.expect(value >= 5 and value <= 9);
    fillUniformInclusiveFrom(&engine, u32, &inclusive_int_buf, 5, 9);
    for (inclusive_int_buf) |value| try std.testing.expect(value >= 5 and value <= 9);
    try fillUniformInclusiveChecked(rng, u32, &inclusive_int_buf, 5, 9);
    for (inclusive_int_buf) |value| try std.testing.expect(value >= 5 and value <= 9);
    try fillUniformInclusiveCheckedFrom(&engine, u32, &inclusive_int_buf, 5, 9);
    for (inclusive_int_buf) |value| try std.testing.expect(value >= 5 and value <= 9);
    try std.testing.expectError(error.EmptyRange, fillUniformInclusiveCheckedFrom(&engine, u32, &inclusive_int_buf, 9, 5));
    const counting_source = struct {
        count: usize = 0,

        pub fn next(self: *@This()) u64 {
            self.count += 1;
            return 0;
        }
    };
    var unchecked_counter = counting_source{};
    var checked_counter = counting_source{};
    var unchecked_inclusive: [4]u32 = undefined;
    var checked_inclusive: [4]u32 = undefined;
    fillUniformInclusiveFrom(&unchecked_counter, u32, &unchecked_inclusive, 5, 5);
    try fillUniformInclusiveCheckedFrom(&checked_counter, u32, &checked_inclusive, 5, 5);
    try std.testing.expectEqual(unchecked_counter.count, checked_counter.count);
    var inclusive_float_buf: [8]f64 = undefined;
    fillUniformInclusive(rng, f64, &inclusive_float_buf, -1, 1);
    for (inclusive_float_buf) |value| try std.testing.expect(value >= -1 and value <= 1);
    try fillUniformInclusiveCheckedFrom(&engine, f64, &inclusive_float_buf, -1, 1);
    for (inclusive_float_buf) |value| try std.testing.expect(value >= -1 and value <= 1);
    try std.testing.expectError(error.NonFinite, fillUniformInclusiveCheckedFrom(&engine, f64, &inclusive_float_buf, std.math.inf(f64), 1));
    try std.testing.expect((try Bernoulli.initRatio(1, 1)).sample(rng));
    try std.testing.expect(!(try Bernoulli.init(0)).sample(rng));
    const fair_bernoulli = try Bernoulli.init(0.5);
    const fair_bernoulli_new = try Bernoulli.new(0.5);
    const ratio_bernoulli_new = try Bernoulli.newRatio(1, 4);
    const ratio_bernoulli_from = try Bernoulli.fromRatio(1, 4);
    try std.testing.expectApproxEqAbs(@as(f64, 0.5), fair_bernoulli.probability(), 1e-12);
    try std.testing.expectApproxEqAbs(fair_bernoulli.probability(), fair_bernoulli.p(), 1e-12);
    try std.testing.expectApproxEqAbs(fair_bernoulli.probability(), fair_bernoulli_new.probability(), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0.25), ratio_bernoulli_new.probability(), 1e-12);
    try std.testing.expectApproxEqAbs(ratio_bernoulli_new.probability(), ratio_bernoulli_from.probability(), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0.5), fair_bernoulli.probabilityValue(), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0.5), fair_bernoulli.expectedValue(), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0.25), fair_bernoulli.varianceValue(), 1e-12);
    try std.testing.expect(fair_bernoulli.modeValue() == null);
    try std.testing.expectEqual(false, (try Bernoulli.init(0.25)).modeValue().?);
    try std.testing.expectEqual(true, (try Bernoulli.init(0.75)).modeValue().?);
    try std.testing.expectEqual(false, fair_bernoulli.minValue());
    try std.testing.expectEqual(true, fair_bernoulli.maxValue());
    try std.testing.expect((try Bernoulli.init(1.0 - std.math.floatEps(f64) / 2.0)).sample(rng));
    try std.testing.expect(try bernoulliChecked(rng, 1.0));
    var direct_bernoulli_engine = alea.ScalarPrng.init(64);
    try std.testing.expect(bernoulliFrom(&direct_bernoulli_engine, 1.0));
    try std.testing.expect(try bernoulliCheckedFrom(&direct_bernoulli_engine, 1.0));
    try std.testing.expect(std.math.isFinite(normalFrom(&direct_bernoulli_engine, f64, 0, 1)));
    try std.testing.expect(std.math.isFinite(try normalCheckedFrom(&direct_bernoulli_engine, f64, 0, 1)));
    var top_normal_buf: [8]f64 = undefined;
    fillNormal(rng, f64, &top_normal_buf, 0, 1);
    for (top_normal_buf) |value| try std.testing.expect(std.math.isFinite(value));
    fillNormalFrom(&direct_bernoulli_engine, f64, &top_normal_buf, 0, 1);
    for (top_normal_buf) |value| try std.testing.expect(std.math.isFinite(value));
    try fillNormalChecked(rng, f64, &top_normal_buf, 0, 1);
    for (top_normal_buf) |value| try std.testing.expect(std.math.isFinite(value));
    try fillNormalCheckedFrom(&direct_bernoulli_engine, f64, &top_normal_buf, 0, 1);
    for (top_normal_buf) |value| try std.testing.expect(std.math.isFinite(value));
    try std.testing.expectError(error.InvalidParameter, fillNormalCheckedFrom(&direct_bernoulli_engine, f64, &top_normal_buf, 0, -1));
    try std.testing.expect(exponentialFrom(&direct_bernoulli_engine, f64, 2) >= 0);
    try std.testing.expect(try exponentialCheckedFrom(&direct_bernoulli_engine, f64, 2) >= 0);
    var top_exponential_buf: [8]f64 = undefined;
    fillExponential(rng, f64, &top_exponential_buf, 2);
    for (top_exponential_buf) |value| try std.testing.expect(value >= 0);
    fillExponentialFrom(&direct_bernoulli_engine, f64, &top_exponential_buf, 2);
    for (top_exponential_buf) |value| try std.testing.expect(value >= 0);
    try fillExponentialChecked(rng, f64, &top_exponential_buf, 2);
    for (top_exponential_buf) |value| try std.testing.expect(value >= 0);
    try fillExponentialCheckedFrom(&direct_bernoulli_engine, f64, &top_exponential_buf, 2);
    for (top_exponential_buf) |value| try std.testing.expect(value >= 0);
    try std.testing.expectError(error.InvalidParameter, fillExponentialCheckedFrom(&direct_bernoulli_engine, f64, &top_exponential_buf, 0));
    try std.testing.expect(poissonFrom(&direct_bernoulli_engine, 4) < 32);
    try std.testing.expect(try poissonCheckedFrom(&direct_bernoulli_engine, 4) < 32);
    try std.testing.expectError(error.InvalidParameter, poissonCheckedFrom(&direct_bernoulli_engine, std.math.inf(f64)));
    try std.testing.expect((try Bernoulli.initRatio(1, 1)).sampleFrom(&direct_bernoulli_engine));
    var bernoulli_buf: [8]bool = undefined;
    fillBernoulli(rng, &bernoulli_buf, 1);
    for (bernoulli_buf) |value| try std.testing.expect(value);
    fillBernoulliFrom(&direct_bernoulli_engine, &bernoulli_buf, 0);
    for (bernoulli_buf) |value| try std.testing.expect(!value);
    try fillBernoulliChecked(rng, &bernoulli_buf, 1);
    for (bernoulli_buf) |value| try std.testing.expect(value);
    try fillBernoulliCheckedFrom(&direct_bernoulli_engine, &bernoulli_buf, 0);
    for (bernoulli_buf) |value| try std.testing.expect(!value);
    try std.testing.expectError(error.InvalidProbability, fillBernoulliCheckedFrom(&direct_bernoulli_engine, &bernoulli_buf, -0.1));
    try std.testing.expectError(error.InvalidProbability, Bernoulli.new(-0.1));
    try std.testing.expectError(error.InvalidProbability, Bernoulli.newRatio(2, 1));
    try std.testing.expectError(error.InvalidProbability, Bernoulli.fromRatio(2, 1));
    const bernoulli_sampler = try Bernoulli.init(0.5);
    bernoulli_sampler.fillFrom(&direct_bernoulli_engine, &bernoulli_buf);
    try std.testing.expectError(error.InvalidProbability, bernoulliCheckedFrom(&direct_bernoulli_engine, 1.1));
    try std.testing.expect((try Binomial.init(10, 1)).sample(rng) == 10);
    try std.testing.expectEqual(@as(u64, 10), try binomialChecked(rng, 10, 1));
    try std.testing.expectEqual(@as(u64, 10), try binomialCheckedFrom(&direct_bernoulli_engine, 10, 1));
    try std.testing.expectError(error.InvalidProbability, binomialCheckedFrom(&direct_bernoulli_engine, 10, 1.1));
    var binomial_buf: [8]u64 = undefined;
    fillBinomial(rng, &binomial_buf, 10, 1);
    for (binomial_buf) |value| try std.testing.expectEqual(@as(u64, 10), value);
    try fillBinomialChecked(rng, &binomial_buf, 10, 1);
    for (binomial_buf) |value| try std.testing.expectEqual(@as(u64, 10), value);
    try fillBinomialCheckedFrom(&direct_bernoulli_engine, &binomial_buf, 10, 1);
    for (binomial_buf) |value| try std.testing.expectEqual(@as(u64, 10), value);
    try std.testing.expectError(error.InvalidProbability, fillBinomialCheckedFrom(&direct_bernoulli_engine, &binomial_buf, 10, 1.1));
    const binomial_sampler = try Binomial.init(10, 0.5);
    try std.testing.expectEqual(@as(u64, 10), binomial_sampler.trialsValue());
    try std.testing.expectApproxEqAbs(@as(f64, 0.5), binomial_sampler.probabilityValue(), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5), binomial_sampler.expectedValue(), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 2.5), binomial_sampler.varianceValue(), 1e-12);
    try std.testing.expectEqual(@as(u64, 0), binomial_sampler.minValue());
    try std.testing.expectEqual(@as(u64, 10), binomial_sampler.maxValue());
    binomial_sampler.fillFrom(&direct_bernoulli_engine, &binomial_buf);
    for (binomial_buf) |value| try std.testing.expect(value <= 10);
    try std.testing.expect(exponential(rng, f64, 2) >= 0);
    try std.testing.expect(poisson(rng, 4) < 32);
    try std.testing.expect(beta(rng, f64, 2, 5) >= 0);

    const die = try Uniform(u8).initInclusive(1, 6);
    const die_new = try Uniform(u8).newInclusive(1, 6);
    try std.testing.expect(die_new.isInclusive());
    try std.testing.expectEqual(die.lowValue(), die_new.lowValue());
    try std.testing.expectEqual(die.highValue(), die_new.highValue());
    const half_open_new = try Uniform(u8).new(1, 6);
    try std.testing.expect(!half_open_new.isInclusive());
    try std.testing.expectError(error.EmptyRange, Uniform(u8).new(6, 1));
    try std.testing.expectError(error.EmptyRange, Uniform(u8).newInclusive(6, 1));
    const roll = die.sample(rng);
    try std.testing.expect(roll >= 1 and roll <= 6);

    const float_edge = struct {
        value: u64,

        pub fn next(self: *@This()) u64 {
            return self.value;
        }

        pub fn fill(self: *@This(), buf: []u8) void {
            var i: usize = 0;
            while (i < buf.len) : (i += 1) {
                if ((i & 7) == 0) self.value +%= 0x9e3779b97f4a7c15;
                buf[i] = @truncate(self.value >> @intCast((i & 7) * 8));
            }
        }
    };
    var min_float_engine = float_edge{ .value = 0 };
    try std.testing.expectEqual(@as(f64, -1), uniformInclusiveFrom(&min_float_engine, f64, -1, 3));
    var max_float_engine = float_edge{ .value = std.math.maxInt(u64) };
    try std.testing.expectEqual(@as(f64, 3), uniformInclusiveFrom(&max_float_engine, f64, -1, 3));
}

test "alias table init allocation failure cleans up" {
    for (0..5) |fail_index| {
        var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = fail_index });
        try std.testing.expectError(error.OutOfMemory, AliasTable(u32).init(failing.allocator(), &.{ 1, 2, 3 }));
        try std.testing.expect(failing.has_induced_failure);
    }
}

test "alias table samples valid indexes" {
    const alea = @import("root.zig");
    var engine = alea.Wyhash64.init(44);
    const rng = Rng.init(&engine);

    var table = try AliasTable(u32).init(std.testing.allocator, &.{ 1, 0, 5, 3 });
    defer table.deinit();

    var i: usize = 0;
    while (i < 32) : (i += 1) {
        const index = table.sample(rng);
        try std.testing.expect(index < 4);
        try std.testing.expect(index != 1);
    }
    try std.testing.expect(table.sampleFrom(&engine) < 4);
    var alias_buf: [8]usize = undefined;
    table.fill(rng, &alias_buf);
    for (alias_buf) |index| {
        try std.testing.expect(index < 4);
        try std.testing.expect(index != 1);
    }
    table.fillFrom(&engine, &alias_buf);
    for (alias_buf) |index| {
        try std.testing.expect(index < 4);
        try std.testing.expect(index != 1);
    }

    try table.update(&.{ 0, 10, 0, 0 });
    i = 0;
    while (i < 16) : (i += 1) {
        try std.testing.expectEqual(@as(usize, 1), table.sampleFrom(&engine));
    }

    try std.testing.expectError(error.InvalidParameter, table.update(&.{ 1, 2 }));
    try std.testing.expectError(error.InsufficientNonZero, table.update(&.{ 0, 0, 0, 0 }));
    try std.testing.expectEqual(@as(usize, 1), table.sampleFrom(&engine));

    try std.testing.expectError(error.InvalidInput, AliasTable(u32).init(std.testing.allocator, &.{}));
    try std.testing.expectError(error.InsufficientNonZero, AliasTable(u32).init(std.testing.allocator, &.{ 0, 0 }));
}

test "alias table u32 sampling helpers mirror usize helpers" {
    const alea = @import("root.zig");
    var table = try AliasTable(u32).init(std.testing.allocator, &.{ 1, 0, 5, 3 });
    defer table.deinit();

    var usize_engine = alea.ScalarPrng.init(0x5150_a11d);
    var u32_engine = alea.ScalarPrng.init(0x5150_a11d);
    try std.testing.expectEqual(@as(u32, @intCast(table.sampleFrom(&usize_engine))), table.sampleU32From(&u32_engine));
    try std.testing.expectEqual(usize_engine.next(), u32_engine.next());

    usize_engine = alea.ScalarPrng.init(0x5150_a11e);
    u32_engine = alea.ScalarPrng.init(0x5150_a11e);
    var usize_out: [8]usize = undefined;
    var u32_out: [8]u32 = undefined;
    table.fillFrom(&usize_engine, &usize_out);
    try table.fillU32CheckedFrom(&u32_engine, &u32_out);
    for (usize_out, u32_out) |usize_index, u32_index| {
        try std.testing.expectEqual(@as(u32, @intCast(usize_index)), u32_index);
        try std.testing.expect(usize_index < 4);
        try std.testing.expect(usize_index != 1);
    }
    try std.testing.expectEqual(usize_engine.next(), u32_engine.next());

    var facade_engine = alea.ScalarPrng.init(0x5150_a11f);
    var direct_engine = alea.ScalarPrng.init(0x5150_a11f);
    const rng = Rng.init(&facade_engine);
    try std.testing.expectEqual(try table.sampleU32Checked(rng), try table.sampleU32CheckedFrom(&direct_engine));
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    var empty: [0]u32 = .{};
    try table.fillU32CheckedFrom(&direct_engine, &empty);

    try table.update(&.{ 0, 0, 5, 0 });
    var single_engine = alea.ScalarPrng.init(0x5150_a120);
    var single_control = alea.ScalarPrng.init(0x5150_a120);
    try std.testing.expectEqual(@as(u32, 2), table.sampleU32From(&single_engine));
    try std.testing.expectEqual(single_control.next(), single_engine.next());
    const single_rng = Rng.init(&single_engine);
    table.fillU32(single_rng, &u32_out);
    for (u32_out) |index| try std.testing.expectEqual(@as(u32, 2), index);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
}

test "alias table owned index batches mirror fills" {
    const alea = @import("root.zig");
    var table = try AliasTable(u32).init(std.testing.allocator, &.{ 1, 0, 5, 3 });
    defer table.deinit();

    var fill_engine = alea.ScalarPrng.init(0x5150_a121);
    var batch_engine = alea.ScalarPrng.init(0x5150_a121);
    var fill_out: [8]usize = undefined;
    table.fillFrom(&fill_engine, &fill_out);
    const batch = try table.indicesFrom(std.testing.allocator, &batch_engine, fill_out.len);
    defer std.testing.allocator.free(batch);
    try std.testing.expectEqualSlices(usize, &fill_out, batch);
    try std.testing.expectEqual(fill_engine.next(), batch_engine.next());

    fill_engine = alea.ScalarPrng.init(0x5150_a122);
    batch_engine = alea.ScalarPrng.init(0x5150_a122);
    var fill_u32: [8]u32 = undefined;
    try table.fillU32CheckedFrom(&fill_engine, &fill_u32);
    const batch_u32 = try table.indicesU32From(std.testing.allocator, &batch_engine, fill_u32.len);
    defer std.testing.allocator.free(batch_u32);
    try std.testing.expectEqualSlices(u32, &fill_u32, batch_u32);
    try std.testing.expectEqual(fill_engine.next(), batch_engine.next());

    var facade_engine = alea.ScalarPrng.init(0x5150_a123);
    var direct_engine = alea.ScalarPrng.init(0x5150_a123);
    const rng = Rng.init(&facade_engine);
    const facade_batch = try table.indices(std.testing.allocator, rng, 4);
    defer std.testing.allocator.free(facade_batch);
    const direct_batch = try table.indicesFrom(std.testing.allocator, &direct_engine, 4);
    defer std.testing.allocator.free(direct_batch);
    try std.testing.expectEqualSlices(usize, direct_batch, facade_batch);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    facade_engine = alea.ScalarPrng.init(0x5150_a140);
    direct_engine = alea.ScalarPrng.init(0x5150_a140);
    const checked_rng = Rng.init(&facade_engine);
    const checked_facade_batch = try table.indicesChecked(std.testing.allocator, checked_rng, 4);
    defer std.testing.allocator.free(checked_facade_batch);
    const checked_direct_batch = try table.indicesCheckedFrom(std.testing.allocator, &direct_engine, 4);
    defer std.testing.allocator.free(checked_direct_batch);
    try std.testing.expectEqualSlices(usize, checked_direct_batch, checked_facade_batch);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    const zero_batch = try table.indicesFrom(std.testing.allocator, &batch_engine, 0);
    defer std.testing.allocator.free(zero_batch);
    try std.testing.expectEqual(@as(usize, 0), zero_batch.len);
    const zero_checked_batch = try table.indicesCheckedFrom(std.testing.allocator, &batch_engine, 0);
    defer std.testing.allocator.free(zero_checked_batch);
    try std.testing.expectEqual(@as(usize, 0), zero_checked_batch.len);
    const zero_u32_batch = try table.indicesU32From(std.testing.allocator, &batch_engine, 0);
    defer std.testing.allocator.free(zero_u32_batch);
    try std.testing.expectEqual(@as(usize, 0), zero_u32_batch.len);

    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.OutOfMemory, table.indicesFrom(failing.allocator(), &batch_engine, 4));
    try std.testing.expect(failing.has_induced_failure);

    try table.update(&.{ 0, 0, 5, 0 });
    var single_engine = alea.ScalarPrng.init(0x5150_a124);
    var single_control = alea.ScalarPrng.init(0x5150_a124);
    const single_batch = try table.indicesFrom(std.testing.allocator, &single_engine, 4);
    defer std.testing.allocator.free(single_batch);
    try std.testing.expectEqualSlices(usize, &.{ 2, 2, 2, 2 }, single_batch);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
    const single_batch_u32 = try table.indicesU32From(std.testing.allocator, &single_engine, 4);
    defer std.testing.allocator.free(single_batch_u32);
    try std.testing.expectEqualSlices(u32, &.{ 2, 2, 2, 2 }, single_batch_u32);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
}

test "alias table index aliases mirror sample helpers" {
    const alea = @import("root.zig");
    var table = try AliasTable(u32).init(std.testing.allocator, &.{ 1, 0, 5, 3 });
    defer table.deinit();

    var sample_engine = alea.ScalarPrng.init(0x5150_a125);
    var alias_engine = alea.ScalarPrng.init(0x5150_a125);
    try std.testing.expectEqual(table.sampleFrom(&sample_engine), table.sampleIndexFrom(&alias_engine));
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_a126);
    alias_engine = alea.ScalarPrng.init(0x5150_a126);
    try std.testing.expectEqual(table.sampleU32From(&sample_engine), table.sampleIndexU32From(&alias_engine));
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_a13d);
    alias_engine = alea.ScalarPrng.init(0x5150_a13d);
    try std.testing.expectEqual(try table.sampleCheckedFrom(&sample_engine), try table.sampleIndexCheckedFrom(&alias_engine));
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    var facade_engine = alea.ScalarPrng.init(0x5150_a127);
    var direct_engine = alea.ScalarPrng.init(0x5150_a127);
    const rng = Rng.init(&facade_engine);
    const direct_rng = Rng.init(&direct_engine);
    try std.testing.expectEqual(table.sampleIndex(rng), table.sample(direct_rng));
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    facade_engine = alea.ScalarPrng.init(0x5150_a13e);
    direct_engine = alea.ScalarPrng.init(0x5150_a13e);
    const checked_rng = Rng.init(&facade_engine);
    const checked_direct_rng = Rng.init(&direct_engine);
    try std.testing.expectEqual(try table.sampleIndexChecked(checked_rng), try table.sampleChecked(checked_direct_rng));
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    facade_engine = alea.ScalarPrng.init(0x5150_a128);
    direct_engine = alea.ScalarPrng.init(0x5150_a128);
    const u32_rng = Rng.init(&facade_engine);
    try std.testing.expectEqual(try table.sampleIndexU32Checked(u32_rng), try table.sampleU32CheckedFrom(&direct_engine));
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_a129);
    alias_engine = alea.ScalarPrng.init(0x5150_a129);
    var fill_out: [8]usize = undefined;
    var alias_fill_out: [8]usize = undefined;
    table.fillFrom(&sample_engine, &fill_out);
    table.fillIndicesFrom(&alias_engine, &alias_fill_out);
    try std.testing.expectEqualSlices(usize, &fill_out, &alias_fill_out);
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_a13f);
    alias_engine = alea.ScalarPrng.init(0x5150_a13f);
    try table.fillCheckedFrom(&sample_engine, &fill_out);
    try table.fillIndicesCheckedFrom(&alias_engine, &alias_fill_out);
    try std.testing.expectEqualSlices(usize, &fill_out, &alias_fill_out);
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_a12a);
    alias_engine = alea.ScalarPrng.init(0x5150_a12a);
    var fill_u32: [8]u32 = undefined;
    var alias_fill_u32: [8]u32 = undefined;
    try table.fillU32CheckedFrom(&sample_engine, &fill_u32);
    try table.fillIndicesU32CheckedFrom(&alias_engine, &alias_fill_u32);
    try std.testing.expectEqualSlices(u32, &fill_u32, &alias_fill_u32);
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    try table.update(&.{ 0, 0, 5, 0 });
    var single_engine = alea.ScalarPrng.init(0x5150_a12b);
    var single_control = alea.ScalarPrng.init(0x5150_a12b);
    try std.testing.expectEqual(@as(usize, 2), table.sampleIndexFrom(&single_engine));
    try std.testing.expectEqual(single_control.next(), single_engine.next());
    table.fillIndicesFrom(&single_engine, &alias_fill_out);
    for (alias_fill_out) |index| try std.testing.expectEqual(@as(usize, 2), index);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
    try table.fillIndicesU32CheckedFrom(&single_engine, &alias_fill_u32);
    for (alias_fill_u32) |index| try std.testing.expectEqual(@as(u32, 2), index);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
}

test "alias table iterators produce repeated indices" {
    const alea = @import("root.zig");
    var table = try AliasTable(u32).init(std.testing.allocator, &.{ 1, 0, 5, 3 });
    defer table.deinit();

    var sample_engine = alea.ScalarPrng.init(0x5150_a12c);
    var iter_engine = alea.ScalarPrng.init(0x5150_a12c);
    var iter = table.iterFrom(&iter_engine);
    var i: usize = 0;
    while (i < 8) : (i += 1) {
        try std.testing.expectEqual(table.sampleFrom(&sample_engine), iter.next().?);
    }
    try std.testing.expectEqual(sample_engine.next(), iter_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_a12d);
    iter_engine = alea.ScalarPrng.init(0x5150_a12d);
    var fill_out: [8]usize = undefined;
    var iter_fill_out: [8]usize = undefined;
    table.fillFrom(&sample_engine, &fill_out);
    var fill_iter = table.iterFrom(&iter_engine);
    fill_iter.fill(&iter_fill_out);
    try std.testing.expectEqualSlices(usize, &fill_out, &iter_fill_out);
    try std.testing.expectEqual(sample_engine.next(), iter_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_a12e);
    iter_engine = alea.ScalarPrng.init(0x5150_a12e);
    var fill_u32: [8]u32 = undefined;
    var iter_fill_u32: [8]u32 = undefined;
    try table.fillU32CheckedFrom(&sample_engine, &fill_u32);
    var u32_iter = table.iterU32From(&iter_engine);
    u32_iter.fill(&iter_fill_u32);
    try std.testing.expectEqualSlices(u32, &fill_u32, &iter_fill_u32);
    try std.testing.expectEqual(sample_engine.next(), iter_engine.next());

    var checked_iter_engine = alea.ScalarPrng.init(0x5150_a138);
    var unchecked_iter_engine = alea.ScalarPrng.init(0x5150_a138);
    var checked_iter = try table.iterCheckedFrom(&checked_iter_engine);
    var unchecked_iter = table.iterFrom(&unchecked_iter_engine);
    try std.testing.expectEqual(unchecked_iter.next().?, checked_iter.next().?);
    try std.testing.expectEqual(unchecked_iter_engine.next(), checked_iter_engine.next());

    var checked_facade_iter_engine = alea.ScalarPrng.init(0x5150_a141);
    var checked_direct_iter_engine = alea.ScalarPrng.init(0x5150_a141);
    var checked_facade_iter = try table.iterChecked(Rng.init(&checked_facade_iter_engine));
    var checked_direct_iter = try table.iterCheckedFrom(&checked_direct_iter_engine);
    try std.testing.expectEqual(checked_direct_iter.next().?, checked_facade_iter.next().?);
    try std.testing.expectEqual(checked_direct_iter_engine.next(), checked_facade_iter_engine.next());

    var facade_engine = alea.ScalarPrng.init(0x5150_a12f);
    var direct_engine = alea.ScalarPrng.init(0x5150_a12f);
    const rng = Rng.init(&facade_engine);
    var facade_iter = table.iter(rng);
    var direct_iter = table.iterFrom(&direct_engine);
    try std.testing.expectEqual(facade_iter.next().?, direct_iter.next().?);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    facade_engine = alea.ScalarPrng.init(0x5150_a130);
    direct_engine = alea.ScalarPrng.init(0x5150_a130);
    const u32_rng = Rng.init(&facade_engine);
    var facade_u32_iter = table.iterU32(u32_rng);
    var direct_u32_iter = table.iterU32From(&direct_engine);
    try std.testing.expectEqual(facade_u32_iter.next().?, direct_u32_iter.next().?);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    var checked_u32_iter_engine = alea.ScalarPrng.init(0x5150_a139);
    var unchecked_u32_iter_engine = alea.ScalarPrng.init(0x5150_a139);
    var checked_u32_iter = try table.iterU32CheckedFrom(&checked_u32_iter_engine);
    var unchecked_u32_iter = table.iterU32From(&unchecked_u32_iter_engine);
    try std.testing.expectEqual(unchecked_u32_iter.next().?, checked_u32_iter.next().?);
    try std.testing.expectEqual(unchecked_u32_iter_engine.next(), checked_u32_iter_engine.next());

    var checked_u32_facade_iter_engine = alea.ScalarPrng.init(0x5150_a142);
    var checked_u32_direct_iter_engine = alea.ScalarPrng.init(0x5150_a142);
    var checked_u32_facade_iter = try table.iterU32Checked(Rng.init(&checked_u32_facade_iter_engine));
    var checked_u32_direct_iter = try table.iterU32CheckedFrom(&checked_u32_direct_iter_engine);
    try std.testing.expectEqual(checked_u32_direct_iter.next().?, checked_u32_facade_iter.next().?);
    try std.testing.expectEqual(checked_u32_direct_iter_engine.next(), checked_u32_facade_iter_engine.next());

    var checked_indices_u32_engine = alea.ScalarPrng.init(0x5150_a13b);
    var unchecked_indices_u32_engine = alea.ScalarPrng.init(0x5150_a13b);
    const unchecked_indices_u32 = try table.indicesU32From(std.testing.allocator, &unchecked_indices_u32_engine, 8);
    defer std.testing.allocator.free(unchecked_indices_u32);
    const checked_indices_u32 = try table.indicesU32CheckedFrom(std.testing.allocator, &checked_indices_u32_engine, 8);
    defer std.testing.allocator.free(checked_indices_u32);
    try std.testing.expectEqualSlices(u32, unchecked_indices_u32, checked_indices_u32);
    try std.testing.expectEqual(unchecked_indices_u32_engine.next(), checked_indices_u32_engine.next());

    const huge_len = @as(usize, std.math.maxInt(u32)) + 1;
    const huge_table = AliasTable(u32){
        .prob = @as([*]f64, @ptrFromInt(0x1000))[0..huge_len],
        .prob_threshold = @as([*]u64, @ptrFromInt(0x2000))[0..huge_len],
        .alias = @as([*]usize, @ptrFromInt(0x3000))[0..huge_len],
        .weight_values = @as([*]f64, @ptrFromInt(0x4000))[0..huge_len],
        .total = 1,
        .positive_count = 1,
        .constant_index = 0,
        .allocator = std.testing.allocator,
    };
    var huge_engine = alea.ScalarPrng.init(0x5150_a13a);
    var huge_control = alea.ScalarPrng.init(0x5150_a13a);
    try std.testing.expectError(error.InvalidParameter, huge_table.iterU32CheckedFrom(&huge_engine));
    try std.testing.expectEqual(huge_control.next(), huge_engine.next());
    var huge_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidParameter, huge_table.indicesU32From(huge_alloc.allocator(), &huge_engine, 1));
    try std.testing.expect(!huge_alloc.has_induced_failure);
    try std.testing.expectEqual(huge_control.next(), huge_engine.next());
    var huge_checked_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidParameter, huge_table.indicesU32CheckedFrom(huge_checked_alloc.allocator(), &huge_engine, 1));
    try std.testing.expect(!huge_checked_alloc.has_induced_failure);
    try std.testing.expectEqual(huge_control.next(), huge_engine.next());

    try table.update(&.{ 0, 0, 5, 0 });
    var single_engine = alea.ScalarPrng.init(0x5150_a131);
    var single_control = alea.ScalarPrng.init(0x5150_a131);
    var single_iter = table.iterFrom(&single_engine);
    var single_out: [4]usize = undefined;
    single_iter.fill(&single_out);
    try std.testing.expectEqualSlices(usize, &.{ 2, 2, 2, 2 }, &single_out);
    try std.testing.expectEqual(single_control.next(), single_engine.next());

    var single_u32_iter = table.iterU32From(&single_engine);
    var single_u32_out: [4]u32 = undefined;
    single_u32_iter.fill(&single_u32_out);
    try std.testing.expectEqualSlices(u32, &.{ 2, 2, 2, 2 }, &single_u32_out);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
}

test "alias table fixed index arrays mirror fills" {
    const alea = @import("root.zig");
    var table = try AliasTable(u32).init(std.testing.allocator, &.{ 1, 0, 5, 3 });
    defer table.deinit();

    var fill_engine = alea.ScalarPrng.init(0x5150_a134);
    var array_engine = alea.ScalarPrng.init(0x5150_a134);
    var fill_out: [6]usize = undefined;
    table.fillFrom(&fill_engine, &fill_out);
    const array_out = table.indexArrayFrom(&array_engine, 6);
    try std.testing.expectEqualSlices(usize, &fill_out, &array_out);
    try std.testing.expectEqual(fill_engine.next(), array_engine.next());

    fill_engine = alea.ScalarPrng.init(0x5150_a135);
    array_engine = alea.ScalarPrng.init(0x5150_a135);
    var fill_u32: [6]u32 = undefined;
    try table.fillU32CheckedFrom(&fill_engine, &fill_u32);
    const array_u32 = try table.indexArrayU32CheckedFrom(&array_engine, 6);
    try std.testing.expectEqualSlices(u32, &fill_u32, &array_u32);
    try std.testing.expectEqual(fill_engine.next(), array_engine.next());

    var facade_engine = alea.ScalarPrng.init(0x5150_a136);
    var direct_engine = alea.ScalarPrng.init(0x5150_a136);
    const rng = Rng.init(&facade_engine);
    const facade_array = table.indexArray(rng, 4);
    const direct_array = table.indexArrayFrom(&direct_engine, 4);
    try std.testing.expectEqualSlices(usize, &direct_array, &facade_array);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    facade_engine = alea.ScalarPrng.init(0x5150_a13c);
    direct_engine = alea.ScalarPrng.init(0x5150_a13c);
    const checked_rng = Rng.init(&facade_engine);
    const checked_facade_array = try table.indexArrayChecked(checked_rng, 4);
    const checked_direct_array = try table.indexArrayCheckedFrom(&direct_engine, 4);
    try std.testing.expectEqualSlices(usize, &checked_direct_array, &checked_facade_array);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    const empty_array = table.indexArrayFrom(&direct_engine, 0);
    try std.testing.expectEqual(@as(usize, 0), empty_array.len);
    const empty_checked_array = try table.indexArrayCheckedFrom(&direct_engine, 0);
    try std.testing.expectEqual(@as(usize, 0), empty_checked_array.len);
    const empty_u32_array = try table.indexArrayU32CheckedFrom(&direct_engine, 0);
    try std.testing.expectEqual(@as(usize, 0), empty_u32_array.len);

    try table.update(&.{ 0, 0, 5, 0 });
    var single_engine = alea.ScalarPrng.init(0x5150_a137);
    var single_control = alea.ScalarPrng.init(0x5150_a137);
    const single_array = table.indexArrayFrom(&single_engine, 4);
    try std.testing.expectEqualSlices(usize, &.{ 2, 2, 2, 2 }, &single_array);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
    const single_u32_array = try table.indexArrayU32CheckedFrom(&single_engine, 4);
    try std.testing.expectEqualSlices(u32, &.{ 2, 2, 2, 2 }, &single_u32_array);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
}

test "alias table index accessors initialize and update tables" {
    const alea = @import("root.zig");
    const IndexWeight = struct {
        fn weight(index: usize) u32 {
            return switch (index) {
                0 => 1,
                2 => 5,
                3 => 3,
                else => 0,
            };
        }

        fn floatWeight(index: usize) f64 {
            return @floatFromInt(weight(index));
        }

        fn updated(index: usize) u32 {
            return if (index == 1) 9 else 0;
        }

        fn invalid(index: usize) f64 {
            return if (index == 2) std.math.nan(f64) else 1;
        }
    };

    var table = try AliasTable(u32).initByIndex(std.testing.allocator, 4, IndexWeight.weight);
    defer table.deinit();
    try std.testing.expectEqual(@as(usize, 4), table.len());
    try std.testing.expectApproxEqAbs(@as(f64, 9), table.totalWeight(), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 1), try table.weightAt(0), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), try table.weightAt(1), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5), try table.weightAt(2), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 3), try table.weightAt(3), 1e-12);

    var engine = alea.ScalarPrng.init(0x5150_a132);
    var saw_two = false;
    var i: usize = 0;
    while (i < 32) : (i += 1) {
        const index = table.sampleFrom(&engine);
        try std.testing.expect(index == 0 or index == 2 or index == 3);
        saw_two = saw_two or index == 2;
    }
    try std.testing.expect(saw_two);

    try table.updateByIndex(IndexWeight.updated);
    try std.testing.expectEqual(@as(usize, 1), table.positiveCount());
    try std.testing.expectEqual(@as(?usize, 1), table.constantIndex());
    try std.testing.expectApproxEqAbs(@as(f64, 9), table.totalWeight(), 1e-12);
    try std.testing.expectEqual(@as(usize, 1), table.sampleFrom(&engine));

    try std.testing.expectError(error.InvalidWeight, AliasTable(f64).initByIndex(std.testing.allocator, 4, IndexWeight.invalid));
    var float_table = try AliasTable(f64).initByIndex(std.testing.allocator, 4, IndexWeight.floatWeight);
    defer float_table.deinit();
    try std.testing.expectError(error.InvalidWeight, float_table.updateByIndex(IndexWeight.invalid));
    try std.testing.expectEqual(@as(usize, 3), float_table.positiveCount());
    try std.testing.expectApproxEqAbs(@as(f64, 9), float_table.totalWeight(), 1e-12);
    try std.testing.expectEqual(@as(?usize, 1), table.constantIndex());
    try std.testing.expectEqual(@as(usize, 1), table.sampleFrom(&engine));

    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.OutOfMemory, AliasTable(u32).initByIndex(failing.allocator(), 4, IndexWeight.weight));
    try std.testing.expect(failing.has_induced_failure);
}

test "alias table item accessors initialize and update tables" {
    const alea = @import("root.zig");
    const Entry = struct {
        label: []const u8,
        weight_value: u32,
        float_weight: f64,

        fn weight(item: *const @This()) u32 {
            return item.weight_value;
        }

        fn updated(item: *const @This()) u32 {
            return if (std.mem.eql(u8, item.label, "rare")) 9 else 0;
        }

        fn floatWeight(item: *const @This()) f64 {
            return item.float_weight;
        }

        fn invalid(item: *const @This()) f64 {
            return if (std.mem.eql(u8, item.label, "often")) std.math.nan(f64) else item.float_weight;
        }
    };
    const entries = [_]Entry{
        .{ .label = "never", .weight_value = 1, .float_weight = 1 },
        .{ .label = "rare", .weight_value = 0, .float_weight = 0 },
        .{ .label = "often", .weight_value = 5, .float_weight = 5 },
        .{ .label = "bonus", .weight_value = 3, .float_weight = 3 },
    };

    var table = try AliasTable(u32).initBy(std.testing.allocator, Entry, &entries, Entry.weight);
    defer table.deinit();
    try std.testing.expectEqual(@as(usize, 4), table.len());
    try std.testing.expectApproxEqAbs(@as(f64, 9), table.totalWeight(), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 1), try table.weightAt(0), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), try table.weightAt(1), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5), try table.weightAt(2), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 3), try table.weightAt(3), 1e-12);

    var engine = alea.ScalarPrng.init(0x5150_a133);
    var saw_often = false;
    var i: usize = 0;
    while (i < 32) : (i += 1) {
        const index = table.sampleFrom(&engine);
        try std.testing.expect(index == 0 or index == 2 or index == 3);
        saw_often = saw_often or index == 2;
    }
    try std.testing.expect(saw_often);

    try table.updateBy(Entry, &entries, Entry.updated);
    try std.testing.expectEqual(@as(usize, 1), table.positiveCount());
    try std.testing.expectEqual(@as(?usize, 1), table.constantIndex());
    try std.testing.expectApproxEqAbs(@as(f64, 9), table.totalWeight(), 1e-12);
    try std.testing.expectEqual(@as(usize, 1), table.sampleFrom(&engine));

    try std.testing.expectError(error.InvalidWeight, AliasTable(f64).initBy(std.testing.allocator, Entry, &entries, Entry.invalid));
    var float_table = try AliasTable(f64).initBy(std.testing.allocator, Entry, &entries, Entry.floatWeight);
    defer float_table.deinit();
    try std.testing.expectError(error.InvalidWeight, float_table.updateBy(Entry, &entries, Entry.invalid));
    try std.testing.expectEqual(@as(usize, 3), float_table.positiveCount());
    try std.testing.expectApproxEqAbs(@as(f64, 9), float_table.totalWeight(), 1e-12);
    try std.testing.expectError(error.InvalidParameter, table.updateBy(Entry, entries[0..3], Entry.updated));
    try std.testing.expectEqual(@as(?usize, 1), table.constantIndex());

    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.OutOfMemory, AliasTable(u32).initBy(failing.allocator(), Entry, &entries, Entry.weight));
    try std.testing.expect(failing.has_induced_failure);
}

test "alias table exposes totals and reconstructs weights" {
    const root = @import("root.zig");

    var table = try AliasTable(u32).init(std.testing.allocator, &.{ 1, 0, 5, 3 });
    defer table.deinit();
    var new_table = try AliasTable(u32).new(std.testing.allocator, &.{ 1, 0, 5, 3 });
    defer new_table.deinit();

    try std.testing.expectEqual(@as(usize, 4), table.len());
    try std.testing.expectEqual(@as(usize, 4), table.numChoices());
    try std.testing.expectEqual(@as(usize, 4), new_table.numChoices());
    try std.testing.expectApproxEqAbs(table.totalWeight(), new_table.totalWeight(), 1e-12);
    try std.testing.expectEqual(@as(usize, 3), table.positiveCount());
    try std.testing.expect(!table.isEmpty());
    try std.testing.expectApproxEqAbs(@as(f64, 9), table.totalWeight(), 1e-12);

    var stack_weights: [4]f64 = undefined;
    try table.weightsInto(&stack_weights);
    try std.testing.expectApproxEqAbs(@as(f64, 1), stack_weights[0], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), stack_weights[1], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5), stack_weights[2], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 3), stack_weights[3], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 1), try table.weightAt(0), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), try table.weightAt(1), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5), try table.weightAt(2), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 3), try table.weightAt(3), 1e-12);
    try std.testing.expectError(error.InvalidParameter, table.weightAt(4));
    try std.testing.expectApproxEqAbs(@as(f64, 1), table.weight(0).?, 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), table.weight(1).?, 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5), table.weight(2).?, 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 3), table.weight(3).?, 1e-12);
    try std.testing.expectEqual(@as(?f64, null), table.weight(4));
    var weight_iter = table.weightIter();
    try std.testing.expectEqual(@as(usize, 4), weight_iter.len());
    var weight_hint = weight_iter.sizeHint();
    try std.testing.expectEqual(@as(usize, 4), weight_hint.lower);
    try std.testing.expectEqual(@as(?usize, 4), weight_hint.upper);
    try std.testing.expectApproxEqAbs(@as(f64, 1), weight_iter.next().?, 1e-12);
    try std.testing.expectEqual(@as(usize, 3), weight_iter.remaining());
    weight_hint = weight_iter.sizeHint();
    try std.testing.expectEqual(@as(usize, 3), weight_hint.lower);
    try std.testing.expectEqual(@as(?usize, 3), weight_hint.upper);
    var iter_weights: [3]f64 = undefined;
    try std.testing.expectEqual(@as(usize, 3), weight_iter.fill(&iter_weights));
    try std.testing.expectApproxEqAbs(@as(f64, 0), iter_weights[0], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5), iter_weights[1], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 3), iter_weights[2], 1e-12);
    try std.testing.expectEqual(@as(usize, 0), weight_iter.len());
    weight_hint = weight_iter.sizeHint();
    try std.testing.expectEqual(@as(usize, 0), weight_hint.lower);
    try std.testing.expectEqual(@as(?usize, 0), weight_hint.upper);
    try std.testing.expectEqual(@as(?f64, null), weight_iter.next());
    try std.testing.expectApproxEqAbs(@as(f64, 1.0 / 9.0), try table.probabilityAt(0), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), try table.probabilityAt(1), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5.0 / 9.0), try table.probabilityAt(2), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 1.0 / 3.0), try table.probabilityAt(3), 1e-12);
    try std.testing.expectError(error.InvalidParameter, table.probabilityAt(4));
    try std.testing.expectApproxEqAbs(@as(f64, 1.0 / 9.0), table.probability(0).?, 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), table.probability(1).?, 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5.0 / 9.0), table.probability(2).?, 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 1.0 / 3.0), table.probability(3).?, 1e-12);
    try std.testing.expectEqual(@as(?f64, null), table.probability(4));
    var probability_iter = table.probabilityIter();
    try std.testing.expectEqual(@as(usize, 4), probability_iter.len());
    var probability_hint = probability_iter.sizeHint();
    try std.testing.expectEqual(@as(usize, 4), probability_hint.lower);
    try std.testing.expectEqual(@as(?usize, 4), probability_hint.upper);
    try std.testing.expectApproxEqAbs(@as(f64, 1.0 / 9.0), probability_iter.next().?, 1e-12);
    try std.testing.expectEqual(@as(usize, 3), probability_iter.remaining());
    probability_hint = probability_iter.sizeHint();
    try std.testing.expectEqual(@as(usize, 3), probability_hint.lower);
    try std.testing.expectEqual(@as(?usize, 3), probability_hint.upper);
    var iter_probabilities: [3]f64 = undefined;
    try std.testing.expectEqual(@as(usize, 3), probability_iter.fill(&iter_probabilities));
    try std.testing.expectApproxEqAbs(@as(f64, 0), iter_probabilities[0], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5.0 / 9.0), iter_probabilities[1], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 1.0 / 3.0), iter_probabilities[2], 1e-12);
    try std.testing.expectEqual(@as(usize, 0), probability_iter.len());
    probability_hint = probability_iter.sizeHint();
    try std.testing.expectEqual(@as(usize, 0), probability_hint.lower);
    try std.testing.expectEqual(@as(?usize, 0), probability_hint.upper);
    try std.testing.expectEqual(@as(?f64, null), probability_iter.next());
    var stack_probabilities: [4]f64 = undefined;
    try table.probabilitiesInto(&stack_probabilities);
    try std.testing.expectApproxEqAbs(@as(f64, 1.0 / 9.0), stack_probabilities[0], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), stack_probabilities[1], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 5.0 / 9.0), stack_probabilities[2], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 1.0 / 3.0), stack_probabilities[3], 1e-12);

    var wrong_len: [3]f64 = undefined;
    try std.testing.expectError(error.InvalidLength, table.weightsInto(&wrong_len));
    try std.testing.expectError(error.InvalidLength, table.probabilitiesInto(&wrong_len));

    const owned_weights = try table.weights(std.testing.allocator);
    defer std.testing.allocator.free(owned_weights);
    try std.testing.expectEqualSlices(f64, &stack_weights, owned_weights);
    const owned_probabilities = try table.probabilities(std.testing.allocator);
    defer std.testing.allocator.free(owned_probabilities);
    try std.testing.expectEqualSlices(f64, &stack_probabilities, owned_probabilities);

    var direct_fill_engine = root.DefaultPrng.init(0xa11a_f110);
    var scalar_engine = root.DefaultPrng.init(0xa11a_f110);
    var direct_fill: [8]usize = undefined;
    var scalar_fill: [8]usize = undefined;
    table.fillFrom(&direct_fill_engine, &direct_fill);
    for (&scalar_fill) |*slot| slot.* = table.sampleFrom(&scalar_engine);
    try std.testing.expectEqualSlices(usize, &scalar_fill, &direct_fill);
    try std.testing.expectEqual(direct_fill_engine.next(), scalar_engine.next());

    var direct_u32_engine = root.DefaultPrng.init(0xa11a_f111);
    var scalar_u32_engine = root.DefaultPrng.init(0xa11a_f111);
    var direct_u32: [8]u32 = undefined;
    var scalar_u32: [8]u32 = undefined;
    try table.fillU32CheckedFrom(&direct_u32_engine, &direct_u32);
    for (&scalar_u32) |*slot| slot.* = try table.sampleU32CheckedFrom(&scalar_u32_engine);
    try std.testing.expectEqualSlices(u32, &scalar_u32, &direct_u32);
    try std.testing.expectEqual(direct_u32_engine.next(), scalar_u32_engine.next());
    var iter_u32_engine = root.DefaultPrng.init(0xa11a_f114);
    var scalar_iter_u32_engine = root.DefaultPrng.init(0xa11a_f114);
    var iter_u32 = table.iterU32From(&iter_u32_engine);
    try std.testing.expectEqual(try table.sampleU32CheckedFrom(&scalar_iter_u32_engine), iter_u32.next().?);
    try std.testing.expectEqual(iter_u32_engine.next(), scalar_iter_u32_engine.next());

    var non_power_table = try AliasTable(u32).init(std.testing.allocator, &.{ 1, 2, 5 });
    defer non_power_table.deinit();
    var non_power_direct_engine = root.DefaultPrng.init(0xa11a_f112);
    var non_power_scalar_engine = root.DefaultPrng.init(0xa11a_f112);
    var non_power_direct: [8]usize = undefined;
    var non_power_scalar: [8]usize = undefined;
    non_power_table.fillFrom(&non_power_direct_engine, &non_power_direct);
    for (&non_power_scalar) |*slot| slot.* = non_power_table.sampleFrom(&non_power_scalar_engine);
    try std.testing.expectEqualSlices(usize, &non_power_scalar, &non_power_direct);
    try std.testing.expectEqual(non_power_direct_engine.next(), non_power_scalar_engine.next());

    var non_power_direct_u32_engine = root.DefaultPrng.init(0xa11a_f113);
    var non_power_scalar_u32_engine = root.DefaultPrng.init(0xa11a_f113);
    var non_power_direct_u32: [8]u32 = undefined;
    var non_power_scalar_u32: [8]u32 = undefined;
    try non_power_table.fillU32CheckedFrom(&non_power_direct_u32_engine, &non_power_direct_u32);
    for (&non_power_scalar_u32) |*slot| slot.* = try non_power_table.sampleU32CheckedFrom(&non_power_scalar_u32_engine);
    try std.testing.expectEqualSlices(u32, &non_power_scalar_u32, &non_power_direct_u32);
    try std.testing.expectEqual(non_power_direct_u32_engine.next(), non_power_scalar_u32_engine.next());

    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.OutOfMemory, table.weights(failing.allocator()));
    try std.testing.expect(failing.has_induced_failure);

    try table.update(&.{ 0, 10, 0, 0 });
    try std.testing.expectEqual(@as(usize, 4), table.len());
    try std.testing.expectEqual(@as(usize, 1), table.positiveCount());
    try std.testing.expectApproxEqAbs(@as(f64, 10), table.totalWeight(), 1e-12);
    try table.weightsInto(&stack_weights);
    try std.testing.expectApproxEqAbs(@as(f64, 0), stack_weights[0], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 10), stack_weights[1], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), stack_weights[2], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), stack_weights[3], 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 10), try table.weightAt(1), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 10), table.weight(1).?, 1e-12);
}

test "zero-length alias table fills do not consume random stream" {
    const alea = @import("root.zig");
    var engine = alea.ScalarPrng.init(0x5150_a11b);
    var control = alea.ScalarPrng.init(0x5150_a11b);
    const rng = Rng.init(&engine);

    var table = try AliasTable(u32).init(std.testing.allocator, &.{ 1, 0, 5, 3 });
    defer table.deinit();

    var empty: [0]usize = .{};
    table.fill(rng, &empty);
    try std.testing.expectEqual(control.next(), engine.next());
    table.fillFrom(&engine, &empty);
    try std.testing.expectEqual(control.next(), engine.next());
}

test "single-positive alias table does not consume random stream" {
    const alea = @import("root.zig");
    var engine = alea.ScalarPrng.init(0x5150_a11c);
    var control = alea.ScalarPrng.init(0x5150_a11c);
    const rng = Rng.init(&engine);

    var table = try AliasTable(u32).init(std.testing.allocator, &.{ 0, 0, 5, 0 });
    defer table.deinit();
    try std.testing.expectEqual(@as(?usize, 2), table.constantIndex());

    try std.testing.expectEqual(@as(usize, 2), table.sampleFrom(&engine));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(@as(usize, 2), table.sample(rng));
    try std.testing.expectEqual(control.next(), engine.next());

    var out: [5]usize = undefined;
    table.fillFrom(&engine, &out);
    for (out) |index| try std.testing.expectEqual(@as(usize, 2), index);
    try std.testing.expectEqual(control.next(), engine.next());

    table.fill(rng, &out);
    for (out) |index| try std.testing.expectEqual(@as(usize, 2), index);
    try std.testing.expectEqual(control.next(), engine.next());

    try table.update(&.{ 0, 7, 0, 0 });
    try std.testing.expectEqual(@as(?usize, 1), table.constantIndex());
    try std.testing.expectEqual(@as(usize, 1), table.sampleFrom(&engine));
    try std.testing.expectEqual(control.next(), engine.next());

    try table.update(&.{ 1, 7, 0, 0 });
    try std.testing.expect(table.constantIndex() == null);
}

test "alias table update allocation failure preserves table" {
    const alea = @import("root.zig");

    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{});
    var table = try AliasTable(u32).init(failing.allocator(), &.{ 0, 0, 1 });
    defer table.deinit();

    var engine = alea.ScalarPrng.init(0x5150_a11a);
    var control = alea.ScalarPrng.init(0x5150_a11a);
    failing.fail_index = failing.alloc_index;
    try std.testing.expectError(error.OutOfMemory, table.update(&.{ 1, 2, 3 }));
    try std.testing.expect(failing.has_induced_failure);
    try std.testing.expectEqual(control.next(), engine.next());

    var out: [8]usize = undefined;
    table.fillFrom(&engine, &out);
    for (out) |index| try std.testing.expectEqual(@as(usize, 2), index);
}

