    try std.testing.expectApproxEqAbs(@as(f64, 7), try tree.weightAt(2), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0), try tree.weightAt(3), 1e-12);

    var engine = alea.ScalarPrng.init(0x5150_d502);
    var saw_often = false;
    var i: usize = 0;
    while (i < 32) : (i += 1) {
