    try std.testing.expectEqual(@as(u64, 0), try int_tree.weightAt(0));
    try std.testing.expectEqual(@as(u64, 2), try int_tree.weightAt(1));
    try std.testing.expectEqual(@as(u64, 0), try int_tree.weightAt(2));
