    try std.testing.expectEqual(fill_engine.next(), batch_engine.next());

    var rng_engine = alea.ScalarPrng.init(0x5150_d50b);
    const rng = Rng.init(&rng_engine);
    const facade_batch = try tree.indicesChecked(std.testing.allocator, rng, 4);
    defer std.testing.allocator.free(facade_batch);
    try std.testing.expectEqual(@as(usize, 4), facade_batch.len);
    for (facade_batch) |index| try std.testing.expect(index == 0 or index == 2 or index == 3);

    const zero_batch = try tree.indicesCheckedFrom(std.testing.allocator, &batch_engine, 0);
    defer std.testing.allocator.free(zero_batch);
    try std.testing.expectEqual(@as(usize, 0), zero_batch.len);
    const zero_u32_batch = try tree.indicesU32CheckedFrom(std.testing.allocator, &batch_engine, 0);
    defer std.testing.allocator.free(zero_u32_batch);
    try std.testing.expectEqual(@as(usize, 0), zero_u32_batch.len);

    var failing = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.OutOfMemory, tree.indicesCheckedFrom(failing.allocator(), &batch_engine, 4));
    try std.testing.expect(failing.has_induced_failure);

    var invalid_tree = try WeightedTree(u32).init(std.testing.allocator, &.{ 0, 0 });
    defer invalid_tree.deinit();
    try std.testing.expectError(error.InvalidWeight, invalid_tree.indicesCheckedFrom(std.testing.allocator, &batch_engine, 1));
    try std.testing.expectError(error.InvalidWeight, invalid_tree.indicesU32CheckedFrom(std.testing.allocator, &batch_engine, 1));
    var invalid_engine = alea.ScalarPrng.init(0x5150_d5a0);
    var invalid_control = alea.ScalarPrng.init(0x5150_d5a0);
    var invalid_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidWeight, invalid_tree.indicesCheckedFrom(invalid_alloc.allocator(), &invalid_engine, 1));
    try std.testing.expect(!invalid_alloc.has_induced_failure);
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());
    var invalid_u32_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidWeight, invalid_tree.indicesU32CheckedFrom(invalid_u32_alloc.allocator(), &invalid_engine, 1));
    try std.testing.expect(!invalid_u32_alloc.has_induced_failure);
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());

    fill_engine = alea.ScalarPrng.init(0x5150_d50c);
    batch_engine = alea.ScalarPrng.init(0x5150_d50c);
    var int_tree = try WeightedIntTree(u32).init(std.testing.allocator, &.{ 0, 2, 0, 6 });
    defer int_tree.deinit();
    try int_tree.fillCheckedFrom(&fill_engine, &fill_out);
    const int_batch = try int_tree.indicesCheckedFrom(std.testing.allocator, &batch_engine, fill_out.len);
    defer std.testing.allocator.free(int_batch);
    try std.testing.expectEqualSlices(usize, &fill_out, int_batch);
    try std.testing.expectEqual(fill_engine.next(), batch_engine.next());

    fill_engine = alea.ScalarPrng.init(0x5150_d50d);
    batch_engine = alea.ScalarPrng.init(0x5150_d50d);
    try int_tree.fillU32CheckedFrom(&fill_engine, &fill_u32);
    const int_batch_u32 = try int_tree.indicesU32CheckedFrom(std.testing.allocator, &batch_engine, fill_u32.len);
    defer std.testing.allocator.free(int_batch_u32);
    try std.testing.expectEqualSlices(u32, &fill_u32, int_batch_u32);
    try std.testing.expectEqual(fill_engine.next(), batch_engine.next());

    var single_tree = try WeightedIntTree(u32).init(std.testing.allocator, &.{ 0, 0, 9 });
    defer single_tree.deinit();
    var single_engine = alea.ScalarPrng.init(0x5150_d50e);
    var single_control = alea.ScalarPrng.init(0x5150_d50e);
    const single_batch = try single_tree.indicesCheckedFrom(std.testing.allocator, &single_engine, 4);
    defer std.testing.allocator.free(single_batch);
    try std.testing.expectEqualSlices(usize, &.{ 2, 2, 2, 2 }, single_batch);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
    const single_batch_u32 = try single_tree.indicesU32CheckedFrom(std.testing.allocator, &single_engine, 4);
    defer std.testing.allocator.free(single_batch_u32);
    try std.testing.expectEqualSlices(u32, &.{ 2, 2, 2, 2 }, single_batch_u32);
    try std.testing.expectEqual(single_control.next(), single_engine.next());

    var invalid_int_tree = try WeightedIntTree(u32).init(std.testing.allocator, &.{ 0, 0 });
    defer invalid_int_tree.deinit();
    invalid_engine = alea.ScalarPrng.init(0x5150_d5a1);
    invalid_control = alea.ScalarPrng.init(0x5150_d5a1);
    var invalid_int_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidWeight, invalid_int_tree.indicesCheckedFrom(invalid_int_alloc.allocator(), &invalid_engine, 1));
    try std.testing.expect(!invalid_int_alloc.has_induced_failure);
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());
    var invalid_int_u32_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidWeight, invalid_int_tree.indicesU32CheckedFrom(invalid_int_u32_alloc.allocator(), &invalid_engine, 1));
    try std.testing.expect(!invalid_int_u32_alloc.has_induced_failure);
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());
}

test "weighted tree index aliases mirror sample helpers" {
    const alea = @import("root.zig");

    var sample_engine = alea.ScalarPrng.init(0x5150_d50f);
    var alias_engine = alea.ScalarPrng.init(0x5150_d50f);
    var tree = try WeightedTree(f64).init(std.testing.allocator, &.{ 1, 0, 7, 3 });
    defer tree.deinit();
    try std.testing.expectEqual(tree.sampleFrom(&sample_engine), tree.sampleIndexFrom(&alias_engine));
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_d510);
    alias_engine = alea.ScalarPrng.init(0x5150_d510);
    try std.testing.expectEqual(try tree.sampleCheckedFrom(&sample_engine), try tree.sampleIndexCheckedFrom(&alias_engine));
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_d511);
    alias_engine = alea.ScalarPrng.init(0x5150_d511);
    try std.testing.expectEqual(tree.sampleU32From(&sample_engine), tree.sampleIndexU32From(&alias_engine));
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_d512);
    alias_engine = alea.ScalarPrng.init(0x5150_d512);
    const rng = Rng.init(&sample_engine);
    const alias_rng = Rng.init(&alias_engine);
    try std.testing.expectEqual(try tree.sampleChecked(rng), try tree.sampleIndexChecked(alias_rng));
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_d513);
    alias_engine = alea.ScalarPrng.init(0x5150_d513);
    var fill_out: [8]usize = undefined;
    var alias_fill_out: [8]usize = undefined;
    tree.fillFrom(&sample_engine, &fill_out);
    tree.fillIndicesFrom(&alias_engine, &alias_fill_out);
    try std.testing.expectEqualSlices(usize, &fill_out, &alias_fill_out);
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_d514);
    alias_engine = alea.ScalarPrng.init(0x5150_d514);
    var fill_u32: [8]u32 = undefined;
    var alias_fill_u32: [8]u32 = undefined;
    try tree.fillU32CheckedFrom(&sample_engine, &fill_u32);
    try tree.fillIndicesU32CheckedFrom(&alias_engine, &alias_fill_u32);
    try std.testing.expectEqualSlices(u32, &fill_u32, &alias_fill_u32);
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    var invalid_tree = try WeightedTree(u32).init(std.testing.allocator, &.{ 0, 0 });
    defer invalid_tree.deinit();
    try std.testing.expectError(error.InvalidWeight, invalid_tree.sampleIndexCheckedFrom(&sample_engine));
    try std.testing.expectError(error.InvalidWeight, invalid_tree.fillIndicesCheckedFrom(&sample_engine, fill_out[0..1]));
    try std.testing.expectError(error.InvalidWeight, invalid_tree.sampleIndexU32CheckedFrom(&sample_engine));
    try std.testing.expectError(error.InvalidWeight, invalid_tree.fillIndicesU32CheckedFrom(&sample_engine, fill_u32[0..1]));

    var int_tree = try WeightedIntTree(u32).init(std.testing.allocator, &.{ 2, 0, 0, 6 });
    defer int_tree.deinit();
    sample_engine = alea.ScalarPrng.init(0x5150_d515);
    alias_engine = alea.ScalarPrng.init(0x5150_d515);
    try std.testing.expectEqual(int_tree.sampleFrom(&sample_engine), int_tree.sampleIndexFrom(&alias_engine));
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_d516);
    alias_engine = alea.ScalarPrng.init(0x5150_d516);
    try int_tree.fillCheckedFrom(&sample_engine, &fill_out);
    try int_tree.fillIndicesCheckedFrom(&alias_engine, &alias_fill_out);
    try std.testing.expectEqualSlices(usize, &fill_out, &alias_fill_out);
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_d517);
    alias_engine = alea.ScalarPrng.init(0x5150_d517);
    try int_tree.fillU32CheckedFrom(&sample_engine, &fill_u32);
    try int_tree.fillIndicesU32CheckedFrom(&alias_engine, &alias_fill_u32);
    try std.testing.expectEqualSlices(u32, &fill_u32, &alias_fill_u32);
    try std.testing.expectEqual(sample_engine.next(), alias_engine.next());

    var single_tree = try WeightedIntTree(u32).init(std.testing.allocator, &.{ 0, 0, 9 });
    defer single_tree.deinit();
    sample_engine = alea.ScalarPrng.init(0x5150_d518);
    var control = alea.ScalarPrng.init(0x5150_d518);
    try std.testing.expectEqual(@as(usize, 2), single_tree.sampleIndexFrom(&sample_engine));
    try std.testing.expectEqual(control.next(), sample_engine.next());
    single_tree.fillIndicesFrom(&sample_engine, &alias_fill_out);
    for (alias_fill_out) |index| try std.testing.expectEqual(@as(usize, 2), index);
    try std.testing.expectEqual(control.next(), sample_engine.next());
}

test "weighted tree iterators produce repeated indices" {
    const alea = @import("root.zig");

    var sample_engine = alea.ScalarPrng.init(0x5150_d519);
    var iter_engine = alea.ScalarPrng.init(0x5150_d519);
    var tree = try WeightedTree(f64).init(std.testing.allocator, &.{ 1, 0, 7, 3 });
    defer tree.deinit();
    var iter = tree.iterFrom(&iter_engine);
    var i: usize = 0;
    while (i < 8) : (i += 1) {
        try std.testing.expectEqual(tree.sampleFrom(&sample_engine), iter.next().?);
    }
    try std.testing.expectEqual(sample_engine.next(), iter_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_d51a);
    iter_engine = alea.ScalarPrng.init(0x5150_d51a);
    var fill_out: [8]usize = undefined;
    var iter_fill_out: [8]usize = undefined;
    tree.fillFrom(&sample_engine, &fill_out);
    var fill_iter = tree.iterFrom(&iter_engine);
    fill_iter.fill(&iter_fill_out);
    try std.testing.expectEqualSlices(usize, &fill_out, &iter_fill_out);
    try std.testing.expectEqual(sample_engine.next(), iter_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_d51b);
    iter_engine = alea.ScalarPrng.init(0x5150_d51b);
    var fill_u32: [8]u32 = undefined;
    var iter_fill_u32: [8]u32 = undefined;
    tree.fillU32From(&sample_engine, &fill_u32);
    var u32_iter = tree.iterU32From(&iter_engine);
    u32_iter.fill(&iter_fill_u32);
    try std.testing.expectEqualSlices(u32, &fill_u32, &iter_fill_u32);
    try std.testing.expectEqual(sample_engine.next(), iter_engine.next());

    var checked_iter_engine = alea.ScalarPrng.init(0x5150_d523);
    var unchecked_iter_engine = alea.ScalarPrng.init(0x5150_d523);
    var checked_iter = try tree.iterCheckedFrom(&checked_iter_engine);
    var unchecked_iter = tree.iterFrom(&unchecked_iter_engine);
    try std.testing.expectEqual(unchecked_iter.next().?, checked_iter.next().?);
    try std.testing.expectEqual(unchecked_iter_engine.next(), checked_iter_engine.next());

    var checked_facade_iter_engine = alea.ScalarPrng.init(0x5150_d52b);
    var checked_direct_iter_engine = alea.ScalarPrng.init(0x5150_d52b);
    var checked_facade_iter = try tree.iterChecked(Rng.init(&checked_facade_iter_engine));
    var checked_direct_iter = try tree.iterCheckedFrom(&checked_direct_iter_engine);
    try std.testing.expectEqual(checked_direct_iter.next().?, checked_facade_iter.next().?);
    try std.testing.expectEqual(checked_direct_iter_engine.next(), checked_facade_iter_engine.next());

    var facade_engine = alea.ScalarPrng.init(0x5150_d51c);
    var direct_engine = alea.ScalarPrng.init(0x5150_d51c);
    const rng = Rng.init(&facade_engine);
    var facade_iter = tree.iter(rng);
    var direct_iter = tree.iterFrom(&direct_engine);
    try std.testing.expectEqual(facade_iter.next().?, direct_iter.next().?);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    facade_engine = alea.ScalarPrng.init(0x5150_d51d);
    direct_engine = alea.ScalarPrng.init(0x5150_d51d);
    const u32_rng = Rng.init(&facade_engine);
    var facade_u32_iter = tree.iterU32(u32_rng);
    var direct_u32_iter = tree.iterU32From(&direct_engine);
    try std.testing.expectEqual(facade_u32_iter.next().?, direct_u32_iter.next().?);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    var checked_u32_iter_engine = alea.ScalarPrng.init(0x5150_d524);
    var unchecked_u32_iter_engine = alea.ScalarPrng.init(0x5150_d524);
    var checked_u32_iter = try tree.iterU32CheckedFrom(&checked_u32_iter_engine);
    var unchecked_u32_iter = tree.iterU32From(&unchecked_u32_iter_engine);
    try std.testing.expectEqual(unchecked_u32_iter.next().?, checked_u32_iter.next().?);
    try std.testing.expectEqual(unchecked_u32_iter_engine.next(), checked_u32_iter_engine.next());

    var checked_u32_facade_iter_engine = alea.ScalarPrng.init(0x5150_d52d);
    var checked_u32_direct_iter_engine = alea.ScalarPrng.init(0x5150_d52d);
    var checked_u32_facade_iter = try tree.iterU32Checked(Rng.init(&checked_u32_facade_iter_engine));
    var checked_u32_direct_iter = try tree.iterU32CheckedFrom(&checked_u32_direct_iter_engine);
    try std.testing.expectEqual(checked_u32_direct_iter.next().?, checked_u32_facade_iter.next().?);
    try std.testing.expectEqual(checked_u32_direct_iter_engine.next(), checked_u32_facade_iter_engine.next());

    var int_tree = try WeightedIntTree(u32).init(std.testing.allocator, &.{ 2, 0, 0, 6 });
    defer int_tree.deinit();
    sample_engine = alea.ScalarPrng.init(0x5150_d51e);
    iter_engine = alea.ScalarPrng.init(0x5150_d51e);
    int_tree.fillFrom(&sample_engine, &fill_out);
    var int_iter = int_tree.iterFrom(&iter_engine);
    int_iter.fill(&iter_fill_out);
    try std.testing.expectEqualSlices(usize, &fill_out, &iter_fill_out);
    try std.testing.expectEqual(sample_engine.next(), iter_engine.next());

    var checked_int_iter_engine = alea.ScalarPrng.init(0x5150_d525);
    var unchecked_int_iter_engine = alea.ScalarPrng.init(0x5150_d525);
    var checked_int_iter = try int_tree.iterCheckedFrom(&checked_int_iter_engine);
    var unchecked_int_iter = int_tree.iterFrom(&unchecked_int_iter_engine);
    try std.testing.expectEqual(unchecked_int_iter.next().?, checked_int_iter.next().?);
    try std.testing.expectEqual(unchecked_int_iter_engine.next(), checked_int_iter_engine.next());

    var checked_int_facade_iter_engine = alea.ScalarPrng.init(0x5150_d52c);
    var checked_int_direct_iter_engine = alea.ScalarPrng.init(0x5150_d52c);
    var checked_int_facade_iter = try int_tree.iterChecked(Rng.init(&checked_int_facade_iter_engine));
    var checked_int_direct_iter = try int_tree.iterCheckedFrom(&checked_int_direct_iter_engine);
    try std.testing.expectEqual(checked_int_direct_iter.next().?, checked_int_facade_iter.next().?);
    try std.testing.expectEqual(checked_int_direct_iter_engine.next(), checked_int_facade_iter_engine.next());

    sample_engine = alea.ScalarPrng.init(0x5150_d51f);
    iter_engine = alea.ScalarPrng.init(0x5150_d51f);
    int_tree.fillU32From(&sample_engine, &fill_u32);
    var int_u32_iter = int_tree.iterU32From(&iter_engine);
    int_u32_iter.fill(&iter_fill_u32);
    try std.testing.expectEqualSlices(u32, &fill_u32, &iter_fill_u32);
    try std.testing.expectEqual(sample_engine.next(), iter_engine.next());

    var checked_int_u32_iter_engine = alea.ScalarPrng.init(0x5150_d526);
    var unchecked_int_u32_iter_engine = alea.ScalarPrng.init(0x5150_d526);
    var checked_int_u32_iter = try int_tree.iterU32CheckedFrom(&checked_int_u32_iter_engine);
    var unchecked_int_u32_iter = int_tree.iterU32From(&unchecked_int_u32_iter_engine);
    try std.testing.expectEqual(unchecked_int_u32_iter.next().?, checked_int_u32_iter.next().?);
    try std.testing.expectEqual(unchecked_int_u32_iter_engine.next(), checked_int_u32_iter_engine.next());

    var checked_int_u32_facade_iter_engine = alea.ScalarPrng.init(0x5150_d52e);
    var checked_int_u32_direct_iter_engine = alea.ScalarPrng.init(0x5150_d52e);
    var checked_int_u32_facade_iter = try int_tree.iterU32Checked(Rng.init(&checked_int_u32_facade_iter_engine));
    var checked_int_u32_direct_iter = try int_tree.iterU32CheckedFrom(&checked_int_u32_direct_iter_engine);
    try std.testing.expectEqual(checked_int_u32_direct_iter.next().?, checked_int_u32_facade_iter.next().?);
    try std.testing.expectEqual(checked_int_u32_direct_iter_engine.next(), checked_int_u32_facade_iter_engine.next());

    var single_tree = try WeightedIntTree(u32).init(std.testing.allocator, &.{ 0, 0, 9 });
    defer single_tree.deinit();
    var single_engine = alea.ScalarPrng.init(0x5150_d520);
    var single_control = alea.ScalarPrng.init(0x5150_d520);
    var single_iter = single_tree.iterFrom(&single_engine);
    var single_out: [4]usize = undefined;
    single_iter.fill(&single_out);
    try std.testing.expectEqualSlices(usize, &.{ 2, 2, 2, 2 }, &single_out);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
    var single_u32_iter = single_tree.iterU32From(&single_engine);
    var single_u32_out: [4]u32 = undefined;
    single_u32_iter.fill(&single_u32_out);
    try std.testing.expectEqualSlices(u32, &.{ 2, 2, 2, 2 }, &single_u32_out);
    try std.testing.expectEqual(single_control.next(), single_engine.next());

    var invalid_tree = try WeightedTree(u32).init(std.testing.allocator, &.{ 0, 0 });
    defer invalid_tree.deinit();
    var invalid_engine = alea.ScalarPrng.init(0x5150_d527);
    var invalid_control = alea.ScalarPrng.init(0x5150_d527);
    try std.testing.expectError(error.InvalidWeight, invalid_tree.iterCheckedFrom(&invalid_engine));
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());
    try std.testing.expectError(error.InvalidWeight, invalid_tree.iterU32CheckedFrom(&invalid_engine));
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());

    var invalid_int_tree = try WeightedIntTree(u32).init(std.testing.allocator, &.{ 0, 0 });
    defer invalid_int_tree.deinit();
    invalid_engine = alea.ScalarPrng.init(0x5150_d528);
    invalid_control = alea.ScalarPrng.init(0x5150_d528);
    try std.testing.expectError(error.InvalidWeight, invalid_int_tree.iterCheckedFrom(&invalid_engine));
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());
    try std.testing.expectError(error.InvalidWeight, invalid_int_tree.iterU32CheckedFrom(&invalid_engine));
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());

    const huge_len = @as(usize, std.math.maxInt(u32)) + 1;
    const huge_tree = WeightedTree(u32){
        .subtotals = .{
            .items = @as([*]f64, @ptrFromInt(0x1000))[0..huge_len],
            .capacity = huge_len,
        },
        .positive_count = 1,
        .positive_index = 0,
        .allocator = std.testing.allocator,
    };
    invalid_engine = alea.ScalarPrng.init(0x5150_d529);
    invalid_control = alea.ScalarPrng.init(0x5150_d529);
    try std.testing.expectError(error.InvalidParameter, huge_tree.iterU32CheckedFrom(&invalid_engine));
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());
    var huge_tree_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidParameter, huge_tree.indicesU32From(huge_tree_alloc.allocator(), &invalid_engine, 1));
    try std.testing.expect(!huge_tree_alloc.has_induced_failure);
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());
    var huge_tree_checked_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidParameter, huge_tree.indicesU32CheckedFrom(huge_tree_checked_alloc.allocator(), &invalid_engine, 1));
    try std.testing.expect(!huge_tree_checked_alloc.has_induced_failure);
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());

    const huge_int_tree = WeightedIntTree(u32){
        .subtotals = .{
            .items = @as([*]u64, @ptrFromInt(0x2000))[0..huge_len],
            .capacity = huge_len,
        },
        .positive_count = 1,
        .positive_index = 0,
        .allocator = std.testing.allocator,
    };
    invalid_engine = alea.ScalarPrng.init(0x5150_d52a);
    invalid_control = alea.ScalarPrng.init(0x5150_d52a);
    try std.testing.expectError(error.InvalidParameter, huge_int_tree.iterU32CheckedFrom(&invalid_engine));
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());
    var huge_int_tree_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidParameter, huge_int_tree.indicesU32From(huge_int_tree_alloc.allocator(), &invalid_engine, 1));
    try std.testing.expect(!huge_int_tree_alloc.has_induced_failure);
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());
    var huge_int_tree_checked_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidParameter, huge_int_tree.indicesU32CheckedFrom(huge_int_tree_checked_alloc.allocator(), &invalid_engine, 1));
    try std.testing.expect(!huge_int_tree_checked_alloc.has_induced_failure);
    try std.testing.expectEqual(invalid_control.next(), invalid_engine.next());
}

test "weighted tree fixed index arrays mirror fills" {
    const alea = @import("root.zig");

    var fill_engine = alea.ScalarPrng.init(0x5150_d521);
    var array_engine = alea.ScalarPrng.init(0x5150_d521);
    var tree = try WeightedTree(f64).init(std.testing.allocator, &.{ 1, 0, 7, 3 });
    defer tree.deinit();
    var fill_out: [6]usize = undefined;
    tree.fillFrom(&fill_engine, &fill_out);
    const array_out = tree.indexArrayFrom(&array_engine, 6);
    try std.testing.expectEqualSlices(usize, &fill_out, &array_out);
    try std.testing.expectEqual(fill_engine.next(), array_engine.next());

    fill_engine = alea.ScalarPrng.init(0x5150_d522);
    array_engine = alea.ScalarPrng.init(0x5150_d522);
    var fill_u32: [6]u32 = undefined;
    try tree.fillU32CheckedFrom(&fill_engine, &fill_u32);
    const array_u32 = try tree.indexArrayU32CheckedFrom(&array_engine, 6);
    try std.testing.expectEqualSlices(u32, &fill_u32, &array_u32);
    try std.testing.expectEqual(fill_engine.next(), array_engine.next());

    var facade_engine = alea.ScalarPrng.init(0x5150_d523);
    var direct_engine = alea.ScalarPrng.init(0x5150_d523);
    const rng = Rng.init(&facade_engine);
    const facade_array = try tree.indexArrayChecked(rng, 4);
    const direct_array = try tree.indexArrayCheckedFrom(&direct_engine, 4);
    try std.testing.expectEqualSlices(usize, &direct_array, &facade_array);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    const empty_array = try tree.indexArrayCheckedFrom(&direct_engine, 0);
    try std.testing.expectEqual(@as(usize, 0), empty_array.len);
    const empty_u32_array = try tree.indexArrayU32CheckedFrom(&direct_engine, 0);
    try std.testing.expectEqual(@as(usize, 0), empty_u32_array.len);

    var int_tree = try WeightedIntTree(u32).init(std.testing.allocator, &.{ 2, 0, 0, 6 });
    defer int_tree.deinit();
    fill_engine = alea.ScalarPrng.init(0x5150_d524);
    array_engine = alea.ScalarPrng.init(0x5150_d524);
    int_tree.fillFrom(&fill_engine, &fill_out);
    const int_array = int_tree.indexArrayFrom(&array_engine, 6);
    try std.testing.expectEqualSlices(usize, &fill_out, &int_array);
    try std.testing.expectEqual(fill_engine.next(), array_engine.next());

    fill_engine = alea.ScalarPrng.init(0x5150_d525);
    array_engine = alea.ScalarPrng.init(0x5150_d525);
    try int_tree.fillU32CheckedFrom(&fill_engine, &fill_u32);
    const int_array_u32 = try int_tree.indexArrayU32CheckedFrom(&array_engine, 6);
    try std.testing.expectEqualSlices(u32, &fill_u32, &int_array_u32);
    try std.testing.expectEqual(fill_engine.next(), array_engine.next());

    var single_tree = try WeightedIntTree(u32).init(std.testing.allocator, &.{ 0, 0, 9 });
    defer single_tree.deinit();
    var single_engine = alea.ScalarPrng.init(0x5150_d526);
    var single_control = alea.ScalarPrng.init(0x5150_d526);
    const single_array = single_tree.indexArrayFrom(&single_engine, 4);
    try std.testing.expectEqualSlices(usize, &.{ 2, 2, 2, 2 }, &single_array);
    try std.testing.expectEqual(single_control.next(), single_engine.next());
    const single_u32_array = try single_tree.indexArrayU32CheckedFrom(&single_engine, 4);
    try std.testing.expectEqualSlices(u32, &.{ 2, 2, 2, 2 }, &single_u32_array);
    try std.testing.expectEqual(single_control.next(), single_engine.next());

    var invalid_tree = try WeightedTree(u32).init(std.testing.allocator, &.{ 0, 0 });
    defer invalid_tree.deinit();
    try std.testing.expectError(error.InvalidWeight, invalid_tree.indexArrayCheckedFrom(&single_engine, 1));
    try std.testing.expectError(error.InvalidWeight, invalid_tree.indexArrayU32CheckedFrom(&single_engine, 1));
}

