    try std.testing.expectEqual(infinite_shape_vec, infinite_shape_vector_sampler.sampleFrom(&engine));
    try std.testing.expectEqual(control.next(), engine.next());

    infinite_shape_vector_sampler.fill(rng, &vector_buf);
