    for (vector_buf) |sample| try std.testing.expectEqual(@as(@Vector(4, f64), @splat(0)), sample);
    try std.testing.expectEqual(control.next(), engine.next());

    const infinite_shape_vec: @Vector(4, f64) = @splat(infinite_shape_point);
    try std.testing.expectEqual(infinite_shape_vec, vectorWeibull(rng, @Vector(4, f64), infinite_shape_point, std.math.inf(f64)));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(infinite_shape_vec, vectorWeibullFrom(&engine, @Vector(4, f64), infinite_shape_point, std.math.inf(f64)));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(infinite_shape_vec, try vectorWeibullChecked(rng, @Vector(4, f64), infinite_shape_point, std.math.inf(f64)));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(infinite_shape_vec, try vectorWeibullCheckedFrom(&engine, @Vector(4, f64), infinite_shape_point, std.math.inf(f64)));
    try std.testing.expectEqual(control.next(), engine.next());

    fillVectorWeibull(rng, @Vector(4, f64), &vector_buf, infinite_shape_point, std.math.inf(f64));
    for (vector_buf) |sample| try std.testing.expectEqual(infinite_shape_vec, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    fillVectorWeibullFrom(&engine, @Vector(4, f64), &vector_buf, infinite_shape_point, std.math.inf(f64));
    for (vector_buf) |sample| try std.testing.expectEqual(infinite_shape_vec, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    try fillVectorWeibullChecked(rng, @Vector(4, f64), &vector_buf, infinite_shape_point, std.math.inf(f64));
    for (vector_buf) |sample| try std.testing.expectEqual(infinite_shape_vec, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    try fillVectorWeibullCheckedFrom(&engine, @Vector(4, f64), &vector_buf, infinite_shape_point, std.math.inf(f64));
    for (vector_buf) |sample| try std.testing.expectEqual(infinite_shape_vec, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    const infinite_shape_vector_sampler = try VectorWeibull(@Vector(4, f64)).init(infinite_shape_point, std.math.inf(f64));
    try std.testing.expectEqual(infinite_shape_point, infinite_shape_vector_sampler.scaleValue());
    try std.testing.expectEqual(std.math.inf(f64), infinite_shape_vector_sampler.shapeValue());
    try std.testing.expectEqual(infinite_shape_point, infinite_shape_vector_sampler.expectedValue());
    try std.testing.expectEqual(@as(f64, 0), infinite_shape_vector_sampler.varianceValue());
    try std.testing.expectEqual(infinite_shape_point, infinite_shape_vector_sampler.medianValue());
    try std.testing.expectEqual(infinite_shape_point, infinite_shape_vector_sampler.modeValue());
    try std.testing.expectEqual(infinite_shape_point, infinite_shape_vector_sampler.minValue());
    try std.testing.expectEqual(infinite_shape_point, infinite_shape_vector_sampler.maxValue().?);
    try std.testing.expectEqual(infinite_shape_vec, infinite_shape_vector_sampler.sample(rng));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(infinite_shape_vec, infinite_shape_vector_sampler.sampleFrom(&engine));
    try std.testing.expectEqual(control.next(), engine.next());

    infinite_shape_vector_sampler.fill(rng, &vector_buf);
    for (vector_buf) |sample| try std.testing.expectEqual(infinite_shape_vec, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    infinite_shape_vector_sampler.fillFrom(&engine, &vector_buf);
    for (vector_buf) |sample| try std.testing.expectEqual(infinite_shape_vec, sample);
    try std.testing.expectEqual(control.next(), engine.next());
}

test "degenerate kumaraswamy helpers do not consume random stream" {
    const alea = @import("root.zig");
    var engine = alea.ScalarPrng.init(0x5150_d1e7);
    var control = alea.ScalarPrng.init(0x5150_d1e7);
    const rng = Rng.init(&engine);

    inline for (.{
        .{ .alpha = std.math.inf(f64), .beta_param = 2.5, .point = 1.0 },
        .{ .alpha = 3.5, .beta_param = std.math.inf(f64), .point = 0.0 },
    }) |params| {
        const alpha: f64 = params.alpha;
        const beta_param: f64 = params.beta_param;
        const point: f64 = params.point;
        const point_vec: @Vector(4, f64) = @splat(point);

        try std.testing.expectEqual(point, kumaraswamy(rng, f64, alpha, beta_param));
        try std.testing.expectEqual(control.next(), engine.next());

        try std.testing.expectEqual(point, kumaraswamyFrom(&engine, f64, alpha, beta_param));
        try std.testing.expectEqual(control.next(), engine.next());

        try std.testing.expectEqual(point, try kumaraswamyChecked(rng, f64, alpha, beta_param));
        try std.testing.expectEqual(control.next(), engine.next());

        try std.testing.expectEqual(point, try kumaraswamyCheckedFrom(&engine, f64, alpha, beta_param));
        try std.testing.expectEqual(control.next(), engine.next());

        var scalar_buf: [5]f64 = undefined;
        fillKumaraswamy(rng, f64, &scalar_buf, alpha, beta_param);
        for (scalar_buf) |sample| try std.testing.expectEqual(point, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        fillKumaraswamyFrom(&engine, f64, &scalar_buf, alpha, beta_param);
        for (scalar_buf) |sample| try std.testing.expectEqual(point, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        try fillKumaraswamyChecked(rng, f64, &scalar_buf, alpha, beta_param);
        for (scalar_buf) |sample| try std.testing.expectEqual(point, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        try fillKumaraswamyCheckedFrom(&engine, f64, &scalar_buf, alpha, beta_param);
        for (scalar_buf) |sample| try std.testing.expectEqual(point, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        const sampler = try Kumaraswamy(f64).init(alpha, beta_param);
        try std.testing.expectEqual(alpha, sampler.alphaValue());
        try std.testing.expectEqual(beta_param, sampler.betaValue());
        try std.testing.expectEqual(point, sampler.expectedValue());
        try std.testing.expectEqual(@as(f64, 0), sampler.varianceValue());
        try std.testing.expectEqual(point, sampler.modeValue().?);
        try std.testing.expectEqual(point, sampler.medianValue());
        try std.testing.expectEqual(point, sampler.minValue());
        try std.testing.expectEqual(point, sampler.maxValue());
        try std.testing.expectEqual(point, sampler.sample(rng));
        try std.testing.expectEqual(control.next(), engine.next());

        try std.testing.expectEqual(point, sampler.sampleFrom(&engine));
        try std.testing.expectEqual(control.next(), engine.next());

        sampler.fill(rng, &scalar_buf);
        for (scalar_buf) |sample| try std.testing.expectEqual(point, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        sampler.fillFrom(&engine, &scalar_buf);
        for (scalar_buf) |sample| try std.testing.expectEqual(point, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        try std.testing.expectEqual(point_vec, vectorKumaraswamy(rng, @Vector(4, f64), alpha, beta_param));
        try std.testing.expectEqual(control.next(), engine.next());

        try std.testing.expectEqual(point_vec, vectorKumaraswamyFrom(&engine, @Vector(4, f64), alpha, beta_param));
        try std.testing.expectEqual(control.next(), engine.next());

        try std.testing.expectEqual(point_vec, try vectorKumaraswamyChecked(rng, @Vector(4, f64), alpha, beta_param));
        try std.testing.expectEqual(control.next(), engine.next());

        try std.testing.expectEqual(point_vec, try vectorKumaraswamyCheckedFrom(&engine, @Vector(4, f64), alpha, beta_param));
        try std.testing.expectEqual(control.next(), engine.next());

        var vector_buf: [3]@Vector(4, f64) = undefined;
        fillVectorKumaraswamy(rng, @Vector(4, f64), &vector_buf, alpha, beta_param);
        for (vector_buf) |sample| try std.testing.expectEqual(point_vec, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        fillVectorKumaraswamyFrom(&engine, @Vector(4, f64), &vector_buf, alpha, beta_param);
        for (vector_buf) |sample| try std.testing.expectEqual(point_vec, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        try fillVectorKumaraswamyChecked(rng, @Vector(4, f64), &vector_buf, alpha, beta_param);
        for (vector_buf) |sample| try std.testing.expectEqual(point_vec, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        try fillVectorKumaraswamyCheckedFrom(&engine, @Vector(4, f64), &vector_buf, alpha, beta_param);
        for (vector_buf) |sample| try std.testing.expectEqual(point_vec, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        const vector_sampler = try VectorKumaraswamy(@Vector(4, f64)).init(alpha, beta_param);
        try std.testing.expectEqual(alpha, vector_sampler.alphaValue());
        try std.testing.expectEqual(beta_param, vector_sampler.betaValue());
        try std.testing.expectEqual(point, vector_sampler.expectedValue());
        try std.testing.expectEqual(@as(f64, 0), vector_sampler.varianceValue());
        try std.testing.expectEqual(point, vector_sampler.modeValue().?);
        try std.testing.expectEqual(point, vector_sampler.medianValue());
        try std.testing.expectEqual(point, vector_sampler.minValue());
        try std.testing.expectEqual(point, vector_sampler.maxValue());
        try std.testing.expectEqual(point_vec, vector_sampler.sample(rng));
        try std.testing.expectEqual(control.next(), engine.next());

        try std.testing.expectEqual(point_vec, vector_sampler.sampleFrom(&engine));
        try std.testing.expectEqual(control.next(), engine.next());

        vector_sampler.fill(rng, &vector_buf);
        for (vector_buf) |sample| try std.testing.expectEqual(point_vec, sample);
        try std.testing.expectEqual(control.next(), engine.next());

        vector_sampler.fillFrom(&engine, &vector_buf);
        for (vector_buf) |sample| try std.testing.expectEqual(point_vec, sample);
        try std.testing.expectEqual(control.next(), engine.next());
    }

    try std.testing.expectError(error.InvalidParameter, kumaraswamyCheckedFrom(&engine, f64, std.math.inf(f64), std.math.inf(f64)));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectError(error.InvalidParameter, vectorKumaraswamyCheckedFrom(&engine, @Vector(4, f64), std.math.inf(f64), std.math.inf(f64)));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectError(error.InvalidParameter, Kumaraswamy(f64).init(std.math.inf(f64), std.math.inf(f64)));
    try std.testing.expectError(error.InvalidParameter, VectorKumaraswamy(@Vector(4, f64)).init(std.math.inf(f64), std.math.inf(f64)));
}

test "degenerate power-function helpers do not consume random stream" {
    const alea = @import("root.zig");
    var engine = alea.ScalarPrng.init(0x5150_d1d7);
    var control = alea.ScalarPrng.init(0x5150_d1d7);
    const rng = Rng.init(&engine);

    const point: f64 = 6.75;
    try std.testing.expectEqual(point, powerFunctionFrom(&engine, f64, point, point, 3));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(point, try powerFunctionChecked(rng, f64, point, point, 3));
    try std.testing.expectEqual(control.next(), engine.next());

    var scalar_buf: [5]f64 = undefined;
    fillPowerFunctionFrom(&engine, f64, &scalar_buf, point, point, 3);
    for (scalar_buf) |sample| try std.testing.expectEqual(point, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    try fillPowerFunctionChecked(rng, f64, &scalar_buf, point, point, 3);
    for (scalar_buf) |sample| try std.testing.expectEqual(point, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    const sampler = try PowerFunction(f64).init(point, point, 3);
    try std.testing.expectEqual(point, sampler.minValue());
    try std.testing.expectEqual(point, sampler.maxValue());
    try std.testing.expectEqual(@as(f64, 3), sampler.shapeValue());
    try std.testing.expectEqual(point, sampler.expectedValue());
    try std.testing.expectEqual(@as(f64, 0), sampler.varianceValue());
    try std.testing.expectEqual(point, sampler.medianValue());
    try std.testing.expectEqual(point, sampler.sampleFrom(&engine));
    try std.testing.expectEqual(control.next(), engine.next());

    sampler.fillFrom(&engine, &scalar_buf);
    for (scalar_buf) |sample| try std.testing.expectEqual(point, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    const shape_one = try PowerFunction(f64).init(point, point, 1);
    try std.testing.expectEqual(point, shape_one.sampleFrom(&engine));
    try std.testing.expectEqual(control.next(), engine.next());

    const shape_two = try PowerFunction(f64).init(point, point, 2);
    shape_two.fillFrom(&engine, &scalar_buf);
    for (scalar_buf) |sample| try std.testing.expectEqual(point, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    const max_point: f64 = 9.25;
    try std.testing.expectEqual(max_point, powerFunctionFrom(&engine, f64, point, max_point, std.math.inf(f64)));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(max_point, try powerFunctionChecked(rng, f64, point, max_point, std.math.inf(f64)));
    try std.testing.expectEqual(control.next(), engine.next());

    fillPowerFunctionFrom(&engine, f64, &scalar_buf, point, max_point, std.math.inf(f64));
    for (scalar_buf) |sample| try std.testing.expectEqual(max_point, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    try fillPowerFunctionChecked(rng, f64, &scalar_buf, point, max_point, std.math.inf(f64));
    for (scalar_buf) |sample| try std.testing.expectEqual(max_point, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    const infinite_shape = try PowerFunction(f64).init(point, max_point, std.math.inf(f64));
    try std.testing.expectEqual(max_point, infinite_shape.minValue());
    try std.testing.expectEqual(max_point, infinite_shape.maxValue());
    try std.testing.expectEqual(std.math.inf(f64), infinite_shape.shapeValue());
    try std.testing.expectEqual(max_point, infinite_shape.expectedValue());
    try std.testing.expectEqual(@as(f64, 0), infinite_shape.varianceValue());
    try std.testing.expectEqual(max_point, infinite_shape.medianValue());
    try std.testing.expectEqual(max_point, infinite_shape.sample(rng));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(max_point, infinite_shape.sampleFrom(&engine));
    try std.testing.expectEqual(control.next(), engine.next());

    infinite_shape.fill(rng, &scalar_buf);
    for (scalar_buf) |sample| try std.testing.expectEqual(max_point, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    infinite_shape.fillFrom(&engine, &scalar_buf);
    for (scalar_buf) |sample| try std.testing.expectEqual(max_point, sample);
    try std.testing.expectEqual(control.next(), engine.next());

    const vector_point: f32 = -2.5;
    try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_point)), vectorPowerFunctionFrom(&engine, @Vector(4, f32), vector_point, vector_point, 3));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_point)), try vectorPowerFunctionChecked(rng, @Vector(4, f32), vector_point, vector_point, 3));
    try std.testing.expectEqual(control.next(), engine.next());

    var vector_buf: [3]@Vector(4, f32) = undefined;
    fillVectorPowerFunctionFrom(&engine, @Vector(4, f32), &vector_buf, vector_point, vector_point, 3);
    for (vector_buf) |sample| try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_point)), sample);
    try std.testing.expectEqual(control.next(), engine.next());

    try fillVectorPowerFunctionChecked(rng, @Vector(4, f32), &vector_buf, vector_point, vector_point, 3);
    for (vector_buf) |sample| try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_point)), sample);
    try std.testing.expectEqual(control.next(), engine.next());

    const vector_max_point: f32 = 3.25;
    try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_max_point)), vectorPowerFunctionFrom(&engine, @Vector(4, f32), vector_point, vector_max_point, std.math.inf(f32)));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_max_point)), try vectorPowerFunctionChecked(rng, @Vector(4, f32), vector_point, vector_max_point, std.math.inf(f32)));
    try std.testing.expectEqual(control.next(), engine.next());

    fillVectorPowerFunctionFrom(&engine, @Vector(4, f32), &vector_buf, vector_point, vector_max_point, std.math.inf(f32));
    for (vector_buf) |sample| try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_max_point)), sample);
    try std.testing.expectEqual(control.next(), engine.next());

    try fillVectorPowerFunctionChecked(rng, @Vector(4, f32), &vector_buf, vector_point, vector_max_point, std.math.inf(f32));
    for (vector_buf) |sample| try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_max_point)), sample);
    try std.testing.expectEqual(control.next(), engine.next());

    const vector_infinite_shape = try VectorPowerFunction(@Vector(4, f32)).init(vector_point, vector_max_point, std.math.inf(f32));
    try std.testing.expectEqual(vector_max_point, vector_infinite_shape.minValue());
    try std.testing.expectEqual(vector_max_point, vector_infinite_shape.maxValue());
    try std.testing.expectEqual(std.math.inf(f32), vector_infinite_shape.shapeValue());
    try std.testing.expectEqual(vector_max_point, vector_infinite_shape.expectedValue());
    try std.testing.expectEqual(@as(f32, 0), vector_infinite_shape.varianceValue());
    try std.testing.expectEqual(vector_max_point, vector_infinite_shape.medianValue());
    try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_max_point)), vector_infinite_shape.sample(rng));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_max_point)), vector_infinite_shape.sampleFrom(&engine));
    try std.testing.expectEqual(control.next(), engine.next());

    vector_infinite_shape.fill(rng, &vector_buf);
    for (vector_buf) |sample| try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_max_point)), sample);
    try std.testing.expectEqual(control.next(), engine.next());

    vector_infinite_shape.fillFrom(&engine, &vector_buf);
    for (vector_buf) |sample| try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_max_point)), sample);
    try std.testing.expectEqual(control.next(), engine.next());

    const vector_sampler = try VectorPowerFunction(@Vector(4, f32)).init(vector_point, vector_point, 3);
    try std.testing.expectEqual(vector_point, vector_sampler.minValue());
    try std.testing.expectEqual(vector_point, vector_sampler.maxValue());
    try std.testing.expectEqual(@as(f32, 3), vector_sampler.shapeValue());
    try std.testing.expectEqual(vector_point, vector_sampler.expectedValue());
    try std.testing.expectEqual(@as(f32, 0), vector_sampler.varianceValue());
    try std.testing.expectEqual(vector_point, vector_sampler.medianValue());
    try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_point)), vector_sampler.sampleFrom(&engine));
    try std.testing.expectEqual(control.next(), engine.next());

    vector_sampler.fillFrom(&engine, &vector_buf);
    for (vector_buf) |sample| try std.testing.expectEqual(@as(@Vector(4, f32), @splat(vector_point)), sample);
    try std.testing.expectEqual(control.next(), engine.next());
}

test "invalid discrete distribution helpers do not consume random stream" {
    const alea = @import("root.zig");
    var engine = alea.ScalarPrng.init(0x5150_d1f4);
    var control = alea.ScalarPrng.init(0x5150_d1f4);

    try std.testing.expectError(error.InvalidProbability, negativeBinomialCheckedFrom(&engine, 5, 0));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectError(error.InvalidProbability, geometricFailuresCheckedFrom(&engine, 0));
    try std.testing.expectEqual(control.next(), engine.next());

    try std.testing.expectError(error.InvalidProbability, geometricCheckedFrom(&engine, 0));
    try std.testing.expectEqual(control.next(), engine.next());

    var buf: [4]u64 = undefined;
    try std.testing.expectError(error.InvalidParameter, fillHypergeometricCheckedFrom(&engine, &buf, 10, 11, 1));
    try std.testing.expectEqual(control.next(), engine.next());
}

test "distribution vector helpers preserve support and stream shape" {
    @setEvalBranchQuota(6000);
    const alea = @import("root.zig");
    var facade_engine = alea.ScalarPrng.init(0x5eed_51d4);
    var direct_engine = alea.ScalarPrng.init(0x5eed_51d4);
    const rng = Rng.init(&facade_engine);

    const bernoulli_vec = vectorBernoulli(rng, @Vector(8, bool), 0.25);
    const direct_bernoulli_vec = vectorBernoulliFrom(&direct_engine, @Vector(8, bool), 0.25);
    try std.testing.expectEqual(bernoulli_vec, direct_bernoulli_vec);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    const checked_bernoulli_vec = try vectorBernoulliChecked(rng, @Vector(8, bool), 0.5);
    const direct_checked_bernoulli_vec = try vectorBernoulliCheckedFrom(&direct_engine, @Vector(8, bool), 0.5);
    try std.testing.expectEqual(checked_bernoulli_vec, direct_checked_bernoulli_vec);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    const vector_bernoulli_sampler = try VectorBernoulli(@Vector(8, bool)).initRatio(1, 4);
    const vector_bernoulli_new = try VectorBernoulli(@Vector(8, bool)).new(0.25);
    const vector_bernoulli_ratio_new = try VectorBernoulli(@Vector(8, bool)).newRatio(1, 4);
    const vector_bernoulli_from_ratio = try VectorBernoulli(@Vector(8, bool)).fromRatio(1, 4);
    try std.testing.expectApproxEqAbs(@as(f64, 0.25), vector_bernoulli_sampler.probabilityValue(), 1e-15);
    try std.testing.expectApproxEqAbs(vector_bernoulli_sampler.probabilityValue(), vector_bernoulli_sampler.p(), 1e-15);
    try std.testing.expectApproxEqAbs(vector_bernoulli_sampler.probabilityValue(), vector_bernoulli_new.probabilityValue(), 1e-15);
    try std.testing.expectApproxEqAbs(vector_bernoulli_sampler.probabilityValue(), vector_bernoulli_ratio_new.probabilityValue(), 1e-15);
    try std.testing.expectApproxEqAbs(vector_bernoulli_sampler.probabilityValue(), vector_bernoulli_from_ratio.probabilityValue(), 1e-15);
    try std.testing.expectApproxEqAbs(@as(f64, 0.25), vector_bernoulli_sampler.expectedValue(), 1e-15);
    try std.testing.expectApproxEqAbs(@as(f64, 0.1875), vector_bernoulli_sampler.varianceValue(), 1e-15);
    try std.testing.expectEqual(false, vector_bernoulli_sampler.modeValue().?);
    try std.testing.expectEqual(false, vector_bernoulli_sampler.minValue());
    try std.testing.expectEqual(true, vector_bernoulli_sampler.maxValue());
    const sampled_bernoulli_vec = vector_bernoulli_sampler.sample(rng);
    const direct_sampled_bernoulli_vec = vector_bernoulli_sampler.sampleFrom(&direct_engine);
    try std.testing.expectEqual(sampled_bernoulli_vec, direct_sampled_bernoulli_vec);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

    var bernoulli_buf: [3]@Vector(8, bool) = undefined;
    var direct_bernoulli_buf: [3]@Vector(8, bool) = undefined;
    try fillVectorBernoulliChecked(rng, @Vector(8, bool), &bernoulli_buf, 0.25);
    try fillVectorBernoulliCheckedFrom(&direct_engine, @Vector(8, bool), &direct_bernoulli_buf, 0.25);
    try std.testing.expectEqualSlices(@Vector(8, bool), &bernoulli_buf, &direct_bernoulli_buf);
    try std.testing.expectEqual(facade_engine.next(), direct_engine.next());

