    try std.testing.expectEqual(@as(u32, 0x3f7fad1f), @as(u32, @bitCast(checked)));
    try std.testing.expectEqual(@as(u64, 0xa7e1c4ff73fa1150), checked_engine.next());

    var sampler_engine = alea.ScalarPrng.init(0x3270);
