test "standard uniform sampler mirrors value helpers" {
    const root = @import("root.zig");
    const sampler = StandardUniform{};

    var sample_engine = root.DefaultPrng.init(0x5150_57d);
    var value_engine = root.DefaultPrng.init(0x5150_57d);
    const sample_rng = Rng.init(&sample_engine);
    const value_rng = Rng.init(&value_engine);
    const Value = struct { u16, bool, f32 };
    try std.testing.expectEqual(value_rng.value(Value), sampler.sample(sample_rng, Value));
    try std.testing.expectEqual(value_engine.next(), sample_engine.next());

    var direct_sample_engine = root.DefaultPrng.init(0x5150_57d1);
    var direct_value_engine = root.DefaultPrng.init(0x5150_57d1);
    try std.testing.expectEqual(Rng.valueFrom(&direct_value_engine, u64), sampler.sampleFrom(&direct_sample_engine, u64));
    try std.testing.expectEqual(direct_value_engine.next(), direct_sample_engine.next());

    var fill_engine = root.DefaultPrng.init(0x5150_f111);
    var value_fill_engine = root.DefaultPrng.init(0x5150_f111);
    const fill_rng = Rng.init(&fill_engine);
    const value_fill_rng = Rng.init(&value_fill_engine);
    var sample_values: [5]u64 = undefined;
    var value_values: [5]u64 = undefined;
    sampler.fill(fill_rng, u64, &sample_values);
    value_fill_rng.fill(u64, &value_values);
    try std.testing.expectEqualSlices(u64, &value_values, &sample_values);
    try std.testing.expectEqual(value_fill_engine.next(), fill_engine.next());

    var compound_fill_engine = root.DefaultPrng.init(0x5150_c0de);
    var compound_value_engine = root.DefaultPrng.init(0x5150_c0de);
    var compound_sample_values: [4]Value = undefined;
    var compound_value_values: [4]Value = undefined;
    sampler.fillFrom(&compound_fill_engine, Value, &compound_sample_values);
    for (&compound_value_values) |*item| item.* = Rng.valueFrom(&compound_value_engine, Value);
    try std.testing.expectEqualSlices(Value, &compound_value_values, &compound_sample_values);
    try std.testing.expectEqual(compound_value_engine.next(), compound_fill_engine.next());

    var direct_fill_engine = root.DefaultPrng.init(0x5150_d111);
    var direct_value_fill_engine = root.DefaultPrng.init(0x5150_d111);
    var direct_sample_values: [5]u16 = undefined;
    var direct_value_values: [5]u16 = undefined;
    sampler.fillFrom(&direct_fill_engine, u16, &direct_sample_values);
    Rng.fillFrom(&direct_value_fill_engine, u16, &direct_value_values);
    try std.testing.expectEqualSlices(u16, &direct_value_values, &direct_sample_values);
    try std.testing.expectEqual(direct_value_fill_engine.next(), direct_fill_engine.next());
}

test "BernoulliError mirrors local rand error shape" {
    const err: BernoulliError = error.InvalidProbability;
    try std.testing.expectEqual(@as(BernoulliError, error.InvalidProbability), err);
    try std.testing.expect(@typeInfo(@TypeOf(Bernoulli.init(0.5))).error_union.error_set == BernoulliError);
    try std.testing.expect(@typeInfo(@TypeOf(VectorBernoulli(@Vector(4, bool)).fromRatio(1, 4))).error_union.error_set == BernoulliError);
    try std.testing.expectError(error.InvalidProbability, Bernoulli.new(-0.1));
    try std.testing.expectError(error.InvalidProbability, Bernoulli.fromRatio(2, 1));
}

test "UniformError mirrors uniform-family errors" {
    const err: UniformError = error.EmptyRange;
    const non_finite: UniformError = error.NonFinite;
    try std.testing.expectEqual(@as(Error, error.EmptyRange), err);
    try std.testing.expectEqual(@as(Error, error.NonFinite), non_finite);
    try std.testing.expect(@typeInfo(@TypeOf(Uniform(u8).new(1, 6))).error_union.error_set == UniformError);
    try std.testing.expect(@typeInfo(@TypeOf(VectorUniform(@Vector(4, i32)).newInclusive(-1, 1))).error_union.error_set == UniformError);
    try std.testing.expect(@typeInfo(@TypeOf(UniformDuration.new(.fromMilliseconds(1), .fromMilliseconds(2)))).error_union.error_set == UniformError);
    try std.testing.expect(@typeInfo(@TypeOf(UniformUnicodeScalar.new('A', 'Z'))).error_union.error_set == UniformError);
    try std.testing.expectError(error.EmptyRange, Uniform(u8).new(6, 1));
    try std.testing.expectError(error.NonFinite, Uniform(f64).new(0, std.math.inf(f64)));
    try std.testing.expectError(error.EmptyRange, UniformDuration.new(.fromMilliseconds(2), .fromMilliseconds(1)));
}

test "rand_distr error aliases mirror distribution Error" {
    comptime {
        std.debug.assert(NormalError == Error);
        std.debug.assert(ExpError == Error);
        std.debug.assert(GammaError == Error);
        std.debug.assert(BetaError == Error);
        std.debug.assert(BinomialError == Error);
        std.debug.assert(CauchyError == Error);
        std.debug.assert(ChiSquaredError == Error);
        std.debug.assert(FisherFError == Error);
        std.debug.assert(FrechetError == Error);
        std.debug.assert(GeoError == Error);
        std.debug.assert(GumbelError == Error);
        std.debug.assert(HyperGeoError == Error);
        std.debug.assert(InverseGaussianError == Error);
        std.debug.assert(NormalInverseGaussianError == Error);
        std.debug.assert(ParetoError == Error);
        std.debug.assert(PertError == Error);
        std.debug.assert(PoissonError == Error);
        std.debug.assert(SkewNormalError == Error);
        std.debug.assert(TriangularError == Error);
        std.debug.assert(WeibullError == Error);
        std.debug.assert(ZetaError == Error);
        std.debug.assert(ZipfError == Error);
    }

    const normal_alias: NormalError = error.InvalidParameter;
    const exponential_alias: ExpError = error.InvalidParameter;
    const gamma_alias: GammaError = error.InvalidParameter;
    const beta_alias: BetaError = error.InvalidParameter;
    const binomial_alias: BinomialError = error.InvalidProbability;
    const hypergeometric_alias: HyperGeoError = error.InvalidParameter;
    const poisson_alias: PoissonError = error.InvalidParameter;
    try std.testing.expectEqual(@as(Error, error.InvalidParameter), normal_alias);
    try std.testing.expectEqual(@as(Error, error.InvalidParameter), exponential_alias);
    try std.testing.expectEqual(@as(Error, error.InvalidParameter), gamma_alias);
    try std.testing.expectEqual(@as(Error, error.InvalidParameter), beta_alias);
    try std.testing.expectEqual(@as(Error, error.InvalidProbability), binomial_alias);
    try std.testing.expectEqual(@as(Error, error.InvalidParameter), hypergeometric_alias);
    try std.testing.expectEqual(@as(Error, error.InvalidParameter), poisson_alias);

    try std.testing.expect(@typeInfo(@TypeOf(Normal(f64).init(0, 1))).error_union.error_set == NormalError);
    try std.testing.expect(@typeInfo(@TypeOf(Exponential(f64).init(1))).error_union.error_set == ExpError);
    try std.testing.expect(@typeInfo(@TypeOf(Gamma(f64).init(2, 3))).error_union.error_set == GammaError);
    try std.testing.expect(@typeInfo(@TypeOf(Beta(f64).init(2, 5))).error_union.error_set == BetaError);
    try std.testing.expect(@typeInfo(@TypeOf(Binomial.init(8, 0.5))).error_union.error_set == BinomialError);
    try std.testing.expect(@typeInfo(@TypeOf(Hypergeometric.init(10, 5, 2))).error_union.error_set == HyperGeoError);
    try std.testing.expect(@typeInfo(@TypeOf(Poisson.init(2))).error_union.error_set == PoissonError);
}

test "rand_distr Exp and Exp1 aliases mirror exponential samplers" {
    const root = @import("root.zig");
    comptime {
        std.debug.assert(Exp(f64) == Exponential(f64));
        std.debug.assert(Exp1(f64) == StandardExponential(f64));
    }

    const exp_alias = try Exp(f64).init(2);
    const exponential_sampler = try Exponential(f64).init(2);
    try std.testing.expectApproxEqAbs(exponential_sampler.rateValue(), exp_alias.rateValue(), 0);
    try std.testing.expectApproxEqAbs(exponential_sampler.inverseRateValue(), exp_alias.inverseRateValue(), 0);

    var exp_alias_engine = root.DefaultPrng.init(0x51_4d_290);
    var exponential_engine = root.DefaultPrng.init(0x51_4d_290);
    try std.testing.expectEqual(exponential_sampler.sampleFrom(&exponential_engine), exp_alias.sampleFrom(&exp_alias_engine));
    try std.testing.expectEqual(exponential_engine.next(), exp_alias_engine.next());

    var exp1_alias_engine = root.DefaultPrng.init(0x51_4d_291);
    var standard_engine = root.DefaultPrng.init(0x51_4d_291);
    try std.testing.expectEqual((StandardExponential(f64){}).sampleFrom(&standard_engine), (Exp1(f64){}).sampleFrom(&exp1_alias_engine));
    try std.testing.expectEqual(standard_engine.next(), exp1_alias_engine.next());

    var exp1_alias_buf: [6]f64 = undefined;
    var standard_buf: [6]f64 = undefined;
    var exp1_fill_engine = root.DefaultPrng.init(0x51_4d_292);
    var standard_fill_engine = root.DefaultPrng.init(0x51_4d_292);
    (Exp1(f64){}).fillFrom(&exp1_fill_engine, &exp1_alias_buf);
    (StandardExponential(f64){}).fillFrom(&standard_fill_engine, &standard_buf);
    try std.testing.expectEqualSlices(f64, &standard_buf, &exp1_alias_buf);
    try std.testing.expectEqual(standard_fill_engine.next(), exp1_fill_engine.next());
}

test "rand_distr multi Dirichlet namespace alias mirrors Dirichlet" {
    const root = @import("root.zig");
    comptime std.debug.assert(multi.Dirichlet(f64) == Dirichlet(f64));

    const namespace_sampler = try multi.Dirichlet(f64).init(&.{ 1.0, 2.0, 3.0 });
    const canonical_sampler = try Dirichlet(f64).init(&.{ 1.0, 2.0, 3.0 });
    try std.testing.expectEqual(canonical_sampler.dimensionValue(), namespace_sampler.dimensionValue());
    try std.testing.expectApproxEqAbs(canonical_sampler.totalAlphaValue(), namespace_sampler.totalAlphaValue(), 0);
    try std.testing.expectApproxEqAbs(try canonical_sampler.meanAt(1), try namespace_sampler.meanAt(1), 0);

    var namespace_engine = root.DefaultPrng.init(0x51_4d_291);
    var canonical_engine = root.DefaultPrng.init(0x51_4d_291);
    var namespace_sample: [3]f64 = undefined;
    var canonical_sample: [3]f64 = undefined;
    namespace_sampler.sampleIntoFrom(&namespace_engine, &namespace_sample);
    canonical_sampler.sampleIntoFrom(&canonical_engine, &canonical_sample);
    try std.testing.expectEqualSlices(f64, &canonical_sample, &namespace_sample);
    try std.testing.expectEqual(canonical_engine.next(), namespace_engine.next());
}

