test "distribution Choose sampler mirrors slice choices" {
    const root = @import("root.zig");
    const items = [_]u8{ 10, 20, 30, 40 };
    const choice = Choose(u8).new(&items).?;

    try std.testing.expectEqual(@as(usize, items.len), choice.len());
    try std.testing.expectEqual(@as(usize, items.len), choice.numChoices());
    try std.testing.expect(!choice.isEmpty());
    try std.testing.expectEqual(@as(?usize, null), choice.constantIndex());
    try std.testing.expectEqualSlices(u8, &items, choice.itemsValue());
    try std.testing.expectEqual(&items[2], try choice.itemAt(2));
    try std.testing.expectEqual(&items[2], try choice.item(2));
    try std.testing.expectEqual(&items[2], choice.get(2).?);
    try std.testing.expectEqual(@as(?*const u8, null), choice.get(items.len));
    try std.testing.expectError(error.InvalidParameter, choice.itemAt(items.len));
    try std.testing.expectApproxEqAbs(@as(f64, 0.25), try choice.probabilityAt(0), 1e-12);
    try std.testing.expectApproxEqAbs(@as(f64, 0.25), choice.probability(3).?, 1e-12);
    try std.testing.expectEqual(@as(?f64, null), choice.probability(items.len));
    try std.testing.expectError(error.InvalidParameter, choice.probabilityAt(items.len));
    var probabilities: [4]f64 = undefined;
    try choice.probabilitiesInto(&probabilities);
    for (probabilities) |probability| try std.testing.expectApproxEqAbs(@as(f64, 0.25), probability, 1e-12);
    var short_probabilities: [3]f64 = undefined;
    try std.testing.expectError(error.InvalidLength, choice.probabilitiesInto(&short_probabilities));
    const owned_probabilities = try choice.probabilities(std.testing.allocator);
    defer std.testing.allocator.free(owned_probabilities);
    try std.testing.expectEqualSlices(f64, &probabilities, owned_probabilities);
    var probability_iter = choice.probabilityIter();
    try std.testing.expectEqual(@as(usize, 4), probability_iter.len());
    try std.testing.expectEqual(@as(usize, 4), probability_iter.remaining());
    try std.testing.expectEqual(@as(usize, 4), probability_iter.sizeHint().lower);
    try std.testing.expectEqual(@as(?usize, 4), probability_iter.sizeHint().upper);
    try std.testing.expectApproxEqAbs(@as(f64, 0.25), probability_iter.next().?, 1e-12);
    var iter_probabilities: [3]f64 = undefined;
    try std.testing.expectEqual(@as(usize, 3), probability_iter.fill(&iter_probabilities));
    for (iter_probabilities) |probability| try std.testing.expectApproxEqAbs(@as(f64, 0.25), probability, 1e-12);
    try std.testing.expectEqual(@as(?f64, null), probability_iter.next());

    var choice_engine = root.DefaultPrng.init(0xc0_267);
    var index_engine = root.DefaultPrng.init(0xc0_267);
    try std.testing.expectEqual(
        items[Rng.chooseIndexFrom(&index_engine, items.len).?],
        choice.sampleValueFrom(&choice_engine),
    );
    try std.testing.expectEqual(index_engine.next(), choice_engine.next());
    var checked_value_engine = root.DefaultPrng.init(0xc0_286);
    var unchecked_value_engine = root.DefaultPrng.init(0xc0_286);
    try std.testing.expectEqual(
        choice.sampleValueFrom(&unchecked_value_engine),
        try choice.sampleValueCheckedFrom(&checked_value_engine),
    );
    try std.testing.expectEqual(unchecked_value_engine.next(), checked_value_engine.next());
    var sample_index_engine = root.DefaultPrng.init(0xc0_276);
    var choose_index_engine = root.DefaultPrng.init(0xc0_276);
    try std.testing.expectEqual(
        Rng.chooseIndexFrom(&choose_index_engine, items.len).?,
        choice.sampleIndexFrom(&sample_index_engine),
    );
    try std.testing.expectEqual(choose_index_engine.next(), sample_index_engine.next());
    var sample_index_u32_engine = root.DefaultPrng.init(0xc0_279);
    var choose_index_u32_engine = root.DefaultPrng.init(0xc0_279);
    try std.testing.expectEqual(
        Rng.chooseIndexU32From(&choose_index_u32_engine, @intCast(items.len)).?,
        try choice.sampleIndexU32From(&sample_index_u32_engine),
    );
    try std.testing.expectEqual(choose_index_u32_engine.next(), sample_index_u32_engine.next());
    var checked_index_u32_engine = root.DefaultPrng.init(0xc0_282);
    var unchecked_index_u32_engine = root.DefaultPrng.init(0xc0_282);
    try std.testing.expectEqual(
        try choice.sampleIndexU32From(&unchecked_index_u32_engine),
        try choice.sampleIndexU32CheckedFrom(&checked_index_u32_engine),
    );
    try std.testing.expectEqual(unchecked_index_u32_engine.next(), checked_index_u32_engine.next());

    var fill_engine = root.DefaultPrng.init(0xc0_268);
    var helper_engine = root.DefaultPrng.init(0xc0_268);
    var values: [6]u8 = undefined;
    var helper_values: [6]u8 = undefined;
    choice.fillValuesFrom(&fill_engine, &values);
    for (&helper_values) |*value| value.* = Rng.chooseFrom(&helper_engine, u8, &items).?;
    try std.testing.expectEqualSlices(u8, &helper_values, &values);
    try std.testing.expectEqual(helper_engine.next(), fill_engine.next());
    var value_direct_engine = root.DefaultPrng.init(0xc0_297);
    var value_index_engine = root.DefaultPrng.init(0xc0_297);
    var value_direct: [6]u8 = undefined;
    var value_indices: [6]usize = undefined;
    choice.fillValuesFrom(&value_direct_engine, &value_direct);
    choice.fillIndicesFrom(&value_index_engine, &value_indices);
    for (value_direct, value_indices) |value, index| try std.testing.expectEqual(items[index], value);
    try std.testing.expectEqual(value_index_engine.next(), value_direct_engine.next());
    var index_fill_engine = root.DefaultPrng.init(0xc0_277);
    var index_array_engine = root.DefaultPrng.init(0xc0_277);
    var index_fill: [6]usize = undefined;
