    var singleton_index_iter_u32 = try singleton.indexIterU32From(&singleton_engine);
    try std.testing.expectEqual(@as(u32, 0), singleton_index_iter_u32.next().?);
    try std.testing.expectEqual(singleton_control.next(), singleton_engine.next());

    const Empty = enum {};
    const empty_items = @as([*]const Empty, @ptrFromInt(0x1000))[0..1];
    const empty_choice = Choose(Empty).new(empty_items).?;
    var empty_engine = root.DefaultPrng.init(0xc0_271);
    var empty_control = root.DefaultPrng.init(0xc0_271);
    var empty_values: [1]Empty = undefined;
    empty_choice.fillValuesFrom(&empty_engine, &empty_values);
    try std.testing.expectEqual(empty_control.next(), empty_engine.next());
    if (empty_choice.sampleValueCheckedFrom(&empty_engine)) |_| {
        return error.TestExpectedError;
    } else |err| {
        try std.testing.expectEqual(error.EmptyRange, err);
    }
    try std.testing.expectEqual(empty_control.next(), empty_engine.next());
    if (empty_choice.valueCheckedFrom(&empty_engine)) |_| {
        return error.TestExpectedError;
    } else |err| {
        try std.testing.expectEqual(error.EmptyRange, err);
    }
    try std.testing.expectEqual(empty_control.next(), empty_engine.next());
    if (empty_choice.valueArrayCheckedFrom(&empty_engine, 1)) |_| {
        return error.TestExpectedError;
    } else |err| {
        try std.testing.expectEqual(error.EmptyRange, err);
    }
    try std.testing.expectEqual(empty_control.next(), empty_engine.next());
    const empty_array = try empty_choice.valueArrayCheckedFrom(&empty_engine, 0);
    try std.testing.expectEqual(@as(usize, 0), empty_array.len);
    try std.testing.expectEqual(empty_control.next(), empty_engine.next());
    var empty_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    if (empty_choice.valuesFrom(empty_alloc.allocator(), &empty_engine, 1)) |unexpected| {
        empty_alloc.allocator().free(unexpected);
        return error.TestExpectedError;
    } else |err| {
        try std.testing.expectEqual(error.EmptyRange, err);
    }
    try std.testing.expect(!empty_alloc.has_induced_failure);
    try std.testing.expectEqual(empty_control.next(), empty_engine.next());
    var empty_checked_fill: [1]Empty = undefined;
    if (empty_choice.fillValuesCheckedFrom(&empty_engine, &empty_checked_fill)) |_| {
        return error.TestExpectedError;
    } else |err| {
        try std.testing.expectEqual(error.EmptyRange, err);
    }
    try std.testing.expectEqual(empty_control.next(), empty_engine.next());
    var empty_checked_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    if (empty_choice.valuesCheckedFrom(empty_checked_alloc.allocator(), &empty_engine, 1)) |unexpected| {
        empty_checked_alloc.allocator().free(unexpected);
        return error.TestExpectedError;
    } else |err| {
        try std.testing.expectEqual(error.EmptyRange, err);
    }
    try std.testing.expect(!empty_checked_alloc.has_induced_failure);
    try std.testing.expectEqual(empty_control.next(), empty_engine.next());
    var empty_iter = empty_choice.valueIterFrom(&empty_engine);
    try std.testing.expect(empty_iter.next() == null);
    try std.testing.expectEqual(empty_control.next(), empty_engine.next());
    if (empty_choice.valueIterCheckedFrom(&empty_engine)) |_| {
        return error.TestExpectedError;
    } else |err| {
        try std.testing.expectEqual(error.EmptyRange, err);
    }
    try std.testing.expectEqual(empty_control.next(), empty_engine.next());

    try std.testing.expect(Choose(u8).new(&.{}) == null);
    try std.testing.expectError(error.EmptyRange, Choose(u8).newChecked(&.{}));
}

test "distribution Choose owned u32 indices reject oversized population before allocation" {
    const root = @import("root.zig");
    const oversized_len = @as(usize, std.math.maxInt(u32)) + 1;
    const oversized_items = @as([*]const u8, @ptrFromInt(0x2000))[0..oversized_len];
    const choice = Choose(u8).new(oversized_items).?;

    var engine = root.ScalarPrng.init(0x5150_c0f1);
    var control = root.ScalarPrng.init(0x5150_c0f1);

    var alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidParameter, choice.indicesU32From(alloc.allocator(), &engine, 1));
    try std.testing.expect(!alloc.has_induced_failure);
    try std.testing.expectEqual(control.next(), engine.next());

    var checked_alloc = std.testing.FailingAllocator.init(std.testing.allocator, .{ .fail_index = 0 });
    try std.testing.expectError(error.InvalidParameter, choice.indicesU32CheckedFrom(checked_alloc.allocator(), &engine, 1));
    try std.testing.expect(!checked_alloc.has_induced_failure);
    try std.testing.expectEqual(control.next(), engine.next());
}

test "distribution Map and Iter aliases mirror concrete adapter types" {
    const root = @import("root.zig");
    const die = try Uniform(u8).newInclusive(1, 6);
    const Even = struct {
        pub fn map(value: u8) bool {
            return value % 2 == 0;
        }
    };
    const mapper = Even{};
    const mapped = map(u8, bool, die, mapper);

    try std.testing.expect(@TypeOf(mapped) == Map(@TypeOf(die), @TypeOf(mapper), u8, bool));

    var mapped_engine = root.DefaultPrng.init(0x51_4d_270);
    var alias_engine = root.DefaultPrng.init(0x51_4d_270);
    try std.testing.expectEqual(
        mapped.sampleFrom(&mapped_engine),
        @as(Map(@TypeOf(die), @TypeOf(mapper), u8, bool), mapped).sampleFrom(&alias_engine),
    );
    try std.testing.expectEqual(mapped_engine.next(), alias_engine.next());

    var iter_engine = root.DefaultPrng.init(0x51_4d_271);
    var namespace_iter = sampleIterFrom(&iter_engine, u8, die);
    const AliasIter = Iter(@TypeOf(die), *@TypeOf(iter_engine), u8);
    try std.testing.expect(@TypeOf(namespace_iter) == AliasIter);
    _ = namespace_iter.next().?;
}
